begin;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('06742099-246b-5d40-983b-89db923b2a3f', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-09-01', '16:30:00', null, '通常 / 複数のスプライト、背景、メッセージを使いこなす', '自分で作りたいこと、やりたいことがはっきりしていて、テキスト通りにはなかなか進みませんが、学年や現在の習得度を考えると、そうちゃんの納得のいくペースでも構わないかと思われます。 実際、繰り返しの作業を面倒がらずにするので、メッセージや背景が変わった時の動きや、それに伴うスプライトの表示非表示、座標の指定などはかなり慣れてマスターできていました。', null, 'タイピング: 今日はタイピングに盛り上がって、25分くらい集中して取り組んでいました。 右手は薬指、小指も使って打てるようになってきましたが、左手はまだ右手で打ったり人差し指だったりと、もう少し慣れが必要な感じです。
盛り上がり: メッセージや背景の変更を活用することにより、自分の思った通りのストーリーが広がっていくのがとても楽しそうでした。
備考: まさきくんがスマホでしていたポケモンのゲームに興味津々でした。'),
  ('b4a53602-ad3f-5294-8e1d-2c558b39db57', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-08-30', '17:30:00', null, '通常 / ジャンプゲーム', 'ディラックが剣と銃を持ち換えてゾンビを攻撃する動きを集中して作成していました。 ディラックが武器を持って移動する動きを、座標をうまく使って表現できていました。 剣を持っているときはスペースキーを押すと剣を振って攻撃、銃を持っているときはスペースキーで弾が発射されるようにする動きで悩んでいたので、変数にフラグという使い方があると提案したところ、想像以上に感動してくれました！これだけのヒントで、わかりやすいコードを作成してくれました！', null, '盛り上がり: 90分ほどの時間、集中して作成していました。 自分が何を目的として作成しているのかをよくわかっていて、余分な動作を省いたわかりやすいコードを書こうとしている姿勢が素晴らしかったです！
備考: 武器を持ったスプライトの動き、武器の持ち替え、武器による攻撃方法の違いなど、同じようなゲームを作りたい子に参考になりそうな要素がつまった作品です。公開してみてもよいかも！'),
  ('db0fc6d7-1754-51b7-8131-552eddae2617', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-08-30', '16:30:00', null, '通常 / ジャンプゲームの作成', 'ゲームのアレンジがどんどん浮かぶようで、何度か脱線しながら作成をしていました。 ジャンプの動きのコードはすぐに理解していましたが、どうしても滞空時間を入れたいというこだわりを見せていました。 障害物の動きはしょうたくんの得意分野で、スラスラと作成していました。', '09＿04から', 'タイピング: 最初のステージをクリアすることができました。 小指や薬指の動きがまだ遅いですが、それでも指使いを守って丁寧に打とうとしています！
盛り上がり: ようくんのペースにのせられたのか、教室にきて初めてというくらい、よくしゃべっていました。 何度か脱線しながらも、課題に関しては楽しそうに取り組んでいました。'),
  ('62ef93a3-fe0e-51ad-8fab-5ce72d68dd22', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-08-30', '16:30:00', null, '通常 / ジャンプの動きの確認', '前回の復習で、基本操作コースのジャンプを再現するところから始めましたが、あまり覚えていなかったようで、「ジャンプの動きを作るには何をすればよいか」から考えることが必要でした。 垂直ジャンプを思い出してからは気分がのってきたようで、垂直ジャンプの動きと並行してx方向の動きをさせることで、幅のあるジャンプを作ることができました。 ジャンプの精度をあげることよりも、ブロックの上に乗る動きを作りたがったので、そのために必要な要素を考えてもらい、ブロックの色とy座標というパーツを導き出すことができました。', 'ジャンプの着地を作成予定', 'タイピング: 今やっている範囲では、安定したスコアを出せるようになってきています。
盛り上がり: どうしてもジャンピングゲームのようなものを作りたいようで、ジャンプの動きにその要素が入ってからは、「わからない」「どうすればいい？」と質問しつつも、こちらが答えを教えないことに焦れたりせず、一生懸命にヒントを聴いて考えようとする姿勢が見られました。'),
  ('5ca93e29-c736-53af-a8d6-00cdb1191136', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-08-30', '17:30:00', null, '通常 / 星取りゲームの完成', 'かなり疲れていたようで、自力で考えることが難しそうだったため、一つの動きごとに問答をしてヒントを出しながら作成しました。 上記でも難しい場合は、見本のコードを見せてどのブロックがどの動きに対応しているかを確認してから写経しました。 「もし～なら」と「～まで繰り返す」のブロックを間違えていて動きがおかしかったところで、自力で間違いを探せなかったため、自分で作成したコードを言葉で解説させたところ、間違いに気づくことができました。', null, 'タイピング: タイピングの気分ではなかったようで、同じ文字の連打で少し遊んでいました。
盛り上がり: 思い通りに動いたときは嬉しそうでしたが、バグが見つけられなかったことで、疲れた様子を見せていました。 ゲームが完成したら、今日の授業はここまで、と決めてからは一気にがんばっていました。 残り15分くらいは、プロセカで遊んでいました。
備考: かなり睡眠不足だということと、まだ食事が通常通りではないのか、体力が戻りきっていないようでしんどそうでした…'),
  ('8136ba6e-1f99-53e9-9e66-a191345a54a5', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-08-29', null, null, '通常 / ゴルフゲームの作成、様子を見てコードモンキー', '前回からの続きでゴルフゲームの作成をしました。 同じ教材が続いているため、飽きているようなら途中でコードモンキーに切り替えることも検討していましたが、想像以上に集中して真剣にゴルフゲームに取り組んでいたため、そのまま継続して作成してもらいました。', null, '時間帯: その他
タイピング: 集中して取り組めています
盛り上がり: 自学自習がしっかりできていました！ たまに声掛けした際も、今自分が何のコードを作成しているのか、しっかり理解して作成している様子でした。'),
  ('8fd1d181-f133-59d4-9ca9-829dc2337fe7', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-08-29', '17:30:00', null, '通常 / 興味をもったゲームのコードを再現してみる', 'どのゲームも最後まできちんとプレイしてから選んでいました。 動画を見るのは拒否していたので、見本のコードを開いたタブと切り替えながらの写経になりましたが、自分でどのスプライトのコードから作成すればよいのか考えながら集中してうつしていました。', null, 'タイピング: 20分以上集中して取り組んでいました。
盛り上がり: 妥協せずに取り組む作品を選んで、ただ写経するのではなくある程度コードを見て考えながら写しているところが素晴らしかったです！'),
  ('815e1a25-8bb0-5541-a23a-d0360077a4d7', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-08-29', '16:30:00', null, '通常 / 今後のコンテスト作品の課題確認', '・全国選抜小学生プログラミング大会に向けて、ブラッシュアップしたいところを整理しました。はるちゃんが、親子大会の他の入賞作品を見て気づいた点を重視して計画をたてていたのが良かったです！ ⇒音楽をつける、ゲームをもう一つ増やす、バグを完璧になおす等 ・親子大会決勝に向けて、どんなことをスライドにするかを大まかに決めました。（はるちゃんのノートにメモ） ・現時点でのゲームのアピールポイントを、ゲームの進みに沿って説明してもらいました。 ・地球温暖化の影響でウミガメが絶滅してしまう可能性があることをしって何かできないか考えた。自分の何かできないかという気持ちをプログラミングであらわした。 ・現実ではできなかもしれないけど、ゲームの中ではできることをタイトルで表してみた。 ・初めての人でも進められるように説明画面を入れた。 ・スズリンパの性格を明るく親しみやすくした。 ・物語の途中で名前を呼んでもらうことで、作品に入り込みやすいように ・ゲームを進めやすいようにヒントも工夫した ・ウミガメの表情をこだわった ・魔法の杖のエフェクトもこだわった ・練習モードも相手のことを考えて作成 ・ゲームの難易度も無理しなければクリアできる程度にした ・落ちてくるＣＯ２にもバリエーションをつけた ・エンディング画面に裏設定で子亀が話すようにした ・ゲームに合いそうな音楽を探しました。 （甘茶の音楽工房 https://amachamusic.chagasi.com/）', null, 'タイピング: 3級相当の結果が出せています！
盛り上がり: ゲームのアピールポイントや改善したいところなどを、とても生き生きと語ってくれました！引き続きこの作品に関わってブラッシュアップできることがとても嬉しそうでした。'),
  ('3fc7e3a7-2e82-5481-9ea3-9701832ed889', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-08-29', '18:40:00', null, '通常 / 検定の練習をしよう', '10月の検定に向けて3級の練習問題をやりました。集中を切らすことなくできていました。 結果として、1つ音を付け忘れただけで、ほかはすべてできていました。本人的にも余裕でできていたので、すごかったです。もう1つ上の級でもよいかもしれません。', null, 'タイピング: 集中してできていました
盛り上がり: 端いながら集中できていました。'),
  ('56356095-5a55-5be8-9d23-eb92e36a0b73', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-08-29', '17:30:00', null, '通常 / DKのレースゲームを完成しよう', 'DKのレースゲームを完成を目指しました。「ではない」のコードを使った進むコードは前回で作りかけだったので、まず、どうしてこのコードを並べているかと問いただしたところ、しっかりと説明できたので、そのまま完成に向けて進めるよう指示しました。順位を作るところで、当たり判定が機能しないバグは発生していたが、以前作っていた別のコードが邪魔していたので、動かなっただけで、順位を作るコードは正しく作れていました。そして、完成できました。 後半は、次に作るprgの脱出ゲームを動画を見て、遊んで、次回に備えて、コスチュームを作りました。虹色の円や鍵のアレンジなどして、想像力があふれていました。', '修君とともに脱出ゲームつくり', 'タイピング: 久々だったが、集中してできていました。
盛り上がり: 授業前の遊びはとてもうきうきしていました。'),
  ('99b99402-df61-5334-85e9-4e8aa28fe73b', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-08-29', '17:30:00', null, '通常 / （DK)レースゲームを完成しよう及び「ではない」「変数」の確認', '前回までにやっていたDKのレースゲームを完成をめざしました。「ではない」のコードを使って進むコードはできていたが、以前に作っていた別の進むコードが同時に存在していて、困っていました。しゅうくんはコードが散らかっているので、ダブっているものを消すよう指示しました。そして、ではない」のコードはなんとなく作っていた気がするので、1行1行説明しながら「ではない」の活用の理解を共有しました。順位のコードも前に作ったコードがそのまま残っていたので、それが邪魔し、整理したら、解消しました。ほんとしゅうくんには定期的にコードの整理が必要です。 後半は、prgのゲームを見せて、コスチュームを作りました。しゅうくんはコスチュームを先に作らないとコードを進まないので、残り時間がそれに専念してもらいました。', '動画見ながら脱出ゲーム作成がいいかも', 'タイピング: 久々だったので手が進まず、しょげていました
盛り上がり: やっぱクリオネが好きらしいです'),
  ('7e449379-ac15-598d-8fa0-92072f9a059b', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-08-29', '16:30:00', null, '通常 / ピンポンゲームを復習しよう', '前回やったピンポンゲームをクイズ形式として復習しました。 最初に向きを設定するところで海底のブロックを使ったり、また逆もしかりで、曖昧になっていました。そして、マウスポインタの座標でスプライトを動かすところは、考えが進んでいなかったので、一緒に自分が問いただしながら答える形式で細分化の考え方を共有しました。ほかにスコアをつけたり、ゲームオーバークリアの画面変化をスムーズに作れました。時間の都合で、最後まで作れませんでしたが、簡単な条件分岐や変数の使い方はできていると思います', null, 'タイピング: 着実にスコアも伸ばしてよくなっています
盛り上がり: 夏休みはディズニーやスカイツリーに行って楽しんでいました。'),
  ('b9d48c29-d5bd-5818-92b4-021861f9435f', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-08-26', '18:40:00', null, '通常 / 検定2級の苦手分野の確認', '点数のところがうまくいかず、時間切れでしたが、先にわかりやすい背景のスプライトを完成させる機転がきいていました！ 使用するブロックはカンペキでした！ どこまでをどの繰り返しの中に入れるかなど、ブロックの位置による不具合が3か所ほどありました。 本番中に不具合があった場合は、一時的に変数を表示してフラグがきちんと動いているかなどを確認する方法を実践しました。', null, 'タイピング: 相変わらず準2級の基準をクリアできています！
盛り上がり: 完成したゲームで、楽しそうにタイムアタックにチャレンジしていました！ 前回よりもこちらを頼るそぶりがなくなり、自力で取り組む姿勢がよかったです。'),
  ('f060ddd6-ae36-5e1b-9fe8-d0aeb729a5eb', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-08-26', '17:30:00', null, '通常 / ピンポンゲームをやる→移してもいいから自分アイディアでゲームを作る楽しさを知る', '・自分のことばでやりたいコードの説明ができるようになった（前は全然ことばになってなかった） ・集中力が高まった（30分がんばった） ・コードの理解、自分が書きたいものはここのカテゴリーのプログラムにあるという理解ができるようになった →もし〜、当たったら〜、', 'メッセージを送り合って、スプライトがそれに応じて変化する 隠す、表示がメッセージでできるようになる', 'タイピング: なし
盛り上がり: アイディアがたくさんでるようになったこと、コードの理解が進んでいる（日本語の理解、論理立てて話す）'),
  ('4a6508f4-cc64-5522-890f-2fc971273a86', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-08-26', '17:30:00', null, '通常 / 変数の使い方（カウント）をマスターする（ピンポンゲーム）', 'ピンポンゲームで変数を使いこなす、特に減るというのはどうやってやったらいいか？を変数で表すのをやってもらいました（単純に増えるだけじゃない） また、ライフや体力という変数に関しては、それぞれのスプライト分作らないといけないということを学んでもらって、今日のやること自体は学び終えてもらいました（タイム、HP、得点という変数のカウント） ただし新しい変数を作った際に前に作っていたコードが干渉して動かないというバグ自体は自分で見つけるのが苦手な様子です。', null, 'タイピング: 今までとちがって段々と得点が増えてきているなと思います。
盛り上がり: アイディアを見つける、ヒントを言えば自分でこうかな？と考えられる力がついてきたと思います。'),
  ('a298e08d-abc6-5c0a-ac45-57e9e819636b', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-08-26', '16:30:00', null, '通常 / キャッチゲームを自分でどこまでできるか（自分が知っているコードをふんだんに使って、どこまで近づけられるか？）', 'まずゲームをやってもらってどこまで自分で再現できるか？をやってもらいました（普段使っているコードでどこまでかけるか、座標の理解度） もちろん、左右に動くことはできる、そして上から下へスプライトが動くという理解もきちんとしていました→もともとのテキストのコードとの違いはあるものの、よくできたと思います。 そこからキャッチゲームで使用する演算＜の理解と、もう一度上に戻るということを新しく学んでもらいました。 変数の使い方も得点に関しては問題ないと思います。 すこし弱いかな？と思うのはXとYの違いかなとおもっています（縦、横が迷うみたい）', '最後のYou Winを出すところのみです', 'タイピング: 休み明けかすこし集中力が切れていたのが目につきましたが、なんとか最後までやり切ることができました。以前よりスコア自体は低くなっているものの、腕試しで長い文章を2年生で出来ることが素晴らしいと思います。
盛り上がり: 自分で作ることにとても自信があるように思いました。迷いながらもコレだよなと考えられることが出来る。'),
  ('80c64944-ceea-56d8-bf92-dc78ee65a676', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-08-26', '17:30:00', null, '通常 / キャッチゲームの作成を通して座標や動きの復習', 'ゲームで遊んだ後の細分化シートはかなり頑張って書けていました。プログラムを言語化することにはあまり抵抗がなさそうです。 反対に、言語化したものをブロックに直すときは、言葉の印象だけで先走ってしまうことが多々あります。「これでいい？」「これかな？」と先生の様子を伺いながら適当にブロックを持ってくる傾向があるので、とりあえずそのまま動かしてみたり、ブロックを一緒に見ながらどういう動作になっているか確認したりして、少しずつブロックを自力で読み解くよう促していきました。 今日の最後のあたりでは、このブロックはこの動きのためのものだから、ブロックの順番はこうなる、ということを自分で考えることができました。 座標を○○にする、座標を○○ずつかえる、〇秒で座標を○○にするの使い分けに混乱が見られました。実際にブロックを使わせて、このゲームにはどの動きが必要かを考えてもらいました。', 'スコアの作成から', 'タイピング: 8月の腕試しにチャレンジしていました。時間はかなりかかりましたが、途中で投げ出さずにやり遂げていました。
盛り上がり: コースを進める間に少しずつヒントを減らしていって、最後の方は自分で作成したコードを読み解けるようになっていました。数学的なことはあまり得意ではなさそうですが、言語化の能力をうまく活かして、自力でできることを増やしていきたいところです。 ラストに取り組んだキャッチしたときの動きのプログラミングでは、さらちゃんが言語化したスプライトの動きと、ブロックを上から読み解いた動きが一致して、とても満足そうでした。
備考: 検定受検については、少ししり込みしていましたが、受験の練習にもアピールポイントにもなるということでやる気になっていました。'),
  ('91e93955-3b94-5e83-bace-c0c09b6a5ea2', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-08-25', '16:30:00', null, '通常 / 検定4級最初に取り組む問題', '試験についてはやる気満々でした。 余裕～と言いながら解いていましたが、途中でアレンジをしたりして、最終的に時間配分の失敗が出てしまいました。（アレンジを記入する時間がなかった…） 基本的には合格点に達していると思われますが、問題文とブロックの順序が違っていたりするところが見受けられました。 余裕があるからこそ、ととらくんを持ち上げつつ、シンプルに問題文通りに作ることが求められていることを説明しました。', null, '盛り上がり: 試験自体は楽しそうに取り組んでいました。 もっと上の級をやりたいというので、順番通りにチャレンジしていこうと声掛けをしました。 プライドも満足するのか、100点を目指したい！と盛り上がっていました。'),
  ('27681928-71cd-5a71-bc1f-6ba90771e41f', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-08-25', '17:30:00', null, '通常 / 検定準備、バグを探せるようになる', '夏休み明けの40分テストで少し疲れたようで、見直しを5分前で切り上げて次回に回しました。 初期設定の部分はカンペキにできていましたが、自信がないところは基本的にブロックをつなげないままにしている傾向がありました。不安なところは先生に聞いてから実行するという癖が出てしまっていたので、この検定を通して、とりあえず自分で実行してみること、バグを探せるようになることを心がけていけるよう、成長を促していきたいところです。', null, 'タイピング: タイピングは順調で、プラチナ級を出せています
盛り上がり: ゆきちゃんの基本操作コースの進み具合のわりには、ブロックの選択などもよく頑張っていました。 試験問題へのメモもしっかりとれていて、曖昧なところときちんとできているところの把握も自力でできています。 計算が入ってくると混乱するようなので、次回、問題を丁寧に読みながらバグを見つける練習をしていきたいです。'),
  ('25bacec8-4194-53b6-89dd-bcbb6ed94d50', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'f3d7071d-8968-5e6a-8563-26ea2abfce8f', '2022-08-25', '17:30:00', null, '休み', null, null, null),
  ('f32dc947-ef11-5450-90c0-beab878aafe3', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-25', '17:30:00', null, '通常 / 迷路脱出ゲーム。壁での跳ね返り方', 'このゲームが気に入ったようでした。 あるくんのコスチュームにかなりこだわっていました。 マウスで歩かす方法は自分で考えてプログラムできていました。 壁で跳ね返るためのアイデアはなかなか出てきませんでした。動いているように「見える」ということに注目して説明しました。 棒の動く様子は歩数の値にこだわることで細かく調節していました。ゲームはきちんと完成しました。 残り時間で回転とクローンを組み合わせて模様を描いて楽しんでいました。', null, 'タイピング: しっかり取り組めていました。
盛り上がり: コスチュームに変化を加えるのが好きなようです！今回の作品も「泥棒」とコンセプトを決めていました！'),
  ('d07c9d1a-2b79-528c-9381-7c175c632b47', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-25', '16:30:00', null, '通常 / 検定問題2級（ロケット）取り組む（検定対策）', '時間内に終えられました（アレンジはしていませんでした） 右へ歩かす・左へ歩かすときに座標を使ってコントロールしていたため見本と異なっていました。「〇歩」と指定があるときは、～歩動くのブロックを使うようにアドバイスしました。 プログラムする場所を把握しきれず自分でアレンジしてしまっている箇所が2箇所ほどありましたが、セクションごとのプログラムはよくできていました。かなり疲れた様子でした。', 'コンテストに向けて作品にどう手を加えるのか考えるようにお願いしました！', 'タイピング: ミス率3%としっかり取り組めていました！
盛り上がり: コンテストに挑戦するか尋ねたときに「する！」とすぐに返答が返ってきました！'),
  ('46fbc1b1-d946-5b77-a41d-b2d7adeef7e0', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-25', '16:30:00', null, '振替え / キャッチゲーム（条件分岐・スコアの加算など）', '口頭でゲームの内容を伝えてもらいました。割と自分で説明できていたように感じました。こちらからの問いかけにははっきり答えられていたので良かったです。 スプライトの名前を変更して、プログラムしやすいようにしていました。割と早い段階から自分でアレンジを加えていました。 「もし、ずっと」の使い方良かったです。一方、不等号の向きは自信なさそうです。両方のブロックを使って確認していました。 上から落とすプログラムは良くできていましたが、上に 再現してほしい様子を実際に見せると、取り組む速度が上がるように感じました。スコアのプログラムはバッチリでした。 ユニコーンに触れたときに上に戻すプログラムを作るとき、「または」を使ってコンパクトにプログラムできていました。', null, '盛り上がり: 後半自分でアレンジを加えようと頑張ってくれました！'),
  ('42cc5ec9-11e3-59ac-a79e-9ed5837807bd', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-08-25', '16:30:00', null, '通常 / 基本の見直し、メッセージの送受信と座標の復習', '5月に作成していたダンスプログラムに追加していく形で、メッセージの送受信とスタート位置の座標の設定をしました。 コスチュームを変えるとき、コスチューム名を指定するやり方と、コスチュームを希望通りの順に並べておき、「次のコスチュームにする」を使うやり方を確認しました。 メッセージの送受信やスタート位置の座標については、コンテスト作品で使用したためよく覚えていました。 ダンスの振り付けやステージの様子などを次々に思いつくようで、終始楽しそうに、熱心に作成していました。 次回のつなぎとして、背景もコスチュームと同じようにブロックで変わることを確認して、新線の目が輝いていました。(下迫田)', '背景とバックダンサーを変える希望があったため、そこを作成してからテキストの先に進む予定です。', 'タイピング: かわべの竹林ステージ2をクリアしました。 小文字のフォントによる形の違いが難しいようです。キーボードのgと一覧表のgの形の違いにとまどっていました。'),
  ('a11182f3-9a13-500f-b80c-f240d8680c14', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-09', '17:30:00', null, '通常 / 4級に挑戦。レベルチェック', 'プログラミング検定の役割から確認して始めました。ひとつずつ丁寧に進めている印象でした。自分の力でやろうという気概が感じられました。 何度か動画を確認していました。 座標がうまく制御できずに困っていました。半角と全角を間違えてしまっていたようです。 セクションの1行目を読み飛ばしてしまうことが多く、2~3か所ほどプログラムする場所にミスがありましたが、セクション内のプログラムはとても良くできていました。 難しかったそうです。アレンジとしてはBGMを追加してくれました。検定には挑戦したくない様子でした。', null, null),
  ('2a75b1f4-82db-503f-8340-59718ba5a778', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-09', '17:30:00', null, '通常 / レベルチェック。4級検定問題再チャレンジ', '前回なんとなく始めたようだったので、プログラミング検定の役割から確認して始めました。 かなり早く進めていましたが、あまり完成までは至りませんでした。 分からなくなると、動画をみて自分なりに進めてしまっているようでした。傾向としては、文章を読み飛ばしてしまったが故に分からなくなっているような印象を受けました。一つのセクションについてはよくプログラムできていたので、他のセクションとの関係をしっかりと読みこなせればうまくプログラムできるかなと思います。 アレンジとしてBGMを加えていました。', null, '盛り上がり: 以前から作成していたゲームが完成したようです！'),
  ('9a6c22e9-c3dc-581d-8d70-875b066645a3', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-09', '16:30:00', null, '振替え / 変数の使い方と今までの復習（キャッチなど）', 'ボールの動きについては、乱数を使ってよく表現できていました。ただ、y座標の条件式を使うときの不等号の向きには自信がないようです。ボールが跳ね返る動きが思うように動かなかったようなので、見本よりもより条件を細かく設定して跳ね返るようにプログラムしました。 むらっちの動きに歩数を使って少し困っていたので、座標を使ってみるように声をかけました。向きについては変数を使って考えてみるように言うと、自分で初めからしっかり書けていました。 最後、「もし」の塊が多くなってしまい混乱したため、一度全部スクリプトから外してもう一度初めから考えてみるようにアドバイスをしました。ゲーム自体も完成しました！', null, 'タイピング: しぶしぶでしたが取り組んでくれました。ミスタイプ率も6%ほどでした
盛り上がり: 私の作成中のプログラムをみていろいろとアドバイスをくれました。'),
  ('f6a7ebf2-622b-5d67-9e0d-d0b7ca82327a', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-08', '16:30:00', null, '通常 / 加速、減速を表現する変数の使い方', '減速と加速のコードをみて自分でブロックを動かしてもらい、変数の変わり方について一緒に確認しました。変数を掛け算でだんだん変化させる方法が目新しかったようです。 その後、そのコードを参考にアイテムで脱出ゲームを作ってもらいました。 自分なりに考えて、動いた後に変数が少しずつ変化するようなプログラムを作ってくれていましたが、思ったように動いていなかったようです。元のプログラムと見比べて違う点（変化が別のスクリプトでプログラムされている）を見つけて説明してもらい、自分の作品に生かしてもらいました。 一番キーとなっているプログラムとして、変数が一定以上、一定以下にならないように条件分岐を使って制御しているスクリプトを挙げてくれました。 その後、ゲームの他の部分も作ってもらいました。リスタートしたときのピンポンの位置、赤の壁に触れたときの挙動、鍵をカウントする変数などをプログラムしていました、', null, 'タイピング: 長文でしたがあきらめずに取り組んでくれていました。
盛り上がり: 夏休みの宿題はコツコツ進めているそうです！えらい！'),
  ('23f25634-8f4a-53d7-9633-51fba4503c58', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-08', '16:30:00', null, '通常 / ピンポン（もし～なら、角度、乱数の使い方）', '回転・座標についての理解があまり進んでいないようです。パドルを動かすときにx座標、y座標について一緒に復習しました。さらに、パドルで跳ねかえさせるときに「跳ね返る」という動作は回転させて進んでいるということを一緒に確認しました。また、初期位置もあった方が便利ということにも気づき、追加してくれました。 乱数についてもサイコロに例えて説明しました。しっかり伝わったようです。その後、回転について値を試して乱数を使えていました。クリア画面として桜を表示させる、スコアをつけるのはバッチリできていました。タイミングやプログラムをかく場所もよく考えられていました！ 次にやることへの見通しが素晴らしいです。頭の中で細分化ができていると感じました。', null, 'タイピング: 集中して取り組めていました！'),
  ('6a075705-b21f-51c9-9bb4-dbc234cec7ad', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-08', null, null, '通常 / 変数の使い方（ゴルフ）', '動画を見つつ、ひとつひとつ丁寧に進めていました。かなり進んだようです。 新しい発見について：目新しいブロックがあったようです。 今日はゲーム中のどの部分をプログラムしたのか：しっかり言葉で説明してくれていました。 ボールの向きをコントロールしている部分：矢印の向きを動かしてボールの向きを変化させていることと、ボールをコントロールしているプログラムの場所についてしっかり理解できていました。 メーターを動かすプログラム。その動かし方→あまり理解できていませんでした。変数の値が変わることでメーターを上下させていることが把握ができていなかった。プログラムを見つつ変数についての考え方を共有しました。', null, '時間帯: その他
盛り上がり: 夏休みは熱海に遊びに行くみたいです。'),
  ('79e8e9dd-9a6e-5332-938a-0877ca76acf3', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-08', '17:30:00', null, '通常 / ゴルフに挑戦・変数の使い方', '動画見ながら作るのは少し苦手かもしれません。最初は動画を見ずに自分で挑戦したいようでした。完成系を意識してステージ作成をしてくれました。最背面・最前面に配置する方法を共有しました。 ただ、自分でするのには少し難しすぎるように感じたらしく、最終的にはステージを作るところから動画を見始めました。ステージは自分で作りたかったようです。 ステージをつくり終わったところで終わりになりました。次回からは本格的にプログラムに進む予定です。', null, 'タイピング: 上位20%以内に入っていました！前回から順位が上がっていました。
盛り上がり: タイピングで上位20%以内に入り、とても嬉しそうでした！その後ずっとテンションが高かったです！'),
  ('310358e4-cdfe-5e12-ace2-efe77a5d2d37', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-08', '17:30:00', null, '通常 / だるまさんが転んだ（条件分岐・コスチューム変化の考え方）', 'ずっと「負け」の画面が出てしまう不具合について、自分で確認して改善してくれました。その後、ゾンビのプログラミングをしました。 表現したい事象について自分の言葉で論理的に表現できていましたが、「でないとき」を考えてしまっていたため、プログラムを作るのは難しかったようです。同じ物事でも違う言葉で説明できることを説明し、別の考え方を使って（もしを使って）プログラムしてくれました。 最後に、だるまさんが転んだに合う声を自分で録音して流してくれました。タイミングに注意してこだわってプログラムしていました！ 最後まで完成しました！本人もとても楽しそうでした！', null, 'タイピング: とても集中して取り組めていました。集中しすぎていたくらいです。ホームポジションを少し意識できていたので良かったです。
盛り上がり: 時間ギリギリまで集中して取り組めていました！'),
  ('5aa57b4b-3740-5bb9-9ca5-d9f991035f3f', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-08-08', '16:30:00', null, '通常 / キャッチゲームを最後まで', 'すべて自分でコードを書くことはきちんとできる様子で、答えを自分で導き出せていました。', '次回は、キャッチの応用をやると今日は約束しました、ただ次回の気分をみてあげてください。', 'タイピング: なし
盛り上がり: 今日は特に音の部分で、音階を全部自分で作成してキャッチした時に鳴らすということをしていました。（音階を全部揃えるのがめんどくさいのにも関わらず、全部並べていたのでその部分はすごいと思います）'),
  ('a6a6174e-c4a0-5a16-ad1c-ba24df21f10f', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-08-08', '17:30:00', null, '通常 / レースゲームでカウント（順位）をどうつけるか？を考える', 'レースゲームの前半はよかったものの、変数を使うところに理解ができていないようでした。変数をスコアではなく箱として考える考え方を一緒に教えずに次回は、はるとくんが作成した、バレーボールのゲームを使って、変数を箱として考えるという考え方単体をやってみたいと思います。', 'バレーボールが飛ぶ方向を考える（いつも右にいくのをどう左に向かせるか）', 'タイピング: 正答率が高くなってきている様子です。だいぶ長文を打つことも慣れてきたのかな？
盛り上がり: 時間を決めてやると集中するので、よく時間内で考えようとしていました'),
  ('5e8e2396-f13b-5359-9f2a-4538a8a16e1b', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-08-05', '17:30:00', null, '通常 / 前回衝突したらスプライトが消えるというコードを使ったので、当たる対象スプライトを上下に動かして、弾が当たったらというコードを書いてもらう。', 'XとY座標を使って、コードをかくということをしてみました。 １つのスプライトが上下に動くというコードを移しながらでもやってもらい、スプライト同士が当たると変化する、またスコアを追加するということをやってもらいました。 今回は、ほぼ私がこうしてみようか？という提案をしてやってもらったのですが次回はゆきさんの提案の通り、ビデオを見せながらコードを移して書いてみるということをして、ゲームを実際に作ってもらう方がいいのかな？と思っています。', null, 'タイピング: なし
盛り上がり: やりたくないことをなるべく自分で一生懸命やりきることをしてもらいました。'),
  ('947addd5-19b8-5157-9b75-42eec987f6de', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-08-05', '16:30:00', null, '通常 / ジャンプゲームを最後までやる→変数の使い方を再度慣れる', 'コンテストをやっていたためか、触れたらコスチュームが変化するというコードをほとんど一人でできることができた。また、障害物を増やした時に、タイミングをずらすこと、またまたはという演算を使うことをしたいと話してくれたので、すこしずつ頭の中でコードでできることが発想できているような感じがある', null, 'タイピング: すこし夏休みモードになったためか集中力が欠けていた様子。スコア的には問題はないので、今後また休みに入ったあとの様子を注視したほうがいいかも。
盛り上がり: コンテストでおこなっていたこと、特に変数（スコアの部分）は確実に定着している感じです'),
  ('7d0815b6-4cc8-5a0d-847a-e6865bbfecac', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-05', '18:40:00', null, '通常 / 前回の続き:ゴルフゲーム/2級準備', '最後までプログラムし終わりました。 完成後、ボールがうまく動いていなかったので一緒にプログラム内容を確認しました。動くプログラムを入力していないと思っていたようです。 変数を出力してうまくプログラムが動いているかを確認する方法を共有しました。内容を確認した結果、数字の全角半角の入力ミスということが分かりました。 スプライトの上下移動のコントロールのとき、見本通りだと思うように動かなかったので、演算式を工夫して正しく動くように調整してくれていました、さらに、背景のコントロールも数字を変えてプログラムをすっきりしてくれました。完成です。', null, 'タイピング: 姿勢よく取り組めていました。長文も集中してタイピングできていたので良かったです。
盛り上がり: とても難しいコースを作ってくれました！！'),
  ('87c2703e-daf4-5a65-86ce-897f8a1cd946', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-05', '17:30:00', null, '通常 / ピンポンゲーム（回転/簡単なスコア）', 'ボールの動きのプログラムはバッチリでした。「端で跳ね返る」をきちんと入れることが出来ていました。 パドルを動かすのはかなり苦戦しました。パドルとポインターの位置に注目して考えてもらいました。どうしても「ポインターのところへ行く」を使うと思いこんでしまうようです。「ポインターのx座標」のブロックの紹介をしました。 ボールをパドルで跳ね返す動きも、「回転する」と「動かす」の内容に分けるということを説明しました。「〇度に向ける」と「〇度に回す」の使い分けも意識する必要があるようです。乱数は扱わずに回転してもらいました。 ゲーム終了のプログラムはキチンとできていました。 スコアの変数を追加してもらおうとしましたが、集中力が0だったので終了しました。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 試す前にすぐに「分からない」と言ってしまうのがゲームの全体像を示してからプログラムは進めていますが全体像を意識してのプログラムは苦手なようです。タッチパネルになれてしまっていて、マウスの操作に少しイライラしていました。'),
  ('d77dea55-0763-5a9b-aed2-a857fda60b73', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-05', '17:30:00', null, '通常 / ピンポンゲーム（回転/簡単なスコア）・復習', 'ボールの動かし方はよくできていました！ マウスポインターでパドルを動かすのはかなり苦戦しました。マウスポインターとパドルのx座標が同じということに真っ先に気づいてくれましたが、「ポインターへ行く」を使うという考えにとらわれてしまっていました。また、「ずつ変える」と「にする」が混乱していました。 ボールをパドルで跳ね返すプログラムは「角度を変える」「動かす」に分解できていましたが、角度の値に苦戦していました。リアルな現象を再現したかったようです。ゲーム終了のプログラムはバッチリでした。 スコアの設定もしてくれました。点数の加点を別のスクリプトを使ってプログラムしてくれましたが、うまく動かず困っていました。跳ね返るプログラムと同じスクリプトで加点のプログラムを作るとスムーズに動きました。', null, 'タイピング: 親指をけがしていたので、できる範囲で取り組んでもらいました。不合格で残念そうでした。
盛り上がり: パドルの移動について、答えを求めず自分なりに深く考えようとしてくれていました。'),
  ('bbe26623-8e65-54f6-8841-a9d4c1c0d2c1', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-05', '16:30:00', null, '通常 / キャッチゲーム/座標・条件分岐など', '初期位置の設定で乱数を使いたいようでした。(おそらく)乱数に対する思いが強すぎて、座標で初期位置を設定するという考えがすぐに出てきませんでした。 上から下にスプライトを落とすプログラムは、以前コンテスト作品を作ったときにやったので、よく覚えてくれていました。アレンジとしてくるくる回るように作っていました。 下についたスプライトを上に戻すために下にスプライトを設置し、触れたら上に戻すようなプログラムになりました。見本のプログラムとは違うものを作ってくれたので、それぞれ作り終わったあとに見本のプログラムと見比べてもらいました。 キャッチする男の子のプログラムもスムーズに作れました。アレンジとしてコスチュームの変化をつけてくれました。 落ちてくるスプライトのキャッチのプログラムもバッチリでした。', null, '盛り上がり: どうやら定義を使いたいようでしたが、定義の使いどころを考えるようにお願いしました。一時間しっかり集中して取り組むことが出来ました。'),
  ('2b7492e6-0926-5dec-ae68-69afc81b4f15', 'b2246586-4496-52f9-a825-be2488a00a31', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-08-04', '17:30:00', null, '通常 / シューティングゲームをクローンを使って完成しよう', '先週に引き続きシューティングゲームを作っていきました。動画を見ながら作ってやっていこうと思ったが、先週最後に作った敵のhPの変数をいじることに夢中になってしまいました。クローンを使うことを「球を連射させてみない」と誘導して、やってもらうとしましたが、ただ、スプライトをコピーして終わりって感じになってしまい、なかなか進めませんでした。この方法は失敗しました。 まさきくんは、ゲームとして形あるもの（今回は球を発射されるコードを作る）を作ってしまうとそれで作るのはやめて遊んでしまう傾向があるので、作る段階で入れ込むようにしたい', null, '盛り上がり: アレンジも後半楽しんでできていました。'),
  ('2877492d-433b-5871-a13c-c93334cf169e', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-04', '17:30:00', null, '通常 / 基本の復習 迷路脱出ゲーム', '細分化は大まかにはかけていました。 あるくんが歩くプログラムは難しく考えすぎていたようです。「〇秒でポインターの方へ行く」を使っていましたが、思うような動きが出来ず困っていました。「歩く」という動作は無意識に体を向け足を動かしているように、ひとことで説明できる動作でも、より細かい動作に分けることができることを説明しました。 あるくんが黒い壁で跳ね返るプログラムは（検定の苦い記憶のお陰で）自分でしっかりと作ることができていました。その他のプログラムも詰まることなく完成しました。アレンジのリクエストとして、迫る壁がだんだんと速度を上げるようにお願いしました。〇回とx座標のブロックを組み合わせたコードを作ってくれました。一方、変数で作る方法もあったので、そちらはこうくんに説明してもらいました。 もうひとつ自分のアレンジとし、クリアしたタイムが早いほどたくさんのポイントを得られるアレンジを考えてくれました、変数の使い方はばっちりでした。変数同士の足し算もうまく使いこなしていました。', null, 'タイピング: 右手メインでしたが、集中して取り組めていました。
盛り上がり: ゴール直前、壁がゆっくりに動くようなアレンジもしてくれました。'),
  ('08d9f79b-7913-5b3b-8038-3b28747670c8', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-04', '16:30:00', null, '振替え / 基本操作コース/ジャンプゲーム 完成系を意識して製作する。', '本人いわく一度やったことがあるようでしたが、記録では応用の方をみたことがあるのみだったで、取り組んでもらいました。 背景やスプライトにこだわりがあるようで、イチから自分で作りたいようでしたが、既存のものをアレンジしてもらいました。 ジャンプは「〇歩」で動かしていたので、それだと左右に動くことを指摘したところ、気づいて変えてくれました。もしの使い方、スタート位置の設定はバッチリでした。スタート位置の設定もばっちりでした！ 毒を移動させるのは、初期位置を工夫することで「端に触れたら」と「〇歩あるく」を使ってスプライトをコントロールさせました。 音を鳴らす04・障害物の追加06は本人が乗りきではなかったのでスキップしました。作った変数はジャンプで加算されるわけではなく、時間で加算のゲームとなりました。', null, 'タイピング: 手慣れた様子！両手セットできていました。キーの場所はかなり把握できてる感じです。
盛り上がり: 最後に今日の感想を聞いたところ、「楽しかった！」と答えてくれました！'),
  ('d3eb2680-b476-5aa0-9f6a-1b7e09a40545', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, null, '2022-08-04', '17:30:00', null, '休み', null, null, null),
  ('a910ab02-b8e3-56c2-85dd-6866dbd351e5', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-08-04', '16:30:00', null, '通常 / キーでスプライトを動かす、変数、乱数等の復習', '矢印キーでスプライトを動かすのはよく覚えていて、x、y座標を動かすブロックで作成していました。向きについても過去の学習を覚えていました。 迷路にぶつかったときに跳ね返る動作を見本で何度も見せて、どういう動きにしたら壁に当たっているように見えるかを考えてもらいました。数回目くらいで「後ろにさがっている！」と気づくことができました。 ネズミのミミの動きとチーズの動きまでを作成することができました。 スコアの変数も自力で作成できました。', '敵キャラクターの動きを作成予定です。', 'タイピング: 練習の成果で、正答率も速さもかなり上がりましたが、ほぼ右手でクリアしてしまっています。左手でうつよう勧めてはいますが、現状のステージだと右手だけでも困らないため納得しがたいようでしたが、最後の方では忙しくなったようで、左手を使ってくれました。
盛り上がり: 久しぶりに新しいゲームの作成で楽しそうでした。 ゲームで遊んでからの口頭での細分化もほぼできていました。 お父さんに作成中のゲームを見せることができて得意げでした。'),
  ('ae38d1ca-32cc-5726-98c9-fa295318f626', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-02', '17:30:00', null, '通常 / 迷路(壁が迫ってくるもの)でレベルチェック。跳ね返りの動きの確認', '自分ができるところから取り組み始めていたのが良かったです。既存のゲームを真似るのは嫌いではないようです。オリジナルと見比べつつ、自分でしっかりと考えられながらプログラムできていました。 難しく考えすぎてしまうようでした。あるくんの動きは深く考えすぎていたので、物事をシンプルにとらえるようにアドバイスをしました。 初期位置の設定、喋るタイミングなど、普段よく使うコードは自分でしっかりできていました。 壁にあたったときのあるごんの動きのプログラムに悩んでいました。色判定でプログラムを制御するという考えはとても良かったです。「-〇歩動かす」というアイデアはなかなかでてきませんでした。どうやら家で試したときにうまく動かず、うまくプログラムできないと感じていたようです。理論的には納得してくれました。 迷路のプログラムが終わって時間が余っていたので自分で作っているオリジナルの作品を一緒に製作しました。アレンジよりもそちらをやりたかったようです。銃の向きについて一緒に考えることができました。', null, 'タイピング: うでだめし。気が乗らないようでしたが、取り組んでくれました。
盛り上がり: 一時間しっかりと集中して取り組めていたので良かったです。'),
  ('9ae20d34-4043-52d9-a6a5-2601dd8c372f', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-02', '16:30:00', null, '通常 / ジャンプゲーム もしの使い方など、復習', 'ジャンプゲームが途中まで進んでいたので続きからやりました。 初期位置と見せる・隠すの関係があまり理解できていませんでした。プレイヤーに見てほしいところとそうでないところを意識してプログラムことを伝えました。何をどこ(だれ)にプログラムしたかの意識が薄かったです。プログラムを読むのが苦手なようです。 すぐに「分からない」と言ってしまうのが本当にもったいないなと思います。分からない理由を聞いたり、どうしてそこにプログラムをするのかを聞いたりしました。アレンジになると気分がかなり上がるようです。 ジャンプゲーム応用をやってみたかったようなので、ようくんのレベルでできる範囲で作ったものにアレンジを加えてみました。', null, 'タイピング: 100点を取ることを目標にしていました。楽しそうにプレイしていました。
盛り上がり: 夏休みたのしいイベントがあるそうです！途中はやく終えたそうでしたが、後半はやる気が出せてオリジナリティも出てきました！'),
  ('46aeb7ee-9da7-5851-ad0f-3ecd81ef96ba', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-08-01', '17:30:00', null, '通常 / 風船を割るレース', '変数の使い方を学ぶことが今日はメイン なるべくどういう仕組みになっているのか？を自分で考えてコードを最初から作る わかっていること ・変数の使い所 ・連打しないとスプライトが動かないということ ここで問題なのはわかっているけど、使い方がどうしてもわからないというもどかしさがだいきくんにある様子。 変数は最初の数字を決めないといけないんだよということが忘れてしまうらしく、それを忘れているために、変数をコードの中に挿入しても動いてくれない（カウントの部分）がありました 特にカウントは、繰り返すというコードを使うことでカウントできるのだというのを知らなかった様子なので、コードを重ねて乗り切ろうとしていました。 今後は変数の使い方をどんどん学んでいってほしいと思います。', null, '盛り上がり: 連打の部分が最初からわかったこと→わかるけどできない、でもこのコードで書くということを覚えればいいんだ！というのがわかったのが嬉しかった様子（新しいアイテムを獲得したみたいな）'),
  ('f89aa296-aca8-5d41-aa64-fcbbf4dc4b75', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-08-01', '17:30:00', null, '通常 / だるまさんがころんだを見てコードを書く', '最初にゲームを行って、動画を見ながらコードを書いて良いよと伝えたところ、自力で書く！と言ってくれました わかるコード ・左キーで動く ・鬼が振り向くために向きを左にしないといけない →ここは反転させるというのはなんとなくわかっていたけど、どこにあるのかわからない様子だったので手伝いました ・触れたらゲームが止まる ここまでは全部自分でやってくれました', null, 'タイピング: 3文字のタイピングにも少しずつ慣れてきているので、そろそろ来週あたりから子供タイピングのキーの中段まとめのタイピングを行っても良いのかな？と思います。だいぶ成長している（大文字と小文字の見分け方がわかるようになっている）
盛り上がり: 途中わからない！と嘆きながらも自分でやりきろう！という努力がこの1年でとても成長。 わかるコードはゼッタイ自分でやるんだ！という気持ちが素晴らしいと思います。'),
  ('f2b164b7-fc65-5e13-8132-f32cc4d9348d', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-08-01', '17:30:00', null, '通常 / だるまさんがころんだ→判定をどこでするのか、調べるコードを使って負けという判定をつくる→メッセージを送り合うだけではなくという部分の経験値を増やしてほしいandアレンジ', 'だるまさんがころんだ→ 先にチュートリアルをみて全部コードを書く、途中コードの見間違い？があったのかちゃんと動いてくれないバグあり。自分でちゃんとコードを読み解消しました（15分くらいかな） その後、同じコードを使ってですが、違うスプライトを増やして、面を増やしていくというアレンジをしている様子。一応、クリアしたら、次の面というような状態にしようとしている感じ。', null, 'タイピング: １級に成長！すごい！！
盛り上がり: 次回は変数→ゆまちゃんと同じ'),
  ('45a0a82f-58f0-5f8a-bbf1-1c739e0cd332', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'd39c577b-68e4-539b-9ff6-bf62947e0795', '2022-08-02', '17:30:00', null, '通常 / 100m or チーズを探せを自分で書いてみる', '今日はチーズを探せを選んでらい、自分でできるところまで行いました。 ・座標 →乱数を挿入してどこに出現するのか ・色に当たったら-1歩動く →シンプルなコードを変数でのりきろうとする癖 ある意味考え方はとてもいいのだけど、基礎的な部分（さらちゃんのように自分ができる範囲外のことをやろうとしてしまう）というがすっぽ抜けているのかな？と思いました。 ただしこの辺は根気強く、何回も練習すれば少しずつとれていく&上手く使えるようになるのかなと思います。', null, 'タイピング: なし
盛り上がり: いろいろな色を使う、ミミの動きをスムーズにするということ'),
  ('19f9773d-3b59-5cc4-b3c8-58655678d7c5', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-07-29', '17:30:00', null, '通常 / 触れたら消えるというチュートリアルを見せて、ゲームを作っているように見せる（楽しんでもらうため）', 'チュートリアルを最初は見るのを嫌がっていたものの、それでも最後まで試聴しちゃんと２つのスプライトが当たったらきえるというコードを書きました。 またトウキくんの良さとして上下の向きがきちんとわかっているため、上下キーでスプライトを動かすことも一緒にしてもらって、シューティングゲーム風を作ってもらいました。', null, 'タイピング: なし
盛り上がり: ちゃんとゲームっぽくなっているコードがかけること、そしてゲームが早く作りたいと言ってくれたことが最初に来た時よりもはるかに成長しているところかなと思います。'),
  ('2e6b2841-31c9-50e1-b50c-5acb9c7cf418', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-08-01', '17:30:00', null, '通常', '【DKアート】03 レースゲームを用いて、ゲームの細分化をやっていきました。最初に細分化とは何かを説明したとき、ゲームを作る設計図だと理解できました。まず、何のスプライトがあるか聞いたところ、すべてのスプライトを把握できていました。バツの存在を先に気づけていてよかったです。 絵でスプライトをうまく書いていました。実際に作る際には、ゾンビや銃などいいアレンジできていました。長押しすると、ずっとすすでしまうのは、一回一回押したらよかったらなるようにするように提案したが、悩んでできていませんでした。気が付くと喋りが優先してしまうのが少し気になりました。 だが、風船の順位を作るところ以外基本的な動作ができていた次回は順位を作るところからです。', null, 'タイピング: 久々だったので苦戦していました。
盛り上がり: セリフのカウントダウンを漢字にするなど面白いアレンジでした。'),
  ('ab488ad1-7f02-587d-b198-4e3ffb26a0a9', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-08-01', '17:30:00', null, '通常 / ゲームの細分化をしよう', '【DKアート】03 レースゲームを用いて、ゲームの細分化をやっていきました。最初に細分化とは何かを説明したとき、ゲームを作る設計図だと理解できました。まず、何のスプライトがあるか聞いたところ、すべてを把握できていました。そして、どうゆう風に動いているか確認したところ、話しながらもキーがおされたら、どう動くや言うことも理解できていました。実際に作り始めると、あちこちに中途半端に作ってしまっていたので、何から作るか決めたらスムーズに作ってくれました。移動のコードに、「歩」で動くで向きで困っていたが、座標で動かしてごらんとアドバイスしたら、座標で組むことができました。 風船の順位を作るところ以外基本的な動作ができていた次回は順位を作るところからです。', null, 'タイピング: 久々のタイピングでスコアが伸びませんでした
盛り上がり: しゅうくんははやりクリオネ好きらしいです。'),
  ('7a2dbfee-8cec-54db-9942-f9f887bd79ed', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-01', null, null, '振替え / コンテスト作品を出品する', '一番初めにサイコロが出ていたのが気になったので変更してもらいました。 赤、青、水色のスプライトが受け取ったメッセージと異なる挙動をしてしまう点について、再度プログラムを見直して作成してもらいました。誤って座標を入力してしまっていたので、うまく動いていないようでした。 イベントが2回発生してしまう事象のコントロールを変数を使ってプログラムしようとしましたが、最終的にはうまくいきませんでした。今まで自分で作成したメッセージと変数の関係が自分でも説明できていなかったので、少し残念でした。かなり難易度の高いプログラムに挑戦していました。締め切りを意識するという経験ができて良かったと思います。', null, '時間帯: その他
盛り上がり: キャンプに行くみたいです！'),
  ('ce8aa658-d4c1-5bf9-96af-1063c70b43ad', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-08-01', '16:30:00', null, '通常 / 座標を意識しつつ、物語をつくろうを進める。', '録音は以前試したことがあるようだったので、音声合成を使いました。声を変える機能を使って2種類の動物が喋る動きを作ってくれました。 背景の変更のときに少し混乱していました。ひとつずつ上から順番に考えるのはまだ苦手なようです。 座標についても、ピンポンで扱ったということをよく覚えていました。〇秒で～へ行くを覚えていてくれましたが、詳しく座標を指定する方法については忘れてしまっていたようです。 メッセージの存在は覚えてくれていましたが、使い方については本人曰く忘れてしまっていたようです。「無言のテレパシー」と題して紹介しました。少し思い出してくれました。', null, 'タイピング: 片手で取り組もうとしていたので、両手でやってみるように声かけました！集中して取り組めていました！
盛り上がり: 以前やったことを使った教材と合わせて覚えてくれているようです！ 夏休みはお泊りディズニーに行くみたいです！'),
  ('d0e390fa-73ab-5480-bf83-df7628be7c35', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-08-01', '16:30:00', null, '振替え / ゴルフゲーム作成に通じて、変数や条件分岐の使い方を学ぼう', '前回に引き続きゴルフゲームを動画を見ながら一緒に作成しました。 うつのときのゲージのコードに変数を多用していて、少し戸惑うことはあったが、基本スムーズに組み立てることができました。その際に、このコードがどのように役立っているか確認しながらやっていきました。理解もできていたので、次回やれば完成すると思います。', '動画で22：52から続きです', 'タイピング: 素早い止まらいないタイピングでした
盛り上がり: 自分よりも早くコードを組めていて楽しくやっていました'),
  ('fc8325fb-3df0-5bd2-89a3-76a1b4b17ddd', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-07-29', '17:30:00', null, '通常 / だるまさんがころんだ→コスチュームでゴールを判定する（判定はスコアだけでないということを学ぶ）', '途中まで頑張ってみて行なっていたのですが、となりにトウキくんがいたため、色々とトウキくんに教えるということで、集中力を欠いていた気がします。 ただ、向きを変える（右向きにする角度の問題や反転させること）やコスチュームで判定をするということ自体は動画を見て理解してくれていたように思います。ちょっと難点なのは、きちんとコードの変えなければいけない場所の部分の文字を読んでいないことかな。 そのせいでバグになってしまって、うごかない！ということが起きていました。', null, '盛り上がり: トウキくんに教える（ここはこういうふうにコードを書くんだよ）と教えてくれていて、自分が学んだことやゲームの使い方をちゃんと理解しているのはとても頼もしいと思いました。'),
  ('8bca3911-b63d-5673-97e0-abf70265b2e8', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-07-29', '18:40:00', null, '通常 / ゴルフゲームの続き・変数の使い方を学ぶ', '途中まで私が教えるという形になってしまい、矢印がボールの周りに回転するという方法に悩んでいました。（動画を見ずに行なっていたので）途中から、動画を見ながら一緒にやりつつユマちゃんに聞きながら、最初から私もゲームを作るという方式に変えて行いました。 最後は真美さんにバトンタッチし、ユマちゃんに「ここのコードはどういう方法でやるのか教えて？」という問いかけをしながら行なっていたようです。', '今回の続きから〜', '盛り上がり: 問いかけをしたところ、自分がわかる内容を教えるということがとても満足しているようするだったそうです。'),
  ('557031e2-2bf2-536e-b32b-b82f0e8ac8f6', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-29', '17:30:00', null, '通常 / コンテスト作品の完成', '締切が迫っているせいか、ストーリーを進めるところは自分の考えていたアイディアをさくさくと形にすることができていました。 「メッセージを受け取った時」を先に作って、送るブロックを入れ忘れていることが多いです。新しいメッセージを作成するときは、「送る側」から作っていくよう習慣づけていきたいところです。 キャラクターの視点、場面転換などは、さらちゃんのこだわりを自分で形にできていたと思います。 スプライトとコスチューム、メッセージと背景の使い分けなどの復習を兼ねながら進めることができました。', null, '盛り上がり: 50分延長して完成させ、お母さんにも見せることができました！ ストーリーが完成して、とても満足そうでした。'),
  ('29e37b40-96e9-5fe2-aff1-767fb32aecca', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-29', '17:30:00', null, '通常 / 提出作品に手を加えるorスクロールを勉強する', 'コンテストに出品するかを聞きましたが、終始「分からない」と言っていたので、とりあえず遊んで確認してもらいました。両方確認しても結論が出なかったようなので、「自分の最大限の努力を見てほしいなら提出するのが良いと思うし、完璧なものを見てほしかったら無理して提出する必要はないと思う」と伝えたところ、出品しないことになりました。 その後、私が自分で作っている効果やプログラムを紹介しました。私が実現したい動きについて、プログラムを提案してくれました。 最後に、壁が迫る迷路を作ってもらいました。私が自分で実験しているスプライトの動きを、迷路に応用してくれました。暗がりの中を進むあるくんが登場しました。跳ね返る、進むなどの基本的なスプライトの動きは完璧にプログラムしてくれました。', null, '盛り上がり: 私が作っているプログラムを見ているとき、身を乗り出して楽しそうでした。'),
  ('e4302ae0-242f-53cb-a265-b73567a22621', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, null, '2022-08-04', '16:30:00', null, '休み', null, null, null),
  ('4336ed95-e202-5f2c-bf2a-e5efd193b222', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, null, '2022-07-28', '16:30:00', null, '休み', null, null, null),
  ('6cd5a5b7-2519-53f6-b799-d45dd04ca6c6', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-22', '17:30:00', null, '通常 / コンテスト作品の完成', 'お金の受け渡しでは視点を切り替えて手をクローズアップさせたい、などのアイディアはよく出ていて、絵も上手に描いていましたが、それをコードにするときに、すぐに「どうすんのー」と言いがちでした。 よく考えたり、少しのヒントをもらったりするとできることなので、本人の意識の問題かと思われます。', null, '盛り上がり: ゲームのアイディアを形にするところまでは、なかなか良いものを持っていると思います！ ただ、すぐに先生を頼ろうとするところを、一歩こらえて自力で考えることができるようになるとよいかと…。 基本操作コースのときはそれができかけていたので、コンテストが終わったらもう一度基礎に戻り、自分でできるという成功体験を積ませて、自力で考える習慣を取り戻したい所です。'),
  ('0acfb9fa-c654-58d7-96ad-e4ca8b7ce129', 'b2246586-4496-52f9-a825-be2488a00a31', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-07-28', '17:30:00', null, '通常 / シューティングゲームを通して、クローンや「ではない」のコードを習得しよう', 'シューティングゲームを動画を見ながら一緒に作りました。元の作品は戦闘機と鬼のスプライトであったが、虫と踊る人に変更してまさきくんらしいアレンジでした。 基本的なところはただ動画を見るのではなく、見せる前に問いかけをして、考えながらやりました。「もし」を使ったところは少し悩みながらも正解のものと一致して作ることができました。そして、作り終わった時、そのコードを理解させるようにやっていきました。 よくまさくくんはキャラが傾いたまま動いていることがあったので、正立したままでも動かせることはゆっくり理解してあげました。 ところどころ、笑い声を入れるなど独自のアレンジをして正樹の個性を生かしながらやったので、特に不満がたまることがなく、楽しくできていました。 今日は、動画でシューティングゲーム２の12番目まで進みました。', 'シューティングゲーム２ノ13番目からクローンや「ではない」を使うところ最後まで', null),
  ('2acee13b-c313-540a-af6b-af6d8ff2ba34', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-28', '17:30:00', null, '通常 / コンテスト作品・エントリー文のチェック', '・タイムの変数の使い方に気を付けたい！変数リセットの場所を変えてタイムの管理をしました。プログラムを再スタートしたときの不具合が解消できました。・鍵の使い方が初見だと分からなかったので表示させました。・クローン使ってる地面がうまく表示できていなかったので、工夫してもらいました。・中断してリスタートのときに説明が表示されなかったので、コードを見直して改善してもらいました！ 後半は、最終ステージの作成に入りました。ドラゴンの動きやビームの動きを作成した。時間がないなかでしたが、乱数を使ってコスチュームを変更することもあり、譲れない部分がある模様でした。 エンディングの作成までは時間がありませんでした。何とか提出しました。本人的には納得のできない部分があるようです。次回のチャレンジ(9月中提出のやつ)を目指していきたいです。', null, '盛り上がり: 最後の方は悔しそうな様子でした。9月の大会では本気だしたい！'),
  ('53a1f2c4-c19b-5650-b828-aaf9d5e9d4f2', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-22', '16:30:00', null, '通常 / コンテスト作品の完成', 'プレイヤーの動きについて、ゆき先生が修正してくれたコードを見せようとしましたが、「この微妙な動きなのが絵の雰囲気に合っていて好きなんだ」ということで、参照に応じてくれませんでした。本人が満足しているそうなので、これでOKとしました。 スタート画面から説明画面に行き来する仕様を作成していました。 何度かテストプレイをして、「完成！」となりました。', null, '盛り上がり: 本人のこだわりが強かったですが、とらのすけくんなりに、熱心に取り組めていたと思います。 コピーではなく自分で作成したことがとても嬉しかったようで、Scratchで公開したい！とのことでした。'),
  ('a1449d70-43a8-569f-9194-7c82e7134151', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-28', '16:30:00', null, '通常 / コンテスト提出', 'ラスボスの音楽がうまく再生されない件を一緒に考えました。まみさんが事前に変数を使ったコントロールを考案してくださってたので、大枠はかなりスムーズに進みました。 原因は、メッセージと「ずっと」を併用してプログラムをコントロールしてたことにあるように思います。一緒に原因を探していきました。何回かプレイしましたが、プレイ方法によっておこる現象が違ったためかなり難しかったです。 色の判定が原因ではないか、「音を消す」がうまく働いてないのではないか、メッセージ送信にかかかる時間が原因ではないか、などいろいろと考えました。本人も自分なりに考えて原因を探ってくれました。 「〇回繰り返す」が悪影響を及ぼし、音楽が流れないこともありました。 作品は完成しました。', null, '盛り上がり: 一時間集中して頑張ってくれました。こちらの話も手を止めてきいてくれました！'),
  ('9c97ddc8-eab2-5771-b4fe-268ea09c5580', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-28', '17:30:00', null, '通常 / コンテスト作品の完成', 'マス目に進んだ時の各スプライトの動きのコードを地道に作成していました。 コードを作成するスプライトを間違えた時なども、自分で気づいて訂正ができました。 作品自体は完成しなかったため、来週月曜日に振替となりました。', null, '盛り上がり: 自力でやるところと質問するところのメリハリができてきています。'),
  ('ec133fe3-83fb-5ef5-815a-673f2cbf8ef0', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-21', '17:30:00', null, '通常 / コンテスト作品の完成', 'すごろくのマス目やリストができてきたので、マス目ごとのイベントをリストから読み込むなどの地道な作業をひたすらがんばりました！', null, '盛り上がり: 地道な作業を嫌がらず根気よくやるところが、ゆきちゃんの長所です。 コードも丁寧に見ています。 ただ、文字の間違い（変数名の間違い）などは見つけるのが早いですが、コード自体のバグを見つけるのは一人ではなかなか難しいようです。'),
  ('e7c40c88-4af5-52df-9dfe-c2fdf16f6b79', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-28', '16:30:00', null, '通常 / コンテスト作品の完成', 'つった魚の数によって、最後にコメントを出すための背景とコードを作成しました。 タイピングを家でもがんばっているようで、背景の名前の変更や表示するメッセージなども、アルファベット表を見ながら全部自分で入力できました。 さかなの数によって分岐する演算式を作成するため、不等号と「かつ」を教えました。 一度で理解できたようで、「20以上」なら「19より大きい」と入力することなども自力でできていました。「かつ」については意味を完全には理解していないとは思いますが、使い方として覚えたようでした。', null, '盛り上がり: ゲームのテストプレイを丁寧にして、すべてのメッセージがきちんと表示されることを確認して喜んでいました！'),
  ('c5e027ff-bd22-556c-a7ae-e2ed89c4ea91', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-22', '18:40:00', null, '通常 / いろいろな変数の使い方を理解する', 'ホールの絵の作成は得意分野のためか、スラスラとアレンジを入れながら作成していました。 ホール数を変数で制御するところがとても新鮮だったらしく、「こんな使い方をするんだ」と感心していました。', '【Prg】40 ゴルフゲームを作ろう！ の続き', '盛り上がり: デザイン要素と目新しい変数の使い方がうまく混ざっている教材だったせいか、最近の中では楽しそうに取り組んでいました。'),
  ('0426b314-47a7-5457-a898-c6cfd714360a', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-26', '16:30:00', null, '通常 / さあ踊ろうを進める（見た目の変化・メッセージ）', 'コスチューム変更するのに「次のコスチュームにする」を使ってくれました。指定のコスチュームにしたいときには、別のブロックでコスチューム名を指定できることも共有しました。 「ずっと」のブロックが及ぶ範囲の意識が薄いようです。さらにコードを上から順に確認するのも苦手なようです。メッセージ初めてだったようなので細かく説明しました。「送る人」と「受け取る人」の概念を話しました。なんとなく分かってくれたようです。 すこしでも分からない部分があるとすぐに「分からない」と投げてしまうのがもったいないように感じます。分からない部分が私たちに分からないので、できる限り自分なりにブロックを動かしてほしいことをお願いしました。', null, 'タイピング: キーボードを見ないように意識してタイピングをしていました。間違えてキーを押してしまうこともありましたが、チャレンジ精神が良かったです！
盛り上がり: 授業後にはしょうたくんと一緒に同じゲームで遊んでいました。えにしくんから見ると兄弟みたいに見えたそうです。'),
  ('f8907453-d429-554f-828d-2cb0a0e112fe', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-26', '17:30:00', null, '通常 / コンテスト作品の完成', 'コンテストの紙を家で書いてきてくれていました。 授業開始後、少しテストプレイをして軽く修正をして、「完成！」だとのことです。 自宅で本を見ながらいろいろと作成しているらしく、相撲ゲームやPKゲームなどを見せてくれました。 PKゲームのアレンジで、ボールを蹴る足を選択できるように熱心に工夫していました。 ゴールポストにあたったときのノーゴール判定を、演算式を使って工夫して作成しました。', null, '盛り上がり: 好きなサッカーゲームだからか、ゴール判定なども一生懸命考えて、演算式を組み合わせていました。 ゲームのテストプレイを一緒にしてバグが見つかっても、すぐにこちらを頼らずに、「ちょっと待って」と自分で一生懸命に直す姿勢が見られました。'),
  ('d72306ce-91e6-53df-a2a5-909b6a9caf8b', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-26', null, null, '振替え / 2級への準備：ゴルフゲームを作る', '必要なスプライトのみための編集が大変そうでした（池・サンドなど）。図形のコントロールが難し様子でしたが、見本とほぼ同じに仕上げていました。ひとつひとつの作業がとても丁寧でした。いくつか場面がひつようなので、かなりの時間をそちらに取られていました。 [/]の入力方法が分からなかったようなので、シフトキーや英数キーを使うと、様々な記号を入力できることも共有しました。本人的に一番印象に残ったことはキーの打ち方だったそうです。 次回からより本格的にプログラミングに入ります！！ 動画は8:48くらいで終わっています。', null, '時間帯: その他
盛り上がり: 実際にはゴルフをやったことはないそうです。やる気もあんまりないみたい。'),
  ('e7bf1bc2-4891-5c35-8949-f604c364d283', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-26', '17:30:00', null, '振替え / コンテストの作品を出品', '作品概要とアピールポイントは事前に考えてきてくれました。されんちゃんが事前に確認してタイピングをしてくれたそうです。とても読みやすくできていました。 終わりの場面とスコアの追加、カウントダウンの設定をしました。自分がプログラムしたい事象は順番に考えることができていましたが、ブロックの内容と結びつかないことが多いようです。途中、メッセージを使おうとしてくれました。メッセージの役割を把握できていることが分かりました。 最後に、書いてきてくれた内容に今日加えたプログラムの内容を追加して終わりました。', null, '盛り上がり: 忍者のゲームにはまっているようです。'),
  ('dfc4475b-9f2f-5add-9002-cd11e3690f2f', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-26', '17:30:00', null, '通常 / 星取りゲームの細分化・プログラム作成', '細分化の書き方に最初は戸惑ったようですが、場面ごとに分けて書いてくれました。犬の動き・星の動きとそれぞれの関係性が把握できたようです。 星の動きを作るときに混乱したようだったので、前に作ったものを確認しつつ作り直しました。星の位置を設定するときに乱数を使いたいというリクエストがあったので、座標と組み合わせて使いました。乱数は1から6までしか使えないという固定観念があったようで、最初の方はうまく進みませんでした。様々な値を入れて試してもらい、うまく星の位置を設定することが出来ました。自分的にも納得する星の落ち方になりました。 犬の動き、星の初期位置・落ちる動きは完了しました。次回は星のより細かな動きや、星と犬が関連する部分のプログラムに入ると思います。', null, '盛り上がり: ロケットのスプライトが消えてしまったので、代わりにオーブンを使うことになりました！'),
  ('1debb03f-d4bb-51ba-9a78-7f98dafd694b', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-26', '17:30:00', null, '通常 / コンテスト作品の完成', '音楽の切り替えにかなり苦戦していました。 メッセージのやりとりだけでは前の音楽が鳴りやまないため、「ずっと」ではなくて「～まで繰り返す」「～まで待つ」の併用を提案したところ、ブロックの種類に感心していました。 ゲームをテストプレイすればするほど、もっとこうしたい、ここをスッキリさせたいなどの要望が出てくるようで、時間を延長して必死に取り組んでいました。', 'ゲームオーバーの音楽がうまくならないところを、背景を変えることで代用しようともしたのですが、どうしてもギリギリまで考えたいとのことで、明後日に振替を入れました。', '盛り上がり: 1時間半ほど、かなり集中して取り組めていました。 同じような動きを作るのにもいろいろな切り込み方があることに素直に感心しているようでした。'),
  ('99507b79-651e-5e29-868f-4a5469e70be2', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-26', '16:30:00', null, '通常 / 基本操作コース08_さあ踊ろう', '一つ一つの課題に丁寧に取り組み、じっくりと学習することができていました。 画像効果がとても楽しかったようで、全部の効果を試して喜んでいました。 画像効果やスタンプ、背景の色の効果などに盛り上がり、こういうゲームで使いたいなど、想像を膨らませていました。', null, 'タイピング: これまでのおさらいをSでクリアできました
盛り上がり: 習ったことが今後に活かせそうだということをとても喜んで、いつもより饒舌におしゃべりしてくれました。 課題の範囲でストーリー性のある作品を作って楽しそうにしていました。 授業終了後に、前回作成したドラゴンゲームで、「今日習った色の効果を使っている」と嬉しそうに指摘してくれました。'),
  ('a761cdcf-1c06-55cd-b8b0-55059247e29b', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-19', '16:30:00', null, '通常 / 基礎の確認、振り返り', '一人で問題を読むのがまだ難しい部分もあるようでした。それでも一緒に問題を音読したりすると、その先は一人ですることができていました。', null, '盛り上がり: ドリルの後、Scratchの「ドラゴンと棒人間が戦うクソゲー remix」を自分なりにリミックスしてゲームらしくしていました！'),
  ('218704a0-3969-55bb-b4b7-4c6c6593149e', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-19', '16:30:00', null, '通常 / 基礎の確認、振り返り', 'しょうたくんと二人で一生懸命取り組んでくれました。 ドリルをしながら、過去に習ったことを思い出せていけたようでした。', null, '盛り上がり: 一人で進められたときに褒めると、「もうちょっと先までやってみる」とやる気になってくれました。
備考: 毎回「これでいい？」と確認をとりたがるタイプです。 よくできているので、自分で少し進めてからまとめて答え合わせができるように促していきたいです。'),
  ('d8aa7719-536d-5102-8d50-ce494ab38534', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-19', '17:30:00', null, '通常 / コンテスト作品の完成', 'バットに敵が当たった時の判定を、バット側を主体にさせることで確実にできるようになりました！ 敵が強くなると、数回バットを当てないと倒せない仕様がわかりにくかったので、可視化を進めたところ、変数を作成して表示することで解決していました。', 'プレイヤーと敵との体力のバランスの調整、ボス戦での音楽が重複してしまう問題の解決、エントリーシートの記入をする予定です。', '盛り上がり: ゲームが完成形に近づいてきたため、ゲーマーとして直したい部分も見えてきたようでした。 終始楽しんで作成できていたと思います！'),
  ('8579cd32-0728-57b6-ad5b-aeb878c62b08', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-07-19', '17:30:00', null, '通常 / 大会作品完成', '大会ビギナーコースの中級、ねずみとりのアレンジを完成させました。 ねずみをアイスクリームに変える、かわいい作品になりました。 特に、スペースキーを押してアイスをゲットした瞬間に「メロンアイス」に変身するよいうアイデアが出てナイスでした。', '基本操作コースに戻って、次の単元にすすめるといいですね。 検定を目標にやっています。', '盛り上がり: メロンアイスの変身がイメージ通りに上手くできて、とても満足気でした(^_^)v 早めに終わったのでフリーでいいよ～というと、タイピングをやりはじめました。 スコアが自己新記録がでたので、嬉しそうです。'),
  ('e2559085-cd65-5ad4-8783-671583ab07a6', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-07-25', '18:40:00', null, '通常 / コンテストの作品を完成させよう', 'コンテストの作品を続きをやりました。エントリーシートも家である程度書いていたので、スムーズに進められました。 ネズミをすべ得て取り終わった後、ただ終わるだけでなく、時間に応じて、称号を与えるアイデアを追加しました。条件分岐の不等号の向きに苦戦しましたが、一人でミスなく作ることができました。 背景を変えてネズミの居場所感も出していました。 今日加えたアイデアも少し反発もあったが、最後はしっかり描いて作品を完成できました。', null, '盛り上がり: 称号を与える面白くていい。'),
  ('24ac17ba-75f4-532d-94eb-03521ecd3f1e', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-07-25', '16:30:00', null, '通常 / コンテスト作品作成', 'コンテストの作品がまだ終わってなかったので、その続きをやりました。 物語の対話のシーンで細かな位置調整を素早い手際で直せていました。 物語からゲームの場面に代わるとき、ゲームスタートのボタンを押しても進まないバグが発生しました。見た感じわからないバグであったので、ゆきさんが一緒に取り組みました。このバグの原因は、ほかのブロックのコードの中でずっとのループが並列して起こっており、スプライトを押す」のコードが優先して動かなったことでした。 残りはエンディングを作るくらいで、残りは家で作って応募するだけです。', null, null),
  ('71326d3e-788d-58c7-9495-1b6aecd13983', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-07-25', '17:30:00', null, '通常 / コンテストの作品を完成させる', '初級のねずみとりをアレンジ、完成するまでに色々な発想が出てきており、それを実践しようと頑張っていました。途中うまく動かないところがあり、そこはすべて複製をした場所が邪魔している、もしくは不必要なコードがあるという事例があり、コードをきれいにすることはどうでもいいという感じ。本当はそういうところが治ってくるととてもいいゲームになるのになぁと思っています。 ただ全体的にはゲーム自体もとても工夫し、ゲームの行いてが面白いと思えるような内容になっていると思うので、本人も終了した際満足そうでした。', null, 'タイピング: なし
盛り上がり: コードを読む力がだんだん増えてきたように思います。 アイディアが出てくることとコードがつながってきて、実践できてきています。'),
  ('679cd6d9-6af5-5879-ab72-01f553644cde', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-25', '17:30:00', null, '通常 / コンテストの作品提出・シートの記入内容を確認', '前回作ったプログラムに細かな調整を加えていました。 エントリーシートに書かれたゲームの概要と実際のプログラムとの整合性を確認しました。クリオネのサイズを変えたり、ゲームクリアの条件をより正確にしたりしました。 シートの方にはゲームのクリア条件やアピールポイントの追加などをしましたが、大枠ははっきりと書いてありました。パソコンのテキストに入力しつつ、他の人が読みやすいように体裁を整えてくれました！「回復」「加点」など言葉のチョイスにもこだわれました。 作品は提出できました！', null, '盛り上がり: 「競猫」をおうすけくんと一緒にプレイしていました。気に入ったみたいです！'),
  ('0873f04b-fa23-58ca-98c9-beca6a03e191', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-07-25', '16:30:00', null, '通常 / コンテストの完成と提出、追跡ゲームの応用', 'コンテストはすでに作成仕上がっていたので、それを文章にして提出する →追跡ゲームが忘れていそうだということだったので、応用問題としてマウスで追いかけるというコードを使うこと、乱数を使って座標をランダムに出すということをしながらゲームをさらに面白くすることを学習しました。', null, 'タイピング: なし
盛り上がり: 途中乱数のチュートリアルを見ている時に、人生ゲームとかを作る時に使えそうだねと行っていたので、本人の頭の中に、実際のゲームとコードが繋がっているように思いました。'),
  ('ca899519-9a86-53ed-90d6-9438622f5ad9', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-25', '17:30:00', null, '通常 / コンテスト作品を完成させて提出', 'プログラムの最後の方がうまくい動いていなかったので、確認しました。改善場所(色判定がうまく働いていないかもしれないこと)は伝えましたが、改善方法は自分で考えてくれました！背景やスプライトに工夫の詰まったプログラムになりました。 エントリーシートも事前に書いてきてくれていました。操作方法やコンセプトがしっかり書かれていました。アピールポイントが少なかったので、ドット絵を自分で描いたことを思い出してもらいました。パソコンに内容を自分で入力しつつ、体裁を整えたり、内容を追加したりしていました。', null, 'タイピング: コンテスト作品提出後に取り組んでくれました。ミスタイプ率3％、3タイプ/秒でプラチナ級でした。姿勢も良かったです。
盛り上がり: 入力した内容を、保存前に入念に確認していました。'),
  ('4cddc600-8177-5bf5-9047-58acfb424593', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-22', '17:30:00', null, '通常', 'オープニングと仕事ゲームを別のファイルで作っていたため、統合ができずに自宅で先に進めることができなかったようでした。 双方のコードやスプライトの数や重複している部分などを見比べてもらい、仕事ゲームの方に統合することにして、オープニングのみにあるスプライトと背景をバックパック経由で複製しました。バックパックを使うと良さそうなことはわかっていたけれど、それをしたことにより不具合が出ることが不安だったそうです。 何度も実行を繰り返し、不具合が出ている部分を確認しては、一つずつコードを確認しました。ほとんどの部分はメッセージを新規に作成してわけることで解決しました。 表示のタイミングや変数の変更などは、はるとくんが自力で見つけて直すことができました。', '提出します！', '盛り上がり: オープニングからゲームまでの動きがつながったときは、とても嬉しそうでした！ うまくいかなくなったとき、いつもよりは「もういやだ」という態度を見せるのが早かったようでしたが、ゲームが動き出すと、「実はここも直したかった」「ここが気になる」と向上心がでてきていたのが良かったです。（時間的には厳しいとしても、やろうとする意欲が復活したようだったので…）'),
  ('cd265ab8-3020-55a7-8a5f-e1ce9afa86eb', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-21', '16:30:00', null, '通常 / コンテスト作品作成', '自分なりにゲームの難易度を考えてきたらしく、つりざおと魚が触れた判定を、一部分の色でなくスプライト同士に変えていました。結果、魚を釣った時の動作が思い通りにできたらしく、とても喜んでいました！ 何度もゲームをプレイして、ゲームの難易度やバランスをよく考えていました。', 'クリアしたときの釣った数により、レベルが表示される部分を作成して提出します。', 'タイピング: コンテスト作品作成に重点をおいたので、1ステージだけチャレンジしました。 家ではもっと進んでいる！とのことです。
盛り上がり: 「触れた」判定をスプライト同士にしたことで、思い通りに魚が釣れるようになり、お母さんにも大喜びで見せていました！'),
  ('226ba662-a523-52fc-8e2f-7a915014c917', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-21', '17:30:00', null, '通常 / コンテスト作品の完成', '前回とても面白い（プログラムによると特定のユーザーか、または必要なキーを順番に押さないとプレイができない）アレンジをしてくれましたが、コンテストの出品に必要な要素かどうかを自分で改めて確認しもらいました。しっかり整理ができたようです。 コンテストのフォームに記入するようのアピールポイントを自分で考えてくれていました。残りの時間で、文章を自分でパソコンに入力してくれていました。箇条書きにしたり、ナンバリングをつくったりして読みやすく工夫できていたので良かったです。', null, 'タイピング: 誤タッチが多かったようです。姿勢よく取り組めていたので良かったです。
盛り上がり: 集中して取り組めていました！コンテスト終了です！'),
  ('2b926dcc-09c2-5e50-8a0d-bbd58837bbdd', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-21', '17:30:00', null, '通常 / 上に同じ', null, null, null),
  ('b370ab8e-cf54-534f-8fd7-3bddc0aef95d', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-21', '16:30:00', null, '振替え / コンテスト作品の続き。参考にしたプログラムがあるのかどうか', '参考文献の話をしました。ちょっとわかってくれたようです。参考にしたプログラムを教えてくれるそうです。 前半のストーリーは後でくっつけるそうです。 スプライトの動きやステージの様子は先々週から劇的に変わっていたのでびっくりしました。 エンドストーリーもいれてもらいました。世界観にマッチするように表示のさせ方を工夫してくれました。その後、オープニングのストーリーを本プログラムに移植しました。大体の表示はできたそうですが、細かい表示がまだなので、見直したいそうです。', '全体の見返し。エントリー文の確認。', '盛り上がり: 家でも4時間くらい取り組んでから教室に来てくれたみたいです。途中5分ほど休憩時間を作りましたが、すばらしい集中力でした！'),
  ('100d5f20-57ef-5db5-a693-7926411add41', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-07-21', '17:30:00', null, '通常 / コンテストの応募シートを作ろう', '今日は前回作ったアレンジのアピールポイントを考えました。 最初は、思いつかなかったが、作ったゲームをしながら書いていきました。コードの丸写しのような文章になったが、場面の転換点や終わり方を描くことができました。 商品が間に合わなくてモチベーションが上がらないのか、もっとアピールポイントがあるのに、ほかのゲームをやってしまい、だれることが見られました。このめんどくさくなる癖がちょっと心配です。 ・元のゲームと見比べてもらって、アレンジポイントを書きやすくしました。少し文章校正ながら、取り組みました。 これにて、コンテストは応募まで終わりました。', null, null),
  ('f6af5852-e032-59df-a151-d4e0011f4fdc', 'b2246586-4496-52f9-a825-be2488a00a31', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-21', '17:30:00', null, '通常 / 新しく作品を作る', '新しくお寿司を使ったアニメーションを考えてくれました。クリックするとお寿司が食べられていく様子がプログラミングされていました。コックさんの帽子もそれっぽく見えるように図形を変えていました！ 前回のアニメーションの続きを考えてくれました。自分でタイピング表を見つつ、変数名などを入力していました。前回砂漠の場面で終わったので、砂漠の背景から始めていました。 途中、自分でやってもうまくいかないことがあったようで、こちらから問いかけても先に進まなかったので中断しました。 次回は気分を入れ替えて、先に進めてみたいなと思っています。', null, 'タイピング: 途中、取り組んでくれました。前回の挑戦からかなり時間が空いてしまったので、キーの位置を忘れてしまっている様子でした。
盛り上がり: ウノが好きなようです！！かなり真剣に取り組んでいました。'),
  ('3c6e7328-f0a0-5401-bc07-e05b68e3098d', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-15', '16:30:00', null, '通常 / コンテスト作品の作成', 'プレイヤーキャラクターの体力が0になった時に3秒間停止したあと動き出すのがスムーズにいかないバグを発見し、自力で直していました。（ずっとの位置） 畑の荒らされ度の設定で、変数でやるところをブロック定義でやろうとして挫折していました。そこはブロック定義の必要はないということは、自分でいろいろ試してみてうまくいかなくなるまで納得できない様子だったため、本人の試行錯誤に任せてみました。 最終的に、時間とゲーム性の問題から、畑の荒らされ度をやめて時間制に切り替えていました。', null, '盛り上がり: 自分でプレイしながら設定をやりやすいように変えていく切り替えは見事でした！'),
  ('92e4069b-f48d-5d27-9c15-bfb85f0193af', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-15', '17:30:00', null, '通常 / コンテスト作品の作成', '自分ではまず何をするべきかには迷うようで、早めに入室しても声をかけるまでは手を付けられずにいましたが、今日やることを一緒に確認したら、自分がやりたいことを口で説明してくれて、作成に入ることができました。 クリア後の家の絵や大きさの調整をしました。 オープニングムービーを作成しました！ 占い師のセリフをランダムにしたいとのことで、乱数を使うのかとの質問に肯定でこたえたところ、自分でコードを作成できていました。', null, '盛り上がり: 「これでいいですか？」という確認の問いかけにGOを出すと、自分で考えて作成に入ることができています。作成自体は自力で考えることができているので、作成までのきっかけを自分でうまく作れるようになるといいなあ、と…。
備考: 将来の夢はプログラマー、とはっきり言ってくれました！'),
  ('ac2ec405-76ef-56b3-856e-795452d6fed6', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-07-15', '16:30:00', null, '通常 / コンテストの準備', 'ほぼ自分でアレンジはできたと感じているので、ひとまず提出の紙になにをしたのかを書いてもらいました。 ひとつだけ、私がわからなかった部分があるので、そこは変数を試しに使ってみて、誰にでもわかるようにと提案してみました（変数の使い方はもちろん教えました） 一通り終わったので中級の問題も作成してもらい、授業は終わりました。', null, 'タイピング: なし
盛り上がり: 自分のやりたいことをきちんとできたこと、また私と一緒に追加のアレンジをできたことに関して満足をしていた様子でした。'),
  ('ff49a81e-75f6-5b53-bb46-a3cdaab811a8', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-07-15', '17:30:00', null, '通常 / 検定３級 練習問題', '今日は隣にいながら、一緒に考えて検定の問題を解いてもらいました。 文章を見る、読むことはとてもアップしているものの、どのコードを使うというヒントを見ずにやりがち。 また３級になると文章の書き方が少し難しくなる&演算を使う問題がでてくるので、文章でかかれると理解することがどうしても苦手な様子です。 ただ、一緒にやることで、試行錯誤をするということはしてくれるので、検定３が合格するか？というと、今のレベル感だと難しい可能性がありますが、人とやることでコードを書くということは楽しんでやってくれているようです。', null, 'タイピング: なし
盛り上がり: クラウド変数を使った時に、とても嬉しそうにしていました。（新しい発見）'),
  ('53f9a4ef-e198-5823-8e4d-6e9ad3112438', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-12', '17:30:00', null, '通常', '先週から作成しているジャンプゲームをコンテストに出すことを決めたところ、積極的に修正やアレンジにとりかかっていました。 敵スプライトが、動きの向きなどからより自然に見えるように、日本刀からビームに直したり、残り時間を設定したりと、本人なりの工夫が見られました。', null, '盛り上がり: コンテストに出せる目途がたったからか、授業前から熱心に作品の見直しをしていました！ 集中力もいつもより続いていたかと思います。'),
  ('4293a841-6bb9-5ea4-92cb-b2a8c0a651c9', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-12', '17:30:00', null, '通常 / コンテスト作品作成', 'ゲームを何度もプレイしながら、難易度や判定などの調整をしました。 プレイヤーとしての視点をとても大切にしていて、操作性などもよく確かめてはコードを見直していました。', null, '盛り上がり: 自分でもよくゲームをするからか、確認を丁寧にしてコードを見直す姿勢はよかったです。 ただ、まだ経験が浅いため、自分でバグを見つけるのが難しそうではありました。 一時的にコードを分解したり、数値を書きかえたりしてバグを探しやすくする方法を提示したら、自分で覚えてやってくれるようになりました。'),
  ('895e4011-b89a-5781-ae02-a31b15cdabde', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-15', '17:30:00', null, '通常 / 新しいプログラミング体験', 'お絵描きはもう飽きてきた、とのことで、「お絵描きしたものを動かそう」をめあてに、Viscuitに取り組みました。 描いた魚を海の中で好きなように動かせたときは喜んで、丁寧にいろいろな魚を描いては動かしていました。 さかなをタッチしたら消えるゲームまで作成して、残り25分くらいは自由時間にしました。 隣の晴くんがゲームをしていたせいもあるのか、とても集中してゲームで遊んでいました。', null, '盛り上がり: 新しいことには嬉しそうに反応してくれます！'),
  ('667e0476-f8fb-5ca9-bd75-f6c5660b57a5', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-08', '17:30:00', null, '通常 / コンテストビギナーズ部門の作成', 'コンテスト作品の作成を何度か進めてみましたが、「無理」「できない」とかたくなでした…。 自分がこれまでに作ったゲームを披露して自慢したい様子だったので、作品を見てはコードの説明を促して、自分の作成したコードを見直すことに挑戦してもらいました。', null, '盛り上がり: まわりがコンテストモードのせいか、いつもよりかたくなに、自分の過去作品にこだわっていました。そのときの気分によっては、コンテスト応募もいけたのではないかとも思うのですが…。'),
  ('9b6b7ab2-b3fc-5175-a91a-9667c0bf42be', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-08', '18:40:00', null, '通常 / 変数の見直し／DKアート ふくわらい作成', '前回の変数の課題「1～100までのすべての和」を計算するコードについて、一緒に再考しました。変数を2つ使うというヒントでなんとなくの理解はできたようでしたが、自分で一から考えるのはまだ厳しそうでした。 やりかけの作品を気にしていたので、ふくわらいの続きの絵を描きました。絵だけで終わらないよう、コード作成の時間を必ずとることを伝え、お絵描きをどこで切り上げるのか自分で計画を立てて取り組みました。', '問いに答えさせるというパターンが好きそうなので、リストの学習も良いのではないかと…', '盛り上がり: 変数もふくわらいも、それなりには集中して取り組んでくれました。
備考: プログラミングで何かを作成することの新鮮味が薄れているような様子です…。 課題の選定が悩ましいところです…'),
  ('8df6b8d2-0fc9-586a-81c2-b77a21faea2a', 'b2246586-4496-52f9-a825-be2488a00a31', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-07-14', '17:30:00', null, '通常', '今日は2つもゲームを作っていました。 1つ目は、スプライトが表示されているときにクリックしてスコアを稼ぎ、50秒間でどこまでできるか競うゲームでした。ねこ、チェックマーク、ボールトで出現時間と大きさを工夫して、それに応じた難易度で得点も変わるように作られていて程よい難易度で遊べるゲームになっていました。 2つ目は、指示を与えてこともなく2人でできるピンポンゲームを作っていました。ボールの反射は途中どうやるかわからないと尋ねてきたので、テキストの「ピンポンゲーム」を見ながら一緒に作っていきました。そのとき、左右の反射で算数的理解を拒んでいたので乱数で代用しました。だが、左へ反射するときは向きはマイナスへ、右はプラスへ変わることは認識できました。 端についたら、スコアを欲しいといったので、色付きブッロクを置いてやったらみたらと提案したら、そのあとは、一人で作れることができました。 だんだんと、ゲームらしいゲームが作れるようになっているような気がします。', null, '盛り上がり: 今日も発表意欲が高くてよかったです。'),
  ('dc64983a-f672-5c12-b897-87cced68f20c', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-14', '17:30:00', null, '通常 / コンテスト作品作成', '変数のおさらいをしながら、大量の変数作成をしました！ゲームスタート前の職業選択と所持金、ゲームスタート後のマス目の位置などを変数で動かすようにすることができました！ スタート時のキャラクターの動きや音楽などもこだわって調整していました。 コードが長くなってしまったので、職業と給料の項目を定義でまとめる方法を学習しました。', 'キャラクターがマス目に行く調整、サイコロの順番がどのキャラクターかの判定、マス目の中身をリストから引き出す部分の作成をして、完成を目指します。', '盛り上がり: 当初の計画とはだいぶ変わったそうですが、人生ゲームらしい作品ができてきて嬉しそうにしていました。
備考: 応募の下書き用紙を承太郎君の分も合わせて持ち帰ってもらいました。'),
  ('f6523fd4-5f3e-523a-8429-49fa7e9ba16c', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-14', '16:30:00', null, '通常 / コンテスト作品作成', 'ゲームの始まりと終わりをはっきりするよう要望を出したところ、得点によってベテラン車掌さん、測定不能などのランキングを作成してくれました。これまでよく作っていた行先表示板で、スプライトのコスチュームの切り替えで結果を表示していたスキルが役立ちました！', '応募項目の紙に記入してくる宿題を出したので、それをもとに見直しをしてエントリーする予定です。', 'タイピング: 1度だけチャレンジしていました。
盛り上がり: ひいろくんの好きな行先表示板の経験が活かせて楽しそうに作成していました。'),
  ('658bf3e8-329e-571b-a1ea-d7a7b6f2bb83', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-07-14', '17:30:00', null, '通常 / ビギナー部門の中級のアレンジをしよう', 'ビギナー部門の中級の「ねずみとり」の作品を作成・アレンジを行っていきました。動画を見ながらの作成は特に困ることなくスムーズに進めていました。 ・ねことねずみをキツネと魚に置き換えてアレンジを行っていました。魚を全て食べ終わった後、背景を変えることを変数を使ってやっていましたが、時間はかかりましたが自分一人で完成することができました。 最後に、旗を押してゲームを行う時2回押さなければ始まらないバグが起こっていました。このバグは使っているコードは正しいが、並べ方の違いで発生するバグなので、こどもたちには見つけにくいので教えながら一緒に直しました。「もし」の条件分岐で変数が使われているとき、別の場所で変数の初期化をするのではなく、「もし」のブロックの前に直列で変数の初期化のコードを置くことで直せました。コードを別々にして並列に作ることはいいが、「もし」で変数が使われるときは、その前に変数の初期化を置くことを注意した方がいい。これは、ほかの子でも起きることなので、注意すべき。 ・キツネが全部食べ終わった後、ベットに戻って「おやすみ」とセリフを言うのがとてもかわいらしいアレンジでよかったです。 ・両方作品を作って中級の方をコンテストを出すそうです。', null, '盛り上がり: 50分集中して取り組めていました。'),
  ('aca4e546-9a5f-5403-8f4e-a2796e0a3207', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-14', '16:30:00', null, '通常 / コンテスト作品', 'つりざおと魚が触れた時の色判定がうまくいかずに、30分ほどで疲れてしまいました。 ストーリーはできあがっているので、それを形にしたい気持ちが強いようです。', '色の判定がうまくいかない原因が、色の主語をそのスプライトの色にしていなかったことにありました。色の位置を逆にしたらうまくいけそうなので、次回はそこを直して完成にもっていきたいです。', 'タイピング: ステージでキーボードガイドが出なくなってしまったので、道場でキーボードガイドを見ながら練習してからステージに戻っていました。みごとにガイドがなくてもうてるようになっていました！
盛り上がり: ゲームの完成形については、とても熱心に話してくれました。'),
  ('42f1c82a-6add-5163-98bb-c09a94811713', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2022-07-14', '17:30:00', null, '休み', null, null, null),
  ('f5fe0d75-c3cf-5c16-af27-9f80f872ef5d', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-12', '16:30:00', null, '通常 / コンテスト作品の見直し、完成', '前回でほぼ完成していたので、自分で何度かプレイしてみて、気になるところを探しました。 ゲームクリアが明確ではなかったので、ピンポンゲームの復習をしながら、どちらかの魚の大きさが500になったら「○○のかち」スプライトを表示してすべてを止めるコードを追加しました。 演算式や変数などは、作成しながらどんどん思い出してきた感じでした。今回はちょうどよい復習にもなったのが良かったかと…。', 'Entryと提出', '盛り上がり: 作成したゲームを何度もプレイして見直しして、とてもスッキリしたようでした！'),
  ('9c936d25-308f-561d-b933-3d5b542f67a8', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-12', '17:30:00', null, '振替え / コンテスト作品進める（内容を整理する）', 'コンテストに出品することを意識して、画面にあった不要なもの（ドーナツなど）整理をしました。すごろくは時計として機能しているそうです。グリフィンの存在やサイコロの意義が分かりにくいことを伝えると、はじめの画面を作成することになりました。おわりの画面・はじまりの画面の表示をしました。他のスプライトが終わりや始まりの画面にでないように、それぞれの画面をスプライトとして作り「最前面にする」を使ってコントロールできていたので良かったです。 グリフィンはサイコロの存在意義が分かりにくいことを伝えると、はじめの画面にグリフィンの存在を伝えるような文言を追加してくれました。 ライオンの向きがずっと右になっていたので、左右に向くようにプログラムしてくれました。「左右に回転のみ」のブロックも適切に使うことができていました。 エントリーシートに記入してもらうようにお願いしました。頑張ったポイントがたくさんあるので、しっかり書いてほしいです！！', null, '盛り上がり: 授業前のゲームでコインがたくさんとれたといって見せてくれました。ようくんが作ったゲームで一緒に遊んだりもしたようです。'),
  ('8258dd26-e990-5b0c-b0fe-a843a75b6b08', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-12', '17:30:00', null, '通常 / コンテスト中級に挑戦 提出する方を決める。', '動画を見てスラスラ取り組んでいました。つっかかることなく最後まで進められていました。 途中プログラムが消えてしまうアクシデントに遭遇してしまったものの、最後まであきらめることなく取り組めていて良かったです。アレンジ内容を考えるのが少し難しそうでした。アレンジとして、アイスを出現させていました。途中で見た目が変わるのもポイントだそうです。かわいい作品名も考えてくれました！ 本人の希望で中級の方を出品することになりました。エントリーシートはほぼかけているそうですが、来週も今週の作品にアレンジを加えていく予定です。', '中級アレンジ続き', 'タイピング: 授業前・後に熱心に取り組んでいました！！
盛り上がり: タイピングが楽しそうでした！長文が特に好きなようです。'),
  ('16188894-3d47-5d38-b937-2e5d17221cfe', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-12', '16:30:00', null, '通常 / さあ踊ろうに挑戦 コンテストのペーパーの話', 'コンテスト作品が良くできていたので、さあ踊ろうに進みました。 01:コスチュームを変えることは出来ましたが、時間を設定するのを忘れていました。本人は思ったようにプログラムが動かず、少し困っている様子でした。 02・03:時間もしっかり設定できていました。コスチュームもひとつずつ確認して、自分が使いたいものを選んでいました。最後に出現させたコスチュームを見せるための時間を設定し忘れていましたが、上からプログラムを見直してミスに気づけたので良かったです。 04:一人の動きをまずプログラムしました。メッセージを使って次の人が踊り出すということを伝えると、使い方やブロックを置く場所はバッチリでした！次の人が踊り出すときに、「メッセージを受け取る」ということは忘れてしまっていました。 文字を打つときに必ずホームポジションを意識していて素晴らしかったです！ 「コスチュームを変えた後は必ず見せるための時間を設定する」ということを繰り返しできました！', null, 'タイピング: ホームポジションを意識できていて素晴らしいです。集中して取り組めていました。 評価Aにならないと次のステージに進めません！苦戦中です！
盛り上がり: コンテストの作品について、これをこのまま出品しても良いかを聞くと「おっけー」とはっきり返事をしてくれました！自信があるみたいです！！'),
  ('2beb856f-3c62-5b0c-972f-4338f8f67836', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-07-11', '17:30:00', null, '通常 / アレンジの続きを作ろう', '前回作ったビギナー部門のアレンジの続きをやっていきました。 ・前回、ボスの体力が減らしても元に戻るかつメッセージが表示し続けるバグがあったので直していきました。体力が減らすコードがメッセージの先にあったので、メッセージ送り元を確認してみるとループして、「体力が100になる」ことがループしていることが原因でした。どうやれば治るって聞いてみると、このループを止めたいと答えて認識できていました。ただ、どのコードを使えていいかわかっていない教わっていないそうなので、「このスプライトを止める」コードを教えてあげました。そのあと、新しいコードで作った際にも同じバグ発生していたが一人で修正できていました。 ・この先の展開を聞いてみると、アイデアが出てくるが、実際に何をやるかを自分で決めず先生に決めさせてくることにもうちょっと自主性を持ってよ。 ・新ボスをさらに作って、ボスより色も変えていい感じのアレンジができていました。 ・ゲームの終わりかたを次までに考えてくるに伝えました。', null, '盛り上がり: 他人へのツッコミが今日もよかったです'),
  ('5d299d7c-413f-53c9-a076-ec1a4bb8055a', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-07-11', '18:40:00', null, '通常 / 検定２のために演算と変数の使いこなし', '計算を使わない演算ドリルをやってもらいました。 ただし変数を初期化しないといけないなど、何回も検定でやっていることを忘れてしまっていたり、タイマーというコードをあまり使っていなかったので、今回のドリルは彼にとってよかったのかな？と思います。', '次回は２級を再度', 'タイピング: なし'),
  ('0199979b-57a5-5d42-99db-69e21e0493f3', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-11', null, null, '通常 / ビギナーズ部門中級に挑戦', 'ビギナーズ部門中級は、動画をみつつ作成していました。作成方法を覚えている部分もあったようで、かなりスムーズにプログラムできていました。集中して取り組めていたので良かったです。 アレンジもダミーのスプライトを追加したり、音声を追加したり、背景を切り替えたり、工夫していました。リストも使いたいようです。トランポリンを加えたりタイマーも使ったりしていましたが、ゲーム全体のバランスを踏まえて削除したり調整していたりしました。 細かいところもアレンジしたいようだったので、IDとパスワードを伝え、エントリーシートにも取り組んでくるようにお願いしました。', null, '時間帯: その他
盛り上がり: 自分なりに作品の方向性があるようです。集中して取り組んでいました。'),
  ('c3265b17-d3ff-5e1e-9580-0df56db5121b', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-07-11', '17:30:00', null, '通常 / コンテストの準備', 'コンテスト準備、落下してくるものをキャッチするというゲームのアレンジなのですが、 変数と演算を使いこなすことはできていました。 ただし、ゲームを終わるという概念からすると、どのタイミングでオーバーやクリアを出すことを考えていなかったようなので、こちらから提案してみました →スプライトを自分で作成するということを忘れている様子 できているというプライドもあるので、細分化しないので、こちらから聞いて答えてもらうことを繰り返ししないと、本人の頭の中がクリアにならないと思いました。', null, 'タイピング: なし'),
  ('5cfb7cce-d149-5def-a39a-26782ed35af1', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-11', '17:30:00', null, '通常 / オリジナル作品の作成', 'ゲーム内のリレーションが複雑になってきました！ 背景表示と秒数を組み合わせて進行度をコントロールしています。 「背景が表示されている間ずっと」を表現したいのですが、「ずっと」を使うことで背景が変わった後もそのスプライトが動いてしまい、うまくプログラムが働きませんでした。原因を見つけ、改善することが出来たので良かったです。 途中、おばさんの動きや鍵の動きも正しく動くように調整しました。とても集中して取り組めました。 最後に本人の気になる点として最後の女の子の挙動が、私の気になった点としてネコが移動するとき後ろから移動してしまう点 がありました。次回最終確認をしました。 エントリーシートの記入をお願いしました。', null, 'タイピング: プラチナ級！ミス率1.1%でした！
盛り上がり: 途中、もう嫌だと諦めかけてしまう場面もありましたが、少しずつうまくいき始めると、前に進みだしたら続けることができていたので良かったです。'),
  ('68d18b64-2657-5944-8ac2-b788fddb7878', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-11', '17:30:00', null, '通常 / オリジナル作品に挑戦 or ビギナー初級', 'ビギナーズに挑戦してもらいました。 本人は最初「オリジナルがいい」とのことでしたが、ビギナーズは動画を見て作るということを伝えると興味がでたみたいです。 時間をかけてひとつずつ丁寧に取り組めていたので良かったです。アレンジとして、背景やスプライトの変更を行っていました。自分が設定した魚のスプライトがとても気に入ったようです。 今日作った作品を、コンテスト作品として提出することになりました！エントリーシートに記入してくるように本人にお願いしました。', null, '盛り上がり: 給料図鑑を授業後に熱心に読んでいました。'),
  ('584c4b59-a82f-5808-8e38-6e48fed71832', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-07-11', '16:30:00', null, '通常 / コンテスト準備', 'タイムの変数と演算の使い方（＜の使い方）を再度おさらいしたのち、魚とタコスが隠れると表示されるをタイムでやろうとしました。 今までで使ったことがあるメッセージを使ってやってみたらどうかな？と提案したところ、バグなどを含めて試しながら、動作が反応するところまでできたので、ひとまずヒロトくんのコンテストはこれで提出かなと思います。 演算の使い方がやっぱりちょっとまだ難しいので、今後はこのあたりを繰り返し行えればいいなと思います。', null, 'タイピング: 初級中段、わりと覚えてきているのでミスはありつつ集中してできていたと思います。
盛り上がり: 自分なりに、やりたいことを言葉にできること、そしてそれをやりきろうとする姿勢がすばらしい！'),
  ('ff6287f3-32ea-5365-91d0-ecdcc620f411', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-07-11', '16:30:00', null, '通常 / コンテストの作品を作ろう', 'CO2の球が体力がゼロになった後、消えずに地面まで落ちてしまうバグを一緒に直していきました。原因としてはほかの変数が「もし」の条件の対象になっていて変化しませんでした。そして、CO2の体力の変数よりも明るさの変数に変えた方がスムーズに消えてよい改善が見られました。 ・亀の体力がCO２のたまの触れ続けている間、減り続けてしまうバグも直していきました。これは、追跡ゲームで「音が終わるまで鳴らす」コードを入れることで直せることを振り返って、直しました。ただ、音が短かったので、この修正法は時間を空けてあげることが肝となっていることを確認して、「何秒待つ」のコードで調節してバグは解消しました。 ・亀が左右に動くとき、スプライトが傾いて移動するのはとても面白い工夫だなと思いました。ただ、移動している間、ずっと右向きなので、左側のCO2の球を攻撃できなかったので、左に動くとき左向きになるようにしてあげるといいと提案しました。 ・U16の大会の締め切りは今週までってことも知らせておきました。進捗としては8割ぐらい終わっているといっていました。', null, '盛り上がり: 授業が終わったあと長く集中してやっていました。'),
  ('2a5fd058-abfa-5506-abfd-778ea9e69ebd', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-07-08', '17:30:00', null, '通常 / コンテスト作品の作成', 'やりたいことはわかっていても、一人にすると何から手をつけてよいのかわからないようでした。 忍耐力の残りによって建てる家が変わるようにしたいけれど、何から始めてよいのかわからずにいたので、条件を紙に書きださせたら自分で条件分岐のコードを書くことができていました。 条件式をすべて「=」または「=」で書いていたので、あてはまる数が多い時は「>」かつ「<」を使うことを提案したところ、式がシンプルになったと喜んでいました。 クリアまたはゲームオーバーのときに、動いている書類を止めたい、家が決まった時にプレイヤーにコメントを話させて、そのコメントが5秒経ったらきちんと消えるようにしたいなど、ゲームの仕様にもこだわって完成させようとしていました。「すべて止める」「スプライトの他のスクリプトを止める」「このスクリプトを止める」の使い分けと使うタイミングを一緒に考えて、家購入イベントを完成させることができました！', null, '盛り上がり: ゴールが見えてきたのが嬉しそうでした！ 一人にしておくと、「もう無理だ―！」「全然進みません！」となりがちでしたが、こまめに声をかけると落ち着いて、自分で試行錯誤して「ここがわからない」とピンポイントで質問ができるようになりました！'),
  ('6adb1ba5-bd12-5e6a-80db-58d82427eb4c', 'b2246586-4496-52f9-a825-be2488a00a31', null, null, '2022-07-07', '17:30:00', null, '通常 / 話を完成させよう', '前回作っていた話の続きを作りました。背景が変わるごとにスプライトの動きもそれぞれ動かすコードが作れていました。 現れるタイミングがづれていたり、背景が切り替わっていなかったりするバグがみつけると、ほとんどの場合、まさき君自身がどこが違うか判断して修正できる機会が増えてよかったです。徐々に時間をかけてレベルの高いものができていると思う。秒数で猫の動きをコントロールしたが、自分でもプログラム上でも猫の混乱していたので、背景に合わせて猫の動きをコントロールすることを提案した。', null, '盛り上がり: 1話を完成させてみんなに発表したい欲があふれていてよかったです。55分かけて一話分を作り切り、達成感があったようです。このあとの続編も、現段階では10話分くらいを予定しているそうです。'),
  ('52fc72fb-672f-56cb-8f56-5e820a86ef87', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-07', '17:30:00', null, '通常 / コンテスト作品を進める・スケジュールを確認', '家でかなり取り組んできた印象を受けました。背景にあったスプライトを置いてゲーム内容を示しているのが素晴らしかったです。 音がうまく制御できない事件がありました。複雑に考えすぎていたようです。話しつつ、今あるプログラムを整理して改善しました。論理構造と「もし~でなければ～」のブロックの使い方の関係について深く話しました。少し理解してくれたようです。最終的なプログラムは自分で発案できていたので良かったです。 なんか違うなと思ったらすぐ捨てる癖も少しは落ち着いたと思います。', 'ゲームの説明画面を作成したいです。', 'タイピング: 集中して取り組めていました。お得かそうでないかが目に見えてとても面白いそうです。
盛り上がり: 他の人の作品を見たあと、ポジティブな意見を残してくれました！'),
  ('d6013082-dc5d-5cc9-bd02-c267cf50f6f4', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-07', '17:30:00', null, '通常 / コンテスト作品の作成', 'オープニングの背景やセリフ、音楽などを作ってきていました。リストも20個入力してありました。 これまでの構想から変えて、実際に画面のマス目を出してその上を動くようにしたいとのことで、マス目をスプライトで作成することになりました。 今後の作りやすさを考え、マス目のスプライトの名前の統一やプレイヤーの現在地用の変数作成など、次回作成のための下準備をしました。', 'クリア画面など、自分で作成でき、かつ時間がかかりそうなものは次回までに作成してくる約束をしました。 次回、実際にマス目を移動してそこのイベントに対応するように作り込む予定です。', '盛り上がり: アイディアの切り替えが早く、より効率的に作成するために自分で考えて工夫しようとする姿勢が見られました！'),
  ('dd00a8f2-14ab-591e-b89e-0bc9e2ad0f9d', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-07', '16:30:00', null, '通常 / スケジュールの話。 写真いれるのかな？（→いれないことになりました） プログラムの整理（いらないブロックとったほうがいいかも） 終わりの画面の作成。', 'プログラムの整理は、前回の振り返りをしつつしてくれました。スタートボタンでも、スペースキーでもプログラムが始まるように工夫してくれました。 終わりの画面作成のリクエストをしました。 変数の消去、出現にまで気を配れていて良かったです。 扉がしまっているにも関わらず、何事もなく扉に突進していく状況を改善しました。ひいろくん一人で色や座標による制御を考えてくれましたが、うまくいかなかったので一緒にアイデアを出しました。扉の開閉状況を変数でコントロールする・座標と色でコントロールすることを提案しました。最終的には、乗客の挙動をコントロールするのではなく、窓が割れた音を設定する方にシフトしていて、柔軟な発想がありました。すごい！ 途中プログラムが始まらない事故が起きましたが、「全てをとめる」が原因であることを自分で発見できていました。', '出現するスプライトの重なり具合（最背面・最前面など）がプログラムされていないので、整理したいです。', 'タイピング: ミス9%、はやさ2.56タイプ/秒でした。 ホームポジションを意識して取り組めていたので良かったです。
盛り上がり: 乗客が扉に突進してしまう状況の矛盾ない改善として、場にあった音を出すという解決方法が出てきてとても素晴らしかったです。本人も満足そうでした。'),
  ('ad292284-7928-5959-9589-e85344563060', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-07', '17:30:00', null, '通常 / スケジュールの話をする。 ビギナーズ部門初級に挑戦。', 'オリジナル部門とビギナーズ部門の両方があることを伝えました。 とりあえずビギナーズ部門に挑戦してみるとのことでした。 スプライトをオリジナルのものに変えながらプログラムしていました。 動画を見ながら作っていましたが、よどみなく進めていました。 アレンジを加える際、「すべてを止める」のブロックの配置場所に苦戦していましたが、自分で考えて最終的に決めることができていたので良かったです。アレンジの仕方もとても良かったです。 アレンジで、食べ物を食べるときに、セリフを挟むことはとてもよかったです。セリフをしゃべっているとき、止まってしまうのも悩んでいたが、スムーズに動く程度に時間調整できていました。 ハリネズミが何個か食べてただゲームが終わるだけでなく、「モー無理」とセリフを挟んで終わるアレンジはほかに見なくてよかった', 'ビギナーズ中級をやってみたいです。', 'タイピング: 授業後にやってもらったにもかかわらず、集中して取り組めていたのでよかったです。
盛り上がり: 自分が作ったプログラムの可愛さが審査員の人に伝わるのか、少し心配していました。'),
  ('b599dead-a44e-5a59-a156-92589f4ebb94', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-07', '16:30:00', null, '通常 / コンテスト作品の決定と作成', 'ゲームの仕様を家で考えてきたそうなので、あらためて紙に書き出してから作成をしました。 ピンポンゲームで使用した「～まで待つ」のブロックの復習をしました。すべてをとめるはよく覚えていました。 座標についてはよく覚えていて、理解もかんぺきでした！ ゲームのアイディアがどんどん出てくるため、締め切りを見据えて折り合いをつけるのが少し残念そうでした。', '釣った数の判定が難しいので、ゲームバランスの見直しと、魚が徐々に増えていく仕様を完成させていく予定です。', 'タイピング: こだまの森をクリアしました！以前は全ステージBだったのが、S～Aをとれるようになりました。
盛り上がり: 細分化の紙を見ながらゲームの仕様を語ってもらいましたが、スプライトごとにきちんと整理されていてわかりやすく説明ができていました。文字を書くのが早くなれば、自分で細分化ができると思います。'),
  ('eda923b7-a94f-5e80-bb93-0329792147cd', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-05', '17:30:00', null, '通常 / コンテスト作品の作成', 'オリジナル作品のアイディアを考えてきたということで、一緒に作成していきました。 バットで敵を打って地球を守るゲームを作成しました。 バットにあたる判定を色でしているところがうまくいかないことがあるので、次回見直し予定です。', 'ゲームバランスをみながら調整していく予定です。', 'タイピング: 相変わらず安定したスコアを出しています。
盛り上がり: ほぼ思い通りのゲームが作成できたようで、とても満足そうでした！'),
  ('6a3f53fc-5871-58ce-807c-08c156345ec3', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-05', '16:30:00', null, '通常 / オリジナル作品の作成（ゲーム終了画面）', '①おわりのときにコップの動作をとめ、支柱・アサガオ・コップを隠す ②おわりの画面の作成・出現 ③はじめの画面の作成 の3つをしました。 メッセージの話は初めてではなかったようですが、忘れてしまったとのことだったのでもう一度説明しました。前半に伝えた「すべてを止める」ブロックも使ってコップの動作を制御してくれました。 ひとつひとつの操作が丁寧でした。 背景のグラデーションのつけ方を伝えると実際に使っておわりの画面を作ってくれました。ゲーム終了のときにスプライトを非表示にしてしまったので、スタートのときのスプライトの再表示をうまくプログラムしてくれました。 はじめの画面の作成は作成で終わってしまったので、来週は実際にプログラムに反映させたいです。', 'ゲームスタート画面の表示をプログラムしたいです。', 'タイピング: Sで100点でした。タイピングのときは必ずホームポジションを意識して入力できていました。
盛り上がり: ゲームクリア・スタートの画面の色合いにかなり気を配っていました！'),
  ('45684bef-7b67-5906-b8aa-26a5c3cc7fc6', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-07-05', '16:30:00', null, '通常 / コンテスト作品初級コース', '・中級コースのねずみとりが完成していないので最後まで作りたいとのこと、すべてのねずみをつかまえたら（得点が14になったら）クリアのスプライトを出すコードを付け加えました。 ・「～まで待つ」ブロックのヒントを出したら、変数の演算式を使うことを思い出すことができていました。 ・初級コースを１から作成したところ、こちらの方をコンテストに出したいとのことで、じっくりアレンジをしました。 ・魚を増やすアレンジを希望したため、複数の魚をどう扱うか、魚の数のバランスなども実際に作成してはプレイして考えることを繰り返し、最終的には魚二匹を別のキーで動かすアレンジに行きつきました。そこまでのトライアンドエラーが、ようくんにとって良い経験になりました！', 'ゲームのタイトル画面と説明を追加して、提出を目指します！', 'タイピング: 今日はあまり気乗りがしなかったようで、1度だけやって終了してました。
盛り上がり: ようくんが納得のいくアレンジができたようで、お母さんにも披露してとても嬉しそうでした！'),
  ('438ce2cf-e8a9-5362-88e8-be378e725424', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-05', '17:30:00', null, '通常 / コンテスト作品を進める', 'コンテストにジャンプゲームを出品する旨を伝えると、あるくんのスタミナを設定してくれました。 つぎに、日本刀を出す敵キャラを作ってほしいとリクエストすると、台に乗ったハイエナを設置してくれました。 また、ゲームクリアの条件としてタイマーを設定することになりました。途中「1秒待つ」をプログラムし忘れて残り時間が0になってしまう事故があったものの、間違いを口頭で指摘すると自分で気づいて修正できていたので良かったです。 その後、ゲームオーバー・クリアの画面とゲームスタートの画面を作りました。ゲームプレイ中の音のコントロールに苦戦しましたが、「～まで繰り返す」を使って問題を解決することができました。 ゲームスタートのスプライトの表示にメッセージを使うことを提案しましたが、秒数でコントロールしてくれました。ハイエナがスタート直後に登場していないので、プログラム内容を落ち着いて見直す必要がありそうです。', null, '盛り上がり: 本人の中でかなり達成感があったようです。満足そうでした。集中が途切れることなく60分同じ作品に取り組めていました。'),
  ('2fa792d4-0006-5a2e-8fb1-0b26f07c46bd', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-05', '17:30:00', null, '通常 / コンテストのビギナー初級に挑戦する。', 'ビギナーズ部門初級に挑戦しました。 紙を見てプログラムするよりも、動画をみて取り組む方がいいとのことだったので、動画をみつつ取り組んでもらいました。 アレンジ前の作品も正確にプログラミングできていました。アレンジとして背景・音を一番に変えてくれました。ブロックも丁寧に使えていました。オリジナルのアイデアがたくさん反映されていました。 初級はかなり簡単そうに見えたので、次回中級に挑戦できそうです。', 'ビギナー中級', 'タイピング: かなり長かったようですが、授業が始まる前から集中して取り組めていました。
盛り上がり: 授業後に集中してタイピングに再び挑戦していました。'),
  ('f7d064b2-58df-5a10-863b-0880df6a6354', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-07-04', '17:30:00', null, '通常 / ビギナーの中級作品のアレンジをしよう', '・家で一度を作っていたそうなので、まずは試料を見て中級のネズミ捕りを作りました。 ・アレンジでは、ネズミを4匹捕まえた後、オヤブンのネズミが出てきて、倒して流れを作っていました。4匹のネズミを捕まえた後にオヤブンのネズミの体力を出したいの要望から「変数の表示」のコードを使うように提案して、まだ使っていないコードの発見につながったと思います。 ・猫からパンチを出したときにオヤブンの体力が減らないバグがあったが、オヤブンネズミがパンチに触れたときからパンチがオヤブンネズミに触れた時に変えた直せませした。ただ、ボスキャラねずみのHPが初期値になってしまうバグが発生したので次回修正予定です。 ・・ビギナーズ部門の中級で、おもしろいアレンジをしているので、このまま作成を進めて提出でOKだと思います。（大原）', null, 'タイピング: 特典は下がったが、高い正答率でした。
盛り上がり: 今日も周りへのつこっみがよかったです'),
  ('0dd2b44f-4718-5dca-b689-0a0037cfe394', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-04', '16:30:00', null, '振替え / コンテストの作品を進める', '太陽のコスチュームを使い、モグラに弾があたったときの動きをプログラムしていました。見せるための時間をいれるのを忘れてしまっていました。モグラのスプライトにアレンジを加え、面白くしていました。 畑のあらされ度が変わっていないことが判明しました。本人は音楽をいれる方に気が傾いていました。 もぐらの種類を増やしたのでラスボスの登場はなくてもいいのではないかと言っていました。', 'ゲーム説明画面、得点が開始時-1になっちゃう現象、畑の荒らされ度の調整に取り組みたいです。', 'タイピング: ミスタイプ率もすくなくとても集中して取り組めていました。 1.88/秒でした。
盛り上がり: 他の人の作品も気になる様子でした！'),
  ('cfdc8689-9caf-5c11-8769-0b60a15a4625', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-04', null, null, '通常 / 検定の復習。', '検定復習をしました。前回時間を使い切ったということでしたが、思うところがあったみたいなので、まずは自分で見直してすこし手直しをしてもらいました。正解と見比べたところ、うまくいかなかった点は1箇所のみで、制御と演算ブロックの使い方をすこし間違えていました。一緒に復習しました。 アレンジにも挑戦しました。当たると移動量の減るスプライトを作ってくれました。メッセージを他のものと併用していたので、新しく作っても良いことを伝えました。細部まで気を配れるようになるともっと上達すると思います。 コンテストのアレンジ部門に参加する予定ですが、一週間考えてイチから作る方に変わるかもしれないようです。', 'コンテストの準備', '時間帯: その他
タイピング: いやいやながら取り組むことができました。
盛り上がり: とても集中して取り組めていました。こちらの話をしっかり聞いてくれてとても良かったです。'),
  ('11b43e2a-99d4-5674-ab77-8a4eda3256e5', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-04', '17:30:00', null, '通常 / コンテスト作品を進める', '前回の続きをしました。矢印キーを押すと鬼の体力が減るプログラムを作成しました。メッセージでゲームの進行状況を管理することになりました。本人の希望によると、一定時間無敵になるプログラムも作りたいようです。やりたいことはあるけれど、その一貫性がなく、こちらが心配になる場面もありますが、本人は終止満足そうでした。 メッセージや変数の作り方など、忘れてしまっていることがいくつかありました。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 楽しそうに取り組めていました。途中投げ出すことがなく、良かったです。'),
  ('18243b2c-5bb5-5cde-ae93-dbb77cf74bc3', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-04', '17:30:00', null, '通常 / コンテスト作品を進める', '後ろ部分→中部分→前部分の順でプログラミングしてくれました。ゲームスタートを旗ではなくメッセージを使ってコントロールしていました。背景やスプライトの動きにもこだわりがつまっていてとても良かったです。 スプライトが話す内容をgoogle keepに書いてからうつしました。世界観が明確に感じられました。どうやらほとんどプログラミングが終わったようです。次回はゲーム説明の画面を作ってほしいことを伝えました。 たくさんのメッセージが入り組んでいるプログラムですが、イチから自分で構成を把握できていたので素晴らしいです。', null, 'タイピング: プラチナ級でした。とても早く姿勢よく取り組めていました。
盛り上がり: とても集中して取り組めていました。楽しそうでした。'),
  ('477d7a48-cd26-52bb-ad73-7fa8f959751a', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-07-04', '16:30:00', null, '通常 / コンテスト作品を進める', 'コンテスト用の作品の続きをしました。ゲームで「ボールがきれいに点滅しない」ことに悩んでいました。明るさでコントロールしていたのですが、コスチュームを変えた方がうまくいくと思ったので、こちらから提案しました。さらに、ボールの動きもカクカクしていたのが気になっていたので、「動きの時間をかける」と「動いたあとに時間をかける」のとでは、スプライトの見え方が変わってしまうという話をしました。自分なりに試行錯誤して作ってくれました。 ゲームの仕様で、ボールに弾がぶつかるとランダムに消えるボールと消えないボールを作りたいようです。時間がなかったので、ヒントとして「乱数と変数をうまく組み合わせる」ということを伝えました。 背景の住宅街を、余裕があればもう少しポップな感じにしたいようです。', null, '盛り上がり: ボールの動き、見た目にとてもこだわっていて、うまくいったときは満足そうでした！'),
  ('bad8412a-429b-5800-ba78-aede4bb7d0bb', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-07-04', '17:30:00', null, '通常 / 追跡ゲームの作成', '・作成中のクリオネゲームを、環境問題ゲームにすることにして、オリジナル部門に出すことにしました。 ・前に作っていた雷を乱数をつけて、広い版から落ちるようにしました。その際、一か所から落ちていた時のコードを作り直す必要があったので、「何秒でxy座標に行く」からy座標を何ずつ増やすに変更しました。 ・まみさんとクリオネに体力をつけたり、妨害「雷、爆弾」、回復アイテムを作りました。つを食べてHPを回復して、牛乳パックやサングラスなどのゴミを拾って得点を増やすゲームになりました。 ・妨害の雷や爆弾が多すぎてHPがもたないので、自動回復機能をつけたいそうです。 ・ゲームの説明画面が必要なこと、バックグラウンドとなるストーリーを考えてほしいと話をしてあります。 ・人前で話すのは嫌だそうですが、とりあえずゲームを出すということは承知しています', null, 'タイピング: スコアを少し伸ばせました'),
  ('825dbee4-315d-59fb-ab9d-4a08e7a51a7d', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-07-04', '16:30:00', null, '通常 / ビギナー部門の初級の作品を作り、アレンジしよう', '・ビギナー部門の初級の作品を作りました。動画を見ながら基本の部分を作りましたが、ブロックを探すのが少し大変でした。大きさを変化させるブロックが％で変化するのではなく、数値変化のものになったりしていたが、あとから自分で気づけました。 ・アレンジ部分では、制限時間をつけてあげることをしていました。だが、少し悩んでいたので、OOまで繰り返すと不等号を使うよって言ったところ、なんとなく前にやったような気がするって言っていました。このコードは何度か使っていけば、身についていくと思います。 ・制限時間の変数を変化させるコードを書くとき、一つのスプライトで書けば、全体で反映されるが、すべてのスプライトに同じコードを描く必要があると勘違いしており、そこは訂正して上がました。 ・制限時間が0となった時、スプライトが全部消えるようにしたかったが、消えないとなっっていたが、不等号の向きが違って動いていませんでした。由紀さんがフォローに入ってくれたため、ゲーム終了画面まで時間をかけてできました。 ・', '中級もやってもいいと思う。', null),
  ('b9250990-8ddd-59ee-915f-9d22be369875', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-07-04', '16:30:00', null, '振替え / コンテストの初級のゲームを作り、アレンジしよう', 'ビギナーの初級編の作品を動画を見ながら、作っていきました。特に滞ることなく、スムーズに作っていくことができました。 アレンジでは、タコスを食べるごとに魚の色が変わっていくことを、コスチュームを新たに書いて、「コスチュームを切り替わる」ようにして作っていました。 そして、大きくなりすぎた魚を大きさが100になったら20に戻したいと考えていました。どうコードを作るか悩んでいたので一緒に作りました。もしと等号のコードを使うよって一緒に作ったら喜んでくれました。', '初級のアレンジはスムーズにできたので、中級のものもやってもいいかも。', 'タイピング: 作品作り優先のため無し
盛り上がり: 食べるごとにコスチュームで色を変えているのがおもしろかったです。'),
  ('05f801d1-cca2-577c-9c4f-8e0560463601', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-07', '16:30:00', null, '通常 / 基本操作コース_04 追跡ゲーム アレンジ または 基本操作コース_06 物語を作ろう', '前回作成のゲームを見直してから、アルスパークの「物語を作ろう」サンプルを見せました。 「〇秒待つ」とメッセージの使い分けをして、スムーズに進む物語が作成できました。 「旗が押されたとき」「背景が変わった時」「メッセージを受け取った時」の使い分けは理解できていたようでした。 あと数回使ってみて、定着させたいと考えています。 座標を使って滑るように動かすところは、以前も楽しんで取り組んでいたせいか、よく覚えていました。 自分の声を録音して会話にしたところは、速さを調整して声の高さを変えたりして、キャラクターに合うように工夫できていました。', '吸収が早く、習ったこともよく覚えているようなので、このままピンポンゲームに進めて乱数や変数を学習しても大丈夫かとは思いますが、ファイルの空欄がうまっていくのをとても喜ぶ子なので、少しドリルに取り組んでみても良いかもしれません。', '盛り上がり: 前回の追跡ゲームのアレンジはもう完成しているとのことだったので、「新しいところに進もう」と声をかけたところ、ニコニコしてファイルを開いて「ここまでできたの？」と確認していました！ イベントの使い分けや座標の理解がスムーズだったため、声の録音を少し増やしたりしてちょうど一単元終わった形になりました。 作品をお父さんに披露する時、いつも嬉しそうにしています！'),
  ('486c5930-5008-5946-9847-5b4d6be4318e', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-31', '16:30:00', null, '通常 / 基本操作コース_03 追跡ゲーム', 'ゲームで遊んだ後、どんなゲームだったかを説明することができていました。 左矢印キーが押されたときの説明をしたら、残りの右上下の動きは、y座標との使い分け、プラスとマイナスの使い分けも含め、自力で解決できていました！ ブロックに対しての勘が良いみたいです。変数を作成したら、これとこれを使う、と、自分から「スコアを0にする」「スコアを1ずつ変える」ブロックを持ってきていました。コードのどこに挿入するかも、自分で考えて判断できていました。 授業後、完成した作品をお父さんと熱心にアレンジしていました。', null, '盛り上がり: 基本的にはカードの裏を見ず、こちらの発問から自分で考えて作成していくスタイルができています。適当にブロックを持ってくるのではなく、よく考えて慎重に組み立てているので、作成した範囲の理解はほぼできていると思われます！ 単元の内容が終わってファイルに記入しているのを、いつも嬉しそうに見てくれます！「クリア」していくことがとても楽しそうです。
備考: お迎えを待つ間、「こわいゲームをやってみたい」というので 青鬼 修学旅行https://scratch.mit.edu/projects/627083727/editor/ で遊んでみました。結構楽しんでいたようです。'),
  ('6c3f68e3-45cf-5703-a8ee-1f8eb0b93a1d', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-24', '16:30:00', null, '通常 / 世界を想像しよう！05 から', '復習を兼ねて、前回作成の「上下に動く日本刀」を左右にも動くようにしてもらうところから始めました。 上下左右の動きを自分でできるようになったのが楽しかったようで、「こういうふうに動かしてみたい」という発言が一気に増えました。 コスチュームは使用するものとしないものをよく考えて切り替えができていました。 「1秒で座標を変える」は覚えていたようで、画面の中で動かしたい場所を指さしながら自力で設定できていました。 音を加えるところは、ちょうどようくんが直前にやっていたため、ちょっと照れながらも楽しそうに取り組んでいました。', '次回は追跡ゲームになります。次はいよいよゲームを作るよ！という予告を嬉しそうに聞いてくれました。', '盛り上がり: 「世界を想像しよう」のコースが終わったので表にスタンプを押したところ、とても嬉しそうに見ていました！ 座標はお父さんと家で復習していたそうで、よく覚えていました。xとyで迷うことはありますが、「こういうときは座標を使う」という点は理解できているようです。 「ここをこうしたい」という意思表示が増えてきました！
備考: お父さんから、家ではどんな勉強をしておけばよいかとのご質問がありました。 まだ予習復習するほどのところもないので、とりあえず、Scratchで好きなゲームを探してみてほしいとお伝えしてあります。'),
  ('bcb492d9-727f-5e49-a431-3d494a2fb976', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '5cfbd637-17cd-5e1f-9521-1dae0dcfd527', '2022-05-17', '16:30:00', null, '通常 / 世界を想像しよう！ できることを増やす！楽しむ！焦らない。', '昨日の作品に本人のリクエストで音を付け足しました。時間をかけて「走る馬の音」を選んでいました！文字の動きとマッチしていたのでとても良かったです。本人も満足そうでした。面白い音を見つけるとニヤッとしてました。 世界を想像01：スプライトにおしゃべりさせることができることを伝えました。「〇秒」があるのとないのとでスプライトの動きに差があることを確認できたので良かったです。 世界を想像02：「どこかへ行く」と「スペースキーをおしたとき」を学習しました！スペースキーはもう知っていたようです！「どこかへ行く」もなんとなく理解できたようです。「ずっと」をいれて試したりもしました！ 世界を想像03：矢印キーとx座標の話をしました！スペースキーで制御する方法を覚えていてくれたので、スムーズに進みました。x座標の概念はかなり理解するのが難しそうでしたが、「x座標を変えたら左右に動く」という話はしっかりと伝えました。プラスマイナスはまだ分からないようです。値を変えて試していました！ 世界を想像04：y座標の話をしました！すこし難しそうに聞いていました！繰り返し説明する必要はありそうです。', null, '盛り上がり: おうちではタブレットでゲームをするそうです！いろんなのをプレイすると言っていました！
備考: Scratchの「青鬼 修学旅行」が好きみたいです。 https://scratch.mit.edu/projects/627083727/editor/'),
  ('41449c99-b490-535d-82b1-f3bdbef914d8', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-05-16', '16:30:00', null, '振替え / 先週の振替 →その前がGW前の４/26、間がややあいた', '間があいたため、前回やった事はほぼ全て忘れていたようです( ;∀;) なので、「02 名前を動かそう」を最初からやりました。 色を変える、回転させる、大きさを変えるなど、基本の動きはマスターしたので「SHOU」の４文字を自由に動かそう！というお題にチャレンジしました。 んがんが、何をしていいかアイデアが全くわかず、、、、私の方で具体的な動きのアイデアを出しました。 前回は、自分でオリジナルな動きを作っていたようなので、今日は気持ちが乗らなかったのか。 私の教え方が固すぎたのか( ;∀;) 最後に、「〇回くりかえす」のコードに「ずっと」を加えるアレンジと 「〇秒でX座標、Y座標」を動かすコードを「〇秒でどこかの場所に行く」に変えて動きに変化が出たのは楽しかったようです。 ややお疲れ気味だったのか？何度もあくびをしていたので。小学１年生の５月だからかな～。 また、もともと大人しい子っぽい。', '次回は、他の基本の動きをやる。 アレンジ、創造力が発揮できるといいな。', '盛り上がり: 動きに変化がある時、リズムが急に変わったり、反対に動いた時に一瞬目がキラっとなりました。
備考: Scratchの「青鬼 修学旅行」が好きみたいです。 https://scratch.mit.edu/projects/627083727/editor/'),
  ('ecfe8aa0-e2b1-5d1f-a09c-ce0e0f03bf80', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-26', '16:30:00', null, '通常 / 基本操作コース_02 名前を動かそう', '新1年生のため、アルファベットではなく好きなスプライトを選んでもらって進めました。ゾンビの色や大きさが変わるのを面白がっていました。（本当は「鬼」を使いたかったとのこと…） 角度については分度器と実際の回転の様子を見比べながら説明しました。数値が大きいとたくさん回る、180度だと半回転するということは理解できたようでした。 「躍らせよう」は流れの都合上、今日は飛ばしました。 指定した座標に動くところが楽しかったようで、細かく座標を設定して蝙蝠が飛ぶ様子を表現していました。座標の細かい説明はまだしていませんが、中心が0ということ、スプライトの現在位置によってブロックの数値が変わっていることは納得していました。', 'こうもりの動きをとても楽しんで作成していて、この後はこういう話の流れにしたい、という希望もしっかりとあったので、次回はこのまま「基本操作コース03 世界を想像しよう」の内容にも触れながら、アルファベットの代わりに好きなスプライトを使った「名前を動かそう」のオリジナル作品作成でも良いかと思われます。', 'タイピング: 1年生のため飛ばしましたが、授業終了後に興味を示して、ココアタイピングに挑戦しました。「J」と「F」に人差し指を置くことを教えたところ、上手に打てていました！
盛り上がり: 体験の時と同様、初めはかなり緊張が見られましたが、慣れてくるにつれて感想や意見を話してくれたり、笑顔が増えてきたりと心を開いてくれた様子が見られました。 どちらかというと慎重派で、一つ課題を与えると該当のブロックを指さしたままずっと待っていて、こちらのGOを聞いてから実行する傾向が見られました。 体験のときは怖がりなのかと思われましたが、怖いのは「ゲームで負けそうになってドキドキすること」のようで、キャラクターとしてはゾンビやゆうれい、鬼などが好きなようでした。'),
  ('16f7c5dc-4d87-54b4-9718-3370fa6b363c', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-07', '17:30:00', null, '通常 / 基本操作コース07 ピンポンゲーム ドリル レベル１ 問題6～', '授業開始時は、もっとゲームがしたくて切り替えに5分ほどかかりましたが、「今日はこれを作ってほしい」とピンポンゲームをプレイさせたところ、一気にやる気モードになりました。 スプライトを準備した後、いきなり「赤いラインに触れたらゲームオーバーだよね」と「もし～なら」ブロックを持ってきたので、まずはボールが動かないとその判定ができないのでは？と問題提起し、どういう順番で作成していくかを考えてもらいました。 ゲームを全体から見すぎた上で、自分が気になったところから作成しようとする傾向があるかもしれません。次の単元では細分化をしたほうが良いかと思われます。 跳ね返る動きのところでは、分度器を見て角度を考えました。数値にとても興味を示し、「170から190」を「160から190」に変えたらどうなるか、など、微妙に数値を変えて色々と試していました。 スコアの変数はイメージしやすかったようで、すぐに理解できていました。 ゲームオーバーとレベルアップのスプライトを作成していました。いずれもメッセージ（メッセージ名はそのままではなくわかりやすく変更することを勧めたら、おふざけな名前にしていましたが…）を送ってスプライトを表示するようにしていました。 「～まで待つ」ブロックを使うよう指示したところ、「もし～なら」より簡単！と、いたく感心していました。', null, 'タイピング: 今日はプログラムの気分…とのことで、飛ばしました。
盛り上がり: これまで他の人が作っていたのを見たことがあったのと、ゲーム性が強い教材だったせいか、今日はスプライトでふざけることはなく、とても集中して取り組んでいました。乱数や変数の説明もきちんと聞いてくれました。 ある程度プログラミング的要素？が多い方がまじめに取り組んでくれるのかもしれません。余裕があるとおふざけに走るので…。 今日も、演算ブロックを使うときが一番楽しそうでした。'),
  ('8ade1c5b-6b21-503a-8ff8-66148d626fef', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-31', '17:30:00', null, '通常 / 基本操作コース06 物語を作ろう_06滑るように動かそう～ ドリルレベル２、ピンポンゲーム', '前回の復習をするために作品を開いたところ、まだ話が続いているとのことなので、続きを作成していきました。 先に動き出すフリエの日本刀がディラックに当たっとときと、よけられた時の2パターンの物語を想定して、それぞれの結末を作成しました。 メッセージのタイミングを試行錯誤して、ストーリーがうまく流れるように気を配っていました。タイミングがうまくいったときは興奮して見せてくれました。 スプライトの滑るような動きとジャンプの動きを通して、座標の再確認ができました。xとyの使い分けにもだいぶ慣れたようです。 ドリル レベル1 ジグザグに動かそう 上のオリジナル作品完成後、残り時間15分だったため、1つだけドリルをしたら遊んで良いという条件でドリルに向かわせました。レベル2の「円」というところでおじけづいたようで、レベル1からやりたいとの希望により、「ジグザグに動かそう」だけ挑戦しました。 ドリルの絵を見てパッと答えたようで、「緑の旗が押されたとき」「1秒待つ」が抜けた状態で「できた」と見せてきました。 問題文を音読させたら抜けに気付いてすぐに直すことはできましたが、文章をしっかり読む練習を少しずつさせていきたいところです。', null, 'タイピング: 毎回1時間以上遊んだあとのタイピングなので、切り替えに少し時間がかかりますが、いざ取り組むと集中してそれなりの結果を出せています。うでだめしで上位30%台に入るのが嬉しそうでした。
盛り上がり: タイピング、プログラミングともに、気分のムラはありますが、ノッた時の集中力、発想力はおもしろいです。 自分のこだわりを形にしたいときは、こちらの説明もしっかり聞き、自分でもよくコードを読んでバグを探し、修正することができています。この姿勢が少しずつ長続きするようになると、一気にできることが増えるのではないかと…。'),
  ('ef15d698-eb18-544a-83c8-4accb68fa6f7', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-24', '17:30:00', null, '通常 / 基本操作コース06 物語を作ろう_06滑るように動かそう～', '今日は授業前に見つけたサッカーゲームが気になって仕方なく、授業に入るのに少し時間がかかりました。 単元の内容を踏まえながら、オリジナル要素を入れて作成し、スプライトに触れたことによる分岐とメッセージの活用、スプライトの向きを学習しました。', null, 'タイピング: 「タイピングはもうできるからいいよ」とのことだったので、うでだめしにチャレンジしてもらいました。 シルバー級（ミス2.07%、打鍵1.75秒）がとれていたので称賛し、毎週チャレンジしてゴールド級を目標にしてみました。
盛り上がり: 相変わらずストーリーやセリフは物騒ではありますが、キャラクターを動かすことによってストーリーが分岐できたのが楽しかったようで、完成したときは満足そうでした。
備考: いつかサッカーゲームを作ってみたいとのこと。 サッカー / Soccerhttps://scratch.mit.edu/projects/230073978/'),
  ('344997c3-66ae-58d1-8093-ea830c2b9edd', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-17', '17:30:00', null, '通常 / 基本操作コース06 物語を作ろう', '前回遊んでいたキャットランゲームで遊びたがりましたが、コンテストの話をしたら、新しいことを覚えて作品作りに活かすという目標に納得し、進んで新単元に取り組んでくれました。 適当なキーでコードを動かそうとする癖がありましたが、コンテストに備えてわかりやすいプログラミングを意識し、イベントのブロックは必要に応じて使い分けることを提案したら、自分で考えてくれるようになりました。 色の効果の回数など、自分で試しながら見た目のインパクトを考えていました。 録音した声の活用を熱心に繰り返していました。', null, 'タイピング: 99.9% 相変わらず集中力もあり、よくできています。
盛り上がり: コンテストの話をしたら、「パソコンほしい！」「がんばる！」とのことでした。 セリフをいろいろなキャラクターになりきって録音して、セリフのイメージに合わせて加工していました。後半は遊びも入っていましたが、本人のイマジネーションを膨らませる効果はかなりあったと思われます。
備考: もっとむずいアスレチック remix https://scratch.mit.edu/projects/691786984/で遊んでいました。'),
  ('567dac53-ceec-5aa1-9470-cbc8fb1198fd', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-10', '17:30:00', null, '通常 / 基本操作コース04 追跡ゲーム レベルアップ！～', '「～まで待つ」と演算式の組み合わせはよく理解できていたようでした。 「背景が～になったとき」のところで、「もし～なら」のブロックを探しがちで、「こちらの方が簡単では」と勧めると、「こんな簡単なブロックでいいんだ！」という感じでした。 レベルアップをしたらスプライトの大きさを変える、など、いろいろと試しては楽しそうに遊んでいました。ただ、残り15分でゲームアレンジとして作らせようとすると、「今日は他のゲームをやりたい」とのことで、【Prg】上級 走ってゴールを目指せ！キャットランゲームを作ろう！https://app.arspark.jp/contents/2928で遊び始めました。 先週から上記ゲームがお気に入りでかなり遊んでいたので、簡単なアレンジを勧めてみました。あの長いコードを一生懸命読んで、効果音やセリフの内容やタイミングを変えて、とても楽しそうに盛り上がっていました。', null, 'タイピング: 正誤率100%！ 学校で桃太郎タイピングは全部クリアしたそうです。
盛り上がり: 小学生男子！という感じで、爆発ネタやちょっとした下ネタ？系のセリフや音に大喜びでした。 「ゲームのアレンジ」というと難しそうに感じたようですが、「セリフとか音も変えられる」くらいの提案だとのってきてくれて、自力でコードの該当箇所を見つけて書きかえていました！ ファイルのコース内容表は気にはなっているようで、「どこまで進んだ？」と自分でチェックしていました。
備考: 先週に引き続き、ぎりぎりまで【Prg】上級 走ってゴールを目指せ！キャットランゲームを作ろう！をいじっていました。'),
  ('8f98fbc5-416f-5484-8cf3-1d634ebedcb1', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-26', '17:30:00', null, '通常 / 基本操作コース04 追跡ゲーム', '追跡ゲームの見本で遊んでもらい、細分化に挑戦しましたが、書くことはあまり好きそうではなく、スプライト1つ分のみ取り組みました。 全体を見て細分化するというよりも、自分が気になったところ（スプライトに触れている間、スコアが上がり続けてしまうところ）にとことんこだわってしまい、そこだけ10回ほどプレイしては「おかしい」と首を傾げていて、なかなか割り切って先に進むことができないようでした。 座標については、助言があればなんとなくわかるといった感じで、なんとなく上下左右の動きを作成することはできますが、数値を変えた時にマイナスが抜けていても自分ではすぐに気づけない、というのが現状です。もう少し慣れが必要かと思われます。 「ずっと」と「もし～なら」の使い方はスムーズでした。', 'レベルアップのスプライト作成まで済んでいるので、次回は04_06「レベルアップ！」からスタートし、ゲームの完成を目指します。', '盛り上がり: 気になるところはとことん気になるようですが、そこを自分なりに解決するアイディアがまだ出てこない様子です。 着眼点はあるのにもったいない気もするので…色々なゲームやコードに触れて引き出しを増やしていきたいところです。 ゲーム作成自体は楽しかったようで、自分の作品にウケていました。お母さんにも熱心に説明していました。
備考: 【Prg】上級 走ってゴールを目指せ！キャットランゲームを作ろう！がとても気に入って、ギリギリまで遊んでいました。'),
  ('8ebd1c3f-78ea-56ab-a72c-24ce4f915748', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '5cfbd637-17cd-5e1f-9521-1dae0dcfd527', '2022-04-19', '17:30:00', null, '通常 / 教室になれる！', 'アルスパークの使い方を説明しました。「探す」にあるゲームを見て楽しそうでした！角度はバッチリなようです。「〇度にする」と「〇度に回す」の違いや、「最後まで音を鳴らす」のブロックの特徴を説明しました。「ブロックは上から読んでいくんだよ！ちょっとの言葉で動きが変わるよ！」と伝えたとき、「国語じゃん」と言ってくれました。 「〇回繰り返す」のブロックを使ったとき「ずっと」を試してみたり角度の値を自分で変えてみたりしていて、「試してみる」ということに積極的な印象を受けました。 一度話したことはなんとなく覚えてくれていて、保存や新しいページを開くことを自分でやってくれる場面もありました。', null, 'タイピング: 成績の見方や、いろんなタイピングがある旨は伝えました。両手は使えていましたが、小指が使えていなかったのでホームポジションを紹介しました。左手が苦手なようです。タイピングは「嫌いじゃないけど好きでもない」とのことでした。
盛り上がり: 日本史マニアみたいです！日本のお城が好きなようです！ クラブはスポーツクラブ（ドッジとかキックベースとかするみたい） 左利き 角度は分かるけど座標は知らないみたい ニンテンドースイッチをもってる！'),
  ('1f9b5e8a-ec18-54f1-a607-ada59bea1556', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-06-03', '17:30:00', null, '通常', '先週自分でお絵描きしたものを使って、 コスチュームの変更、発車するというコード移してゲームっぽく作ってみた いい部分は、向きが分かっているので、発射する弾がキチンと真っ直ぐに進むようにできたz 回転方法を左右のみにするというのも、話せば思い出してくれたので、1年性にしたら割と進歩しているかなと思います。', null, '盛り上がり: 会話をさせるのコードを作ってみる、待つというコードを使う'),
  ('70158f36-7f41-5ac5-ba3a-aee12afb0976', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-27', '17:30:00', null, '通常 / 自分のやれることをやる', '最初30分間ドット絵を描きました。 下記自分で考えたものと、マイクラを写して書いたので、来週はこれを使って何かゲームを作るでいいのかもです。 できるコードを使ってやる ただ今回の目的は横に動かすことではなく上下に動かす、を目的としました。 また、矢印キーで動かすことを学んでみて、基本操作コースの色々な部分をかじってコードを本日は学びました。弾が出る箇所に関しては、写してもらって書いてもらいましたが概ね、作品ができた時にうれしそうにしていました。 ただ、わからない、できないという言葉が多いので、先生とのお約束として「できない」言わないと話しました。', null, '盛り上がり: 自分で動かせることに対して、理解をしている様子でした。特に角度に関してはちゃんと時間の針で理解しているので、得意げでした！'),
  ('896363d8-80a6-5758-9761-a0a1a2b5f440', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-20', '17:30:00', null, '通常 / 集中ができるように興味を持ったものに対してのコードを書いてみる', 'はるくんが隣で検定をやっていた事もあり同じ奴をつくりたい！というので簡単なコードで魚を海に泳がせるという作品を作りました', null, '盛り上がり: 隣の子がやっている作品を作りたい！という意欲は素晴らしい！ ただし少し難しいコードなどになると文字がまだちゃんと読めていないので、一旦泳ぐだけということを作ってもらいました。'),
  ('16f0e29e-8b0a-5c24-b354-a1e8b9b90b6d', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-13', '17:30:00', null, '通常 / 追跡ゲームの星をだして完成、マウスの練習', 'コスチュームを待つを使いながら次のコスチュームに変えていく 様子：ある程度頑張ってくれた感が今日はある。前回やっていたことを覚えていてこちらからの問いかけに対しても「こうしたい」という希望が出てきた。', null, 'タイピング: どうしてもマウスが動いてしまうとクリックも一緒に動いてしまうので、そこに慣れること タッチパネルを自分で動かせるようにする＞押す場所を明確にすることに一生懸命やっていた
盛り上がり: アルくんを音楽に乗せて動かすことを思いついた。コスチュームが変化するのは楽しいみたい'),
  ('97fdf130-513e-5083-8407-57df66eb2eaf', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-06', '17:30:00', null, '通常 / 前回のおさらいと基本操作コース：追跡ゲーム', 'ある程度やったことは覚えているので、新しいことを追加してみました（復習も兼ねて） 向きを合わせてあげないと上下左右は動かないということを学んでもらう（動かすというのはわかっているので） 向きを考える時に時計をイメージして教えてあげると理解していたようなので、次回からも上下左右は時計で教えてあげると良い。1年生なので集中が保てないが、授業をやってゲームをやってと、間に挟みながら進行してあげると良いかなと思います。フォートナイトの動きの一部をやっているんだよと話したら、意外に「なるほどな」と思っているみたいで、コードへの理解も遥かに増していると思います。', '追跡ゲームの完成を望む・・・', 'タイピング: Level２までなんとか攻略、文字の概念はまだわからないものの、同じ形を探すということに専念してみたらできた。割と集中力はあるので、学校が始まってから文字を覚えるということに慣れてきたのかな？ひらがなが先だけど英文字がわかれば本人的にも今後楽になりそうかな。
盛り上がり: あちこちに動かすというコードを使った時に、「追いかけっこみたいにしたい！」と言っていたのであながちこちらが意図していることを汲み取ってはくれているよう(笑) なのでそのまま教科書通りに進めるとは思います。ただし覚えているかは分からないので毎回おさらいしながらの方が良いです。 また、連続20分は机に向かって集中できるようになってきました！今日の目標達成！'),
  ('d573d8d6-2049-5dc7-bab8-5f80fd243297', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-04-22', '17:30:00', null, '通常 / 2回目の授業、', '角度、大きさ（おおきくする、小さくする）音の項目まで。イラスト自体は好きな様子なのでしばらくタブレット端末でイラストを書いてもらってそれをコードにしてもらうといいかもしれない。 長い時間はむりなので１５分〜２０分座ってやってもらうことを最初は目標に。今日は５分やったら友達の作品を観にいって〜やって〜みたいな感じで進んで、自分でもやれるかなぁという不安もありつつ、やってみたいという好奇心もある様子。', '次回は今回の続き〜座標とかやれたらいいけどな〜', 'タイピング: タイピングはタブレット端末を使って、まずどの文字を打つということよりもLとかBとかの文字の位置を覚えることにしてもらいました。なんとなく、タイピング？？みたいな概念はわかっていそう。次回からは２〜３個ぐらいでもいいかなと思うけど、学校でもやっている？みたいなので少しずつ慣れていってもらえればいいかな・・・
盛り上がり: 自分のイラストを書くことは好きみたい。そこからコードを書くというところへ繋げられたらいいかな！'),
  ('0931cca7-468a-5fd2-9705-06b3e264a231', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-07', '16:30:00', null, '通常 / 基本操作コース_07 ピンポンゲーム ボールの跳ね返りの見直し、ゲームオーバー以降 ドリル レベル1 6～', '基本操作コース_07 ピンポンゲーム ボールの跳ね返りの乱数が、なぜか「190から10」になっていたので、思うようにボールがパドルから跳ね返らなくなっていました。動きがおかしいことを確認して、乱数の見直しをしました。 ゲームオーバーやゲームクリアスプライトの作成はスムーズでした。ゲームのイメージがしっかりとあったため、ブロックもほぼ自力で探せていました。 完成したゲームをプレイしてみて、とても難易度が高いと思ったようで、どこを調整したらよいのか一緒に考えてみました。 →パドルの動きを少し速くして調整ができました！ ドリル レベル1 問題6 ピンポンゲームが完成した時点で残り15分だったため、ドリルが1問出来たら遊ぼう、ということで取り組んでもらいました。 問題文の「角で1秒待つ」を読み飛ばした状態だったため、問題文は必ず最後までしっかり読むことを伝えました。読み飛ばしに気づいた時点で修正はできていました。', '（中島記入）帰りがけに、自分がアレンジしたScratchの「マリオⅡ」をお母さんに嬉しそうにみせていました。一緒にコードをみると、恐ろしく長いコードにびっくりしていて。 「今度、真似して作ってみたい！」と言っていたので。次回から、時々やってみてもいいかもしれませんね。一部だけでもできると達成感あるかも。 ⇒葉君のScratchのアカウントでremixで保存してあります。', 'タイピング: 相変わらず丁寧にタイピングできていますが、ゲーム画面に表示されるのが大文字、キーボードの文字は小文字なので、覚えきれていない文字になるととまどっているようです。今日はGとgを教えました。
盛り上がり: ゲームが完成したことがとても嬉しそうでした。しょうたくんに遊んでほしそうにしていましたが、パドルの動きの調整前だったせいか、しょうたくんが「難しそうだから無理」と断ってしまったのが少し残念そうでした…。'),
  ('5d25ca30-49fb-56c1-b835-5a28d21a3b4b', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-31', '16:30:00', null, '通常 / 基本操作コース_06 物語を作ろう おさらい オリジナル ドリル ピンポンゲーム', 'ドリル レベル１ ～5まで 意外とドリル形式が性に合っていたようで、いつもよりまじめに取り組んでいました。 角度についてはあまり把握していなかったようですが、ここで慣れてくれたので良い復習になりました。 基本操作コース_07 ピンポンゲーム 見本で遊んだ後、どういうゲームか、という説明は一通りできていました。 パドルを矢印キーで動かしたい、スタートは緑の旗ではなくスペースキーをきっかけにしたい、というこだわりがありました。 本来のブロックを分かったうえで、今回は思い通りにさせてみました。 動きのテストをする際、緑の旗よりもスペースキーの方がすぐに押せるから、という理由らしいです。 いずれきちんと使い分けるよう、徐々に促していきます。 乱数のところは、「〇度まわす」というところの難しさもあり、おそらく納得できていないと思われます。 ドリルを頑張った分、後半疲れが見られたため、ゲームオーバーは次回にまわしました。', 'ボールの跳ね返りの見直しをしてから、ゲームオーバー以降を作成予定です。', 'タイピング: キーの打ち方が丁寧です！指使いにも気を配っています。
盛り上がり: ドリルの問題を一生懸命読んで、すぐに答えを見たりせずに自力で解こうとする姿勢が予想以上で感心しました！ 角度についても、問題を解きながらいろいろと試して楽しそうにしていたので、良い振り返りになったと思います。
備考: 対戦オンラインゲームの起動が間に合わず、残念そうでした。'),
  ('c992bf00-9047-585c-b712-6aa80993c6eb', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-24', '16:30:00', null, '通常 / 基本操作コース_06 物語を作ろう', 'イベントブロックは「旗が押されたとき」よりも「スペースキーが押されたとき」の方が押しやすくて好きとのこと。 「〇歩動かす」と「1秒で座標を変える」の違いを、実際に動かしながら確かめました。', '「基本操作コース_06 物語を作ろう」の内容は、最後までなんとなくはできていますが、きちんと扱ったわけではないので、次回おさらいしながらすべての項目に触れたうえで先に進みたいと思います。', 'タイピング: かわべの竹林クリアしました！
盛り上がり: 自分の声を追加するのがとても楽しかったようで、いろいろとセリフを変えて試していました。 試したいこと、やりたいことが色々あるようで、途中で作成中のスプライトを全部削除して、キャラクターを変えてやり直していました。'),
  ('02853cbb-730c-5edf-9c1a-3798731359b8', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-17', '16:30:00', null, '通常 / 基本操作コース_04追跡ゲーム_04 から', '音を鳴らすときに「ずっと」が必要なのは、すぐに自分で気づいて直せました。 いろいろと試すことが好きで、スプライトの大きさや音、レベルアップの点数など、微調整しては試していました。 変数の変わるタイミングや初期値については、野球やバスケットボール、サッカーのスコアボードで納得していました。', null, 'タイピング: かわべの竹林 まだ間違いは多いですが、ホームポジションを守ろうという意識をもって打てていました。
盛り上がり: 何度も調整をして試しているだけあって、自分の作成したコードをよく覚えていて、修正箇所を見つけるのも早いです。 残り15分くらいで少し疲れが見えましたが、残りあと一つ頑張ればゲーム時間だと伝えたら、一気にやる気になって最後まで頑張りました！ ローマ字はまだかなりおぼつかないですが、タイピング表を見て頑張って入力していました。
備考: マインクラフトのゲームが楽しかったようです。 本人もお母さんも、どちらかというと進捗状況が気になるようなので、コース表を見せて説明すると嬉しそうにします。'),
  ('e18c6550-5217-5d66-9cea-8b03af8f30b4', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-10', '16:30:00', null, '通常 / 基本操作コース_03世界を想像しよう 続き、基本操作コース_04追跡ゲーム', 'おしゃべりのタイミングをずらして会話のようにさせることができました。 上下左右に動かせるのが面白かったらしく、自分からスプライトを増やして動かしていました。横方向はx、縦方向はy、反対方向はマイナスということだけは把握できたようです。 本単元の内容から、「これでゲームが作れそう」と盛り上がったので、そのまま追跡ゲームに入りました。上下左右に動かす復習にもなりました。（座標の区別はまだ完ぺきではないですが、マイナスは覚えていました）', '基本操作コース_04追跡ゲーム_04 から', 'タイピング: あやかしの森のスタートから J、F、G、Hとエンターキーの指を覚えました
盛り上がり: 自分が覚えたことが「ゲームになる」ということをとても喜んでいました！ 今日は一人だったせいか、集中して課題を進めることができました。 「今日はどのくらい進んだ？」と、自分のファイルを確認して、一つの単元がクリアできたことを喜んでいました。
備考: サッカーが好きだそうです！ 人のしていることが気になるようなので、二人のときは背中合わせに座らせるなど配置の工夫があった方が良さそうです。'),
  ('9397d05b-6e10-52e0-975e-9d4a51a574b3', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-26', '16:30:00', null, '通常 / 基本操作コース_03世界を想像しよう', '前回の復習から入ろうとしたところ、隣の席で同じ単元を始めたしょうたくんが気になって、「僕もそれをやる！」となり、同じ範囲での新規作成となりました。 スプライトや背景を変えることは覚えていて、楽しそうに取り組んでいました。 繰り返しについてはあまり覚えていなかったので、しょうたくんと一緒に説明を聞いてもらいました。 実際にコードを作成して動きを確認したところ、納得はできたようでした。 「キーが押されたとき」のブロックはよく覚えていて、得意そうでした。 知っているブロックをなんとなくつなげていって満足している節があります。今回はたまたま面白い動きになったので褒めてみたところ、同じ動きのスプライトをもう一つ作りたいとのことで、ブロックのコピーを教えました。 「基本操作コース_03世界を想像しよう」の「飛び回らせよう」まで作成しました。', '基本操作コース03の続きの予定です。声掛けに工夫して、学習してほしいところと脱線して楽しむところのメリハリが付けられると良いのですが…。', 'タイピング: 授業前のマイクラと、新入会のしょうたくんに気を取られがちでした….。大文字と小文字の違いが苦手だそうです。
盛り上がり: 色々とコードをつなげて結果を楽しむ好奇心は旺盛ですが、適当な部分が多く、偶然の結果を面白がって大人にコメントをもらいたがります。 今日は新入会のしょうたくんの方も手が離せなかったため、待ち時間では物足りなさそうでした。課題を与えておいても、すぐ脱線して「こんなのができた！」と大人の気を引きたがる傾向があります。 気づいたこと、できたことを共有していきたいタイプなのかも…もう少ししょうたくんが慣れたら、二人で切磋琢磨しながら課題に取り組めるようになることを期待したいです。'),
  ('db54725b-f579-5809-b768-e303ad02f058', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '2e9ca4d9-8957-5d02-afd6-3397b7b194c2', '2022-04-19', '16:30:00', null, '通常 / 自分の作品を作るところまで', 'まず何をやったのか？を思い出しながら復習から。大体のことは覚えているもの座標や向き、コードの順番などはあやふや。まずは何回か同じことに慣れてもらうため、もう一度最初から新規で作成。 自分の名前作品に関しては、アイディア自体はとても素晴らしいので、今後はそれぞれのスプライトがどう動いていくのか？を学ぶことがいいかもしれません。特にリレーションという場面になったときに混乱してしまいそうなので、１つづつのスプライトの動きを明確にさせてあげるとGoodかなと思います。', '次回は基本操作コース03を行うで大丈夫かと思います。この部分でリレーションを少し強化したいところ。混乱させないように順序よくが肝かなと。「こうしてみようよ〜」と一緒につくる方がBetter', 'タイピング: キーボードの位置がまだわからないそうなので、５０音をタイピングするよりも、練習モードでキーボードの位置を覚える方からやりました。Level１−９まで行いました（あ〜さ行まで）
盛り上がり: タイピングのところで若干疲れがでてしまったものの、こうしてみたい！という欲求はあり、終始このスプライトはこうして〜などと自分で考えられる力があると思いました。後半疲れがでて、スプライトの動きに混乱してしまっていたので次回は、タイピングのボリュームを少なくしてが◉'),
  ('c1b32b85-b5e3-5363-b2d8-ccfcc71f8105', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-12', '16:30:00', null, '通常 / ようくん初回、写真撮影', '・思いついたことを試したいタイプ。 ・音やスプライト、背景なども、じっくり選んでいた。 ・スプライトの向きを変えたがったので、90度と-90度だけ教えたところ、興味を示していた。', 'ファイルを見せて、次回は基本操作コース_02 名前を動かそうの5から始めることを予告してあります。', 'タイピング: タイピングはまだ苦手とのことだが、やる気はありそう ホームポジションを教えたら、下を見ないであいうえをが打てるようになりました！ どんなに時間がかかっても、正しい指使いで打鍵しようとする姿勢がすばらしい！
盛り上がり: 好奇心が旺盛で、テキスト以外のことでも質問に答えたりヒントを与えたりすると、ワクワクと試していました。 タイピングで正しいキーが打てていても、指使いが違うとやり直す徹底ぶりでした。ホームポジションを教えたら、とても喜んで感心していました！
備考: このクラスは一人だけなのが少しさびしそうで、次の時間に来る子がどんな子か、学年や性別を熱心に聞いていました。 5分前に授業終了した後、ゆずとくんがScratchのマイクラをしているのを見て一緒にやりたがり、操作方法などを積極的に聞いていました。'),
  ('8cd0df5f-7b87-5fef-ba77-c003314450c3', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-31', '17:30:00', null, '通常 / 構想があればコンテスト作品 ピンポンゲーム 細分化', 'コンテストの構想は今の時点では特になく、新しい単元に行ってみたいとのことだったので、ピンポンゲームをプレイしてから細分化の紙を書いてもらいました。最初のスプライトだけ、ゆずとくんに発問する形でその回答を私が筆記し、残りは自力で書かせてみましたが、よくできていました。 「パドル」は「自分で動かせる」と書いていたので、「何で動かせるのか？マウスかキーか？」「動きの特徴はあったか（この場合はx方向のみに動く）」など、付け加える情報を一緒に考えていきました。 ゲームを作成していくうちに、どんどんアイディアが浮かんできたようで、ボールが端について跳ね返るときに音を鳴らしたい、ゲームオーバーのときに音楽を鳴らしたい、など、熱心にアレンジを加えていました。 ゲームオーバーのときに効果音を鳴らしたい、ただし、ゲームオーバーの曲は途中で途切れずに最後まで鳴らしたいが、曲が鳴っている間にボールが動き続けるのはおかしいので、ボールはすぐに止める、というゲームにするために試行錯誤していました。 「すべてを止める」「スプライトの他のスクリプトを止める」の違い、「音を鳴らす」と「終わるまで音を鳴らす」の違い、メッセージの機能について説明し、これらを組み合わせるよう提案したところ、思った通りの仕様ができたようで、満足そうでした。', 'ピンポンゲームのスコア作成から', 'タイピング: うでだめしはよくできていて、ゴールド級を出していました。自分でファイルの用紙に記入してもらったところ、前回より記録が伸びていると喜んでいました。
盛り上がり: ピンポンゲームは自分で一度作ろうとして挫折したことがあったそうで、今回とても嬉しそうに作成していました。 お父さんにも作品を見せたところ、かなり感心してもらっていました。 ゲーマーらしく細かい仕様にこだわりが見られましたが、それをきちんと形にできたことが余程嬉しかったのか、授業後もずっと、自分の作りかけの作品を動かしていました。
備考: 途中まで作成したピンポンゲームをScratchのアカウントに保存しました。リミックスの方法も教えたところ、親子で喜んでくれました。'),
  ('c7eee1f3-4d82-53f3-a2c7-c82074340cc0', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-17', '17:30:00', null, '通常 / 基本操作コース06 物語を作ろう', 'レベルアップ後に、逃げ回るスラボーの動きを早くしたいとのことで、そこのアレンジだけ取り組みました。メッセージを「メッセージ1」のまま使っていたので、わかりやすいコードにするようにメッセージ名を変えるよう促しました。 今後も踏まえて、メッセージ名、スプライト名、コスチューム名などをわかりやすく変えておくことを心がけるようにしました。 課題については、最低限の指示で自力で取り組み、わからないところも質問も的確にできています。', null, 'タイピング: ゴールド級を出していました！タイピングは完全に独学だそうですが、文章を打つのが好きだそうです。
盛り上がり: みずきくんの影響か、今日は少しくだけた感じもありましたが、終始楽しそうに取り組んでいました。 録音した声で遊ぶという発想は新鮮だったらしく、ストーリーに合った声を作り出そうと盛り上がっていました。
備考: コンテストはやる気になっています。お父さんが、「回数が足りなかったらどうすれば？」とご質問されたので、そういうことがあれば応相談とお伝えしてあります。'),
  ('343ad784-6e85-5f4a-9c5e-ef982f0eb06c', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-26', '17:30:00', null, '通常 / 基本操作コース04 追跡ゲーム', '見本のゲームで数回遊んでから細分化をさせたところ、スプライトだけではなく背景にも気が付いてよく書けていました。 自分で書いた細分化のシートを見ながらゲームの作成に取り組みました。カードはほとんど見ずに、細分化シートを見ながら作成していくことができていました。 上下左右をなめらかに動かす方法があった、ということを覚えていて、そちらでやってみたいというので、条件分岐で上下左右に動かすコードで作成しました。 本人の強い意志で、「どこかの場所にいく」スプライトに「端についたら跳ね返る」「回転方法を左右のみ」を入れていました。次回、余裕があったら、後述のブロックが必要な場合と不必要な場合の説明ができればと思います。 変数や背景の処理などについては、細分化の説明が自分でできていたので、それに該当するブロックのグループをヒントとして出すと、そこから組み立てていくことができていました。 スプライトに触れている間、スコアが上がり続けることは、みずきくん同様気になっていたようでした。ゆずとくんは、自分で解決策を考えてアレンジすることができました。（お父さん曰く、「ゲーマーなのでそういう視点はあるかも」とのこと）', null, 'タイピング: タイピング自体はそれなりの速さでできていますが、右手で打ってしまう癖がなかなか抜けないそうです。ホームポジションを教えて、まずは中段だけでも決まった指で打ってることを勧めてみました。
盛り上がり: ゲームを１つ完成させることができたのが嬉しそうでした！ もっともっと、たくさんのゲームを作っていきたいそうです。'),
  ('ab1ada66-f85c-54bf-9476-e11d0b20e76f', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-12', '17:30:00', null, '通常', '一項目を扱うたびに、この機能はゲームのこういう場面で使えそう、という話で盛り上がった。アルスパークの見本を見せると、まずは自分でどんなプログラミングになるかを考えてくれるので、口頭でどんなブロックを使っているかを言ってもらい、どのタブに入っているかヒントを与えながら進めていった。 自分の名前でオリジナル作品を作成するところまで進めることができた。自分のイメージを的確に形にできていた。 「I」が表示し終わったら名前が出るようにしたいとのことで、メッセージ送信を教えた。', '次回はオリジナル作品に音などを付け加えてみる予定', 'タイピング: 苦手と言っていたが、速さはそこそこ。指は完全に自己流, 8割を右手で打っている。本人も自覚有り。 クエスチョン、エクスクラメーションの入れ方を教えた
盛り上がり: オリジナル作品を作成できたのがとても嬉しそうで、とくに座標を使うことによりスプライトが狙った通りに動くことが楽しそうだった。'),
  ('8a752f0a-b9b3-5bf6-b7a5-631a49d9a2f1', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'c51e1aaf-9ff9-5113-85f5-0440529b3831', '2022-06-24', '16:30:00', null, '通常 / コンテストビギナーズ部門作品作成にチャレンジ', 'テキストを渡して、文章に沿って作成するように指示しました。 基本はわかっているため、特に問題なく作成できていました。 テキストの構成が、普段の教室のレッスンとは違う構成のため（必要なブロックを全部スクリプトエリアにもってきてから、プルダウンのメニューを変えていく方式）、ブロックを選ぶ時点では目的と一致していなくて混乱しそうだったため、適宜テキストのページをとばしました。', null, null),
  ('5e31a0fd-17c6-5b22-bdad-3a94ce62ca53', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '5cfbd637-17cd-5e1f-9521-1dae0dcfd527', '2022-06-06', '16:30:00', null, '振替え / スタンプがやれてないので、次回はスタンプへ09 ジャンプゲームへと進みたいと思います。', 'どの動きに関しても自分の世界観をもっていて素晴らしいと思います。 コスチュームの色の揃え方、グラデーションのつけ方について説明しました。 一度扱ったことをよく覚えているようでした。背景の変え方もばっちりでした。 新しい範囲になったときに、指示の内容をプログラムの言葉に置き換えるのは苦手なようです。 座標は苦手そうでした。ｘ、y座標がどちらを示しているのかが分からなかったようです。 ジャンプにかなり苦労しました。「y座標を変える」というアイデアがなかなか出てこなかったです。「～にする」と「～ずる変える」の違いもあまり意識できていませんでした。 ジャンプまで完成しました。', null, 'タイピング: 正答率は前回よりも落ちたものの、打鍵/秒は前回からみるみる値が上がっていて良かったです。集中して取り組めていました。
盛り上がり: 卵を超えるようにジャンプしたいとのことで、値を微調整して何度も試していました。'),
  ('d7fb42ca-1d9a-56eb-b56c-c57e2558dba7', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-27', '16:30:00', null, '通常 / 基本操作コース08 さぁ踊ろう＞＞スタンプ', '今までやってきたことに関しては概ね理解をしているみたい （ドリルの効果あったかも） 今日はコスチュームを変えるという箇所なのでたつきくんに自分で好きなスプライトを選んで行ってもらいました。 かわいいものが好きならしく作品も絵本のような感じにしあげる傾向があります。今後がどうなるか？はわかりませんが世界観がお兄ちゃんとの系統とはまた違うので、たつきくんなりのコードを今後もかけていけたらいいなと思っています。 スタンプがやれてないので、次回はスタンプへ09 ジャンプゲームへと進みたいと思います。 ここまでかなり基礎をやってきているので、問題はないかと思いますが、 座標のあたりが心配ではなるので次回は座標の部分も再度おさらいしてから、かな？', null, 'タイピング: ある程度安定して打ててきているので来週からPlaygramの腕試しなどをしてもいいかも知れません。'),
  ('df587444-e491-5da6-9c7a-a22440379a62', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-20', '16:30:00', null, '通常 / ドリル: Level2', 'コスチュームと動きを合わせてコードを書くというのが最初なかなか思い出せなかった様子でしたが、 「これ前にやったやつだけど？」と古い作品、教科書をみせたらすんなり書くことができました。 理解をしているものの、完全に覚えているか？という問題だけだと思うので、数をこなして手で覚えていく方が今のたつきくんには合っているのかな？と思っています。', '次回はドリル', 'タイピング: 97.3%の正答率、多少ばらつきはあるものの、平均的に高得点を取れていると思うのでそろそろ腕試しでPlaygramのうでだめしなどをやっても良いかと思います。'),
  ('741862d9-3132-5163-871a-18af8ec82567', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-13', '16:30:00', null, '通常 / ピンポンゲーム03〜から引き続き▶︎ドリル？後日スキルチェック', '座標、また条件分岐、乱数までを一気に学んだ。基本的には「こうやろうね」と伝えると本人は理解している様子。アレンジまでは疲れてしまったため進めなかったが、基本的な動作のコードまでは作成できた。', '次回はドリル', 'タイピング: 難しいといいながらも、基本的なタイピングはできているので問題はない、ただし本人がその日の疲れ具合（今日は眠いと話していた）によってムラがあり。
盛り上がり: パドルが動く時にマウスと連動がうまくいかなかったので、そういったバグをきちんと見つける能力ができたかなと思います。もちろん発見するまでにはちょっと難しかったのでX座標にする〜のコードと間違えてしまったんだねと伝えて、解決に至りました。お兄ちゃんと同じでゲームが違った動きをすることに対してはかなり敏感だと思います。'),
  ('1ff64fc6-3d18-54e6-8f8d-1fd1c0adb59d', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-10', '16:30:00', null, '通常 / 前回のバグ探し 重複しているブロックの整理 背景の「旗が押されたとき」「上向き矢印が押されたとき」を統一、背景の名前の確認 キツネの「もし背景の名前がプレイ中なら」の必要性確認 キツネの「隠す」「表示」ブロックの確認 キツネの消えるタイミングのy座標の確認 モグラのブロック定義のx座標を乱数に 敵キャラクターの動きの作成', 'ブロックを整理する意義は理解してくれて、一緒に背景と各スプライトのブロックを丁寧に見直しました。 重複していた命令の整理、コスチュームやスプライト名の統一、定義ブロックの整理などを熱心にしてくれました。 コードが長くなるところを、自分で定義を作成してメインのコードがすっきりするように工夫していました。', 'モグラの動きのコピー、効果音の設定などをする予定', 'タイピング: パス
盛り上がり: コードを整理したら、ゲーム開始の効果音が鳴るようになったり、敵に当たったら体力が減り、0になったら10秒止まってから動くようになる、など、希望していたようにプログラムが動くようになったのが嬉しそうでした。 うまくいかなかったときに一度爆発しそうになりましたが、見直す箇所のヒントを出したらバグ探しに戻って解決することができていました。 ドット絵に合わせて、チープな効果音を自分で作りたいと言っていました。'),
  ('424679a4-9abe-5c94-9291-20149c16616a', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-06-06', '16:30:00', null, '振替え', '全体的に、コードを移しているため自分でバグを見つけるのが苦手？ スペースキーが押された時に、初期化になってしまう →スペースキーが重複しているので弾を発射した時にスタートに戻ってしまう 狐の動き やりたいこと→左右に跳ね返る、下についたら上に戻ってまた落ちてくる キャッチゲーム、ピンポンゲームを活用して敵が出てくるコードを書き換える 自分が作った定義を使いたい、しかし他のコードと重複しているもしくは条件分岐のコードがきちんと入力されていないため狐が思うように動かない。', null, '盛り上がり: 次回は、自分がやりたいところをきちんとコードをかくこと、重複しているところがないか確認すること'),
  ('812af98f-ab3e-5dd2-bd69-2fed40b75f46', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-27', '16:30:00', null, '通常 / ドットキャラクターを活用、敵キャラクターの動きを作成', '早速、ドットのモグラを活用して、敵キャラクターを作成しました。 Scratchの「ゼビウス」を参考に、モグラの動きを作成しました。ブロック定義の構成を一緒に見ていきながら、必要なアレンジをすることができました。 スタート画面に表示するスプライトを作成し、ゲーム画面への切り替えがスムーズにいくようにしました。', '引き続き、敵キャラクターの動きを作成していきます。 次回、6/3を6/6に振替予定です。', 'タイピング: パスしました。
盛り上がり: 少しずつゲームが形になっていくのが嬉しそうでした。 他のコンテスト参加作品が気になるようで、他の子の作品が見たいと言っていました。'),
  ('fa37681a-49ab-545a-9db9-66e64232bc6e', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-20', '16:30:00', null, '通常 / ドットキャラクターを活用', 'コード画面をきれいにするためにブロック定義を使いたがったので移動のためのコードをブロック定義で作成しました。 ブロック定義やコメントの活用をしたり、コスチュームや背景、スプライトの名前などをわかりやすく変えたりしていました。 自機の男の子キャラクターが移動するときの動きや石を投げるときの動きなどを、コスチュームの切り替えをうまく使って設定できました。', 'モグラやキツネなどの敵キャラクターの動きを作成予定です。', 'タイピング: 今日は飛ばしました
盛り上がり: ドット絵はとても喜んでいました！ ブロック定義やコメントを使って、コード画面が見やすくなるように工夫していました。「人に見せるプログラム」を意識できるようになってきています。「こうやって書いておけば見やすいよね？」とこちらに何度か確認してくれました。'),
  ('dead0797-8fef-51b0-9bc2-52aadb859929', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-15', '16:30:00', null, '通常 / 前回まで「ピンポンゲーム」 ハルト君みたいに自分で好きなのを作りたがっていたそうですが。若干、基礎が気になるところよね？ なので、基本は次の「ジャンピング」か「キャッチ」に行きたいところです。 好きなのを作りたそうだったら、時間を決めて基本単元やって、その後自由作品という流れにしてもいいかもです。 その際、「基本単元は、基本スキルの習得が全部入っているから。これを一通り終えると、その後の応用力に雲泥の差がでるんだ」ということを説明してあげてください。そのうえで、「基本単元何時までやろうか？」という流れをお願いしたいところです。 好きなのを作りたがる子には、「今後の作品予定」を少～し見せて、もう少し基礎をやったら、こんなのもあんなのも自分で作れるようになるよ～と、先を見せてあげると良いと思います。', 'この単元で扱うブロックは大体わかっているようで、特に問題もなく作成できていました。 敵がセリフを言いながらせまってくるというアレンジをして、楽しそうにしていました。', null, '盛り上がり: ゲーム性のある作品だったので、作成、アレンジ共に熱心に取り組んでくれました。'),
  ('d6744b8a-e3c0-5e84-97fc-641237641f4b', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, null, '2022-06-24', '17:30:00', null, '休み', null, null, null),
  ('d82c13b5-c6f3-5fbd-89e1-7455fde64777', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-24', '18:40:00', null, '通常 / 変数の理解を深める', '動画を見ながら、一緒に変数の復習をしていきました。 変数の基本までは、少し退屈そうながらも問題なくできていました。 マイナスを変数で表現するときに「*-1」をするところは、私の画面をチラ見しながら作成をがんばっていました。 最後の課題、1～100までの合計の和については、さすがに難しかったようでしたが、ギリギリまでチャレンジしようとする姿勢を見せてくれました。', '100までの合計の和について、一緒に確認できればと思います。 何気ない授業中の会話についてよく覚えていて、「完成させようね」と言ったものがゆまちゃんにとっては未完成のまま放置されるのが気になるようです。次回、変数のおさらいをしたら、作りかけになっていたふくわらいか、ゆまちゃんがキャラクターを取り込んだものについて、作成を進めたいか確認したほうが良いかと思います。', 'タイピング: 安定しています
盛り上がり: 一緒に同じ問題に挑戦するのは楽しそうに見えました。'),
  ('3ec6a82d-a688-54b9-9e78-e63aee1f94ec', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-24', '17:30:00', null, '通常 / コンテストまでの計画見直し、本当に作りたいものの確認と作成開始', '作りかけのラーメンゲームについて、フランクに話してみたところ、そこまで思い入れはないようでした。かといって、すぐに作りたいゲームがあるわけでもなさそうだったので、ビギナーズ部門中級の「ねずみとり」をテキスト通りに作成してもらいました。 もともと、発問を聞いて、自分でブロックを作ることが得意なけいとくんなので、最後までスラスラと進み、集中力も持続していました。 ゲームが動くようになったら、キャラクターや場面をサバンナに変えて、とても楽しそうにライオンの狩りゲームに作り替えていました。隠しキャラがいたりもして、よくアレンジできていました！', 'ビギナーズ部門のアレンジとしてもよく頑張っていると思うので、このまま作成を続けて、飽きる前に完成させて提出したいところです。 得点や場面転換、音など、けいとくんがこれまで学んできたアレンジを提案していく予定です。', 'タイピング: さらちゃん、はるくんと一緒に取り組んだため、どうしても時間がかかってしまったのと、結果が「不合格」と出てしまったのが少し悲しそうでした。 正解率が88.5%を超えていたのが素晴らしかったので、かなり褒めたところ、「そうかな…？」と、少し受け入れてくれたようでした。 今は時間がかかっても構わないので、この正解率を維持したまま慣れていけば、2学期にはかなり上達していることを伝えて励ましました。
盛り上がり: 久しぶりに途中でだれずに楽しそうにゲーム作成に集中するけいとくんが見られました！ これまでの様子からも、動物系のキャラクターが追いかけっこをするような、良い意味で子どもらしいゲームを作ることが楽しそうな感じでした。
備考: お母さんがかなり熱心に準備をされていたようで、少し残念そうでしたが、今回は時間とけいとくんのモチベーション的に難しそうなこと、今回はコンテストにしっかりと応募して達成感を味合わせることを目的とし、次回以降、お母さんのアイディアのような大作にチャレンジしてみたいことをお伝えしました。けいとくんが久しぶりに、得意げにお母さんに作成したゲームを見せにいっていたので、おそらく納得していただけたと思うのですが…。'),
  ('46cc47b8-dc53-5d10-8043-0ac8ce94255d', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-06', '16:30:00', null, '通常 / 前回の復習&もし可能であればピンポンゲーム07', '前回の復習からメッセージを送るの概念をもう一度おさらい&背景もメッセージを使って変えることができることを確認、体力と集中力が今日はなかったので、５時までときめて07のピンポンゲームの02まで作成 座標の概念もおさらいしながら（xが横、yが縦）パドルを動かすのがXとYと変えると縦と横に動かすことができるのを確認。', null, 'タイピング: スコア836点 過去最高得点、だいぶ集中してできた様子です。ローマ字を打つことに関しては問題なさそう、今後もう少し長文のタイピングに移行しても大丈夫かと思います
盛り上がり: タイピングがかなり集中してできた様子で、とても満足げでした。昨日Disenyに行った&連休明けの学校だったため疲れたのか、30分で授業は終わるようにしました。残り30分はゲームにあてて、なんちゃってマイクラをスクラッチでやっていました。やはり低学年なので、疲れた時はあまり無理せず様子見で授業を行った方がいいかなと思います。'),
  ('878bc26f-69ed-507f-82f6-b93b7060ae05', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-04-22', '16:30:00', null, '通常 / 基本操作コース06 物語を作ろう', '基本操作コース０６に関しては始めてメッセージというお題が出てくるので、どのスプライトにメッセージが送られているのか？を覚えるのが大変そうでした。 時間を経るにつれて使い方がわかってくると、このスプライトはこうして〜、ああして〜という理解度とクリエイティビティが合わさって彼なりの世界観の作品ができたと思います。特に座標に関しては2年生ながらに定着率がとても良い。また、まだメッセージ自体が背景の方には使用していないので、次の項目に写った時にそこも並行して学んでいけたら良いかと思っています（ゲームを作りたがっているのもあり。）', null, 'タイピング: タイピングはなんとか自分で時間をかけて行える様子、じっくりコツコツタイプですが正確さはとても良いのでこのまま進んでくれたら問題ないかと思います
盛り上がり: 彼なりの世界観がある、かわいいものが好き？物語みたいなものも好きな様子。ゲームもあってると思うけど、お話みたいなものを作る能力もあるかなと思います。'),
  ('034913cf-252a-5483-bac3-f13ba0ab23f8', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-04-15', '16:30:00', null, '通常 / 前回まで２週連続で「世界を創造しよう」に取り組んだとのこと。 丁寧に取り組むタイプのようなので、そのまま基本カリキュラムにそってみましょうか。 今日から新しい単元ね～と、「追跡ゲーム」に入りますか？', 'それぞれの項目に対して、真剣に取り組んでくれました。特に、「この時のコードはどんなのだろう？」と話すと自分から率先してコードを探す姿勢がとれています。（多分先生の言った言葉の中に答えがあるなと推測している）1つ教えるごとに、1つ習得し、多少難しい座標なども間違えたら、そこを再度自分の頭の中にインプットしながらやれている様子はとても2年生には思えないほどです。 今日ですべての項目が終わったので、次回は物語を作ろうでスプライト同士のリレーションを学ぶ？で良いかなと思います。', null, 'タイピング: 98.3%の正答率、タイピンングの早さも0.8です。小学校2年生にしてはとても良いタイピングスキルを持っていると思います。とても丁寧にタイピングをしているので、今後が楽しみです。
盛り上がり: 背景、音を追加して変更するときに、私から言わなくても、「この時に〜がしたい」という頭の中ができていると思いました。'),
  ('eb8c2ca2-e13e-5306-a83d-6a39eabddf48', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-24', '17:30:00', null, '通常 / コンテストの魚がタコスを食べるをお手本テキストを見ながら作る→アレンジをするまでが目標', '今回はコンテスト作品を作ってもらって、それでよければアレンジをしてコンテストに出してもらおうというのが作戦。 ただ、ハルくんは前からあまりコンテスト自体に乗り気ではないので、一応検定の意味があるからやってみて〜的な感じで伝えて、やってもらいました。 途中やはり文章の意味を真剣に読むことをしなくなるので、何回かこちらからアクションを入れて、一通りやり切ってもらうことまでは成功。 基本的には今回のコンテスト作品のコードは本人にとって楽なコードなため「簡単だよ〜」と言っていましたが、丁寧にコードを書くという作業を今までしていなかったためか見本通りに作るということが嫌な様子はありました。 アレンジアンドコンテストに出るか？の話になるとやはりそこは拒否・・・ 作品を作っている最中は楽しそうなのにと思うのですが、抵抗感があるのかな？', null, null),
  ('783e4c22-3bb2-581d-8f47-6732188c1ee8', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-06-06', null, null, '通常 / 先週の続き、まだトランポリンがタイミングよくクリックしても作動していないので、 今週はそこの動作性をいかにもっていくか？かなと思います', '集中して動画をみつつ取り組めていました。 最後まで見終わりましたが、上にのぼったっきり下がってこなかったので一緒に原因を探しました。 y座標のコントロールがうまくいっていないように見えたのですが、プログラムはきちんとできていました。 検証していく中で変数の変化は目にみえないので、変数を表示させる必要がなくても表示するということを伝えました。考えていく順番も共有できたので良かったです。 見本通りにプログラムできたにも関わらず、うまく動いていなかったので原因が分かりませんでした。来週に持ち越しです。', null, '時間帯: その他
タイピング: ホームポジション大変よい。速さは現在はそこまで早くないが、将来的に早くなりそうです。
盛り上がり: あきらめずに取り組めていたので良かったです。'),
  ('de936401-f3b2-539b-8636-d5022b079e0f', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-05-30', null, null, '通常 / 先週のつづき（ビデオをみて作成＆レベルを上げる！）', '丁寧に見て進めていました。 途中、あるくんが上に行ったきり降りてこなくなってしまいました。見本は動いていたので、このタイミングでもどうやら動くようです。 一緒にプログラムを確認し、どこの部分を間違っているのかを探しました。 うまく働かない部分を探すときのポイント（見た目が関係するのか、動きが関係するのか、どのようなプレイヤーのアクションで動作する部分なのかを参考に考えること）を一緒に確認できたので良かったです。 新しい発見として、「または」の使い方を挙げてくれました。いままであまり積極的に使ったことがないようです。また「（空白）と言う」のブロックの使い方も珍しかったようです。', null, '時間帯: その他
盛り上がり: 集中して取り組んでいました！'),
  ('2f0bb024-46eb-5aea-a2e1-a93b70b497c0', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-05-23', null, null, '通常 / 動画を見てプログラムし、2級レベルを体感する。', '動画は0.5倍速で1/3ほど進みました。 集中して見ていました。自分でも動画を見てプログラムするのは嫌いじゃないそうです。 最後に「使ったことがない新しいブロックの使い方」として加速度と速度のプログラムの部分をあげてくれました。着眼点が素晴らしかったです。やりつつもただ単に移すだけではなく、プログラムの中身も同時に確認できているようです。 検定2級の下地になっていることの説明もできたので良かったです。', null, '時間帯: その他
タイピング: 普段よりもミスが多かった（80％）です。
盛り上がり: 時間ギリギリまで進めていました！すごい！'),
  ('21e61dbe-1446-58a7-89cb-64c9658ea943', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-05-16', null, null, '通常 / 迷路脱出ゲーム（跳ね返りのプログラムと「～へ行く」のプログラムの確認） 細分化の練習', '細分化→あるくんが壁に当たったときの挙動がかかれていなかったので、少し残念でした！リクエストして書いてもらいましたが、「跳ね返る」と分かりやすい言葉で書いてくれたので良かったです！ メッセージを使って「スタート」を制御できていたのでとても良かったです。あるくんのスタートと棒のスタートをうまくコントロールすることができました。 跳ね返りのプログラムもばっちりでした。また、あるくんを動かすときに「～へ向く」を使えていたのでとても良かったです。 線の速さを細かく調整してくれました！お手本だと「0.6歩を〇回」で制御していましたが、「秒数と距離で速さを制御する」という感覚をつかんでほしかったので、「〇秒で～～に動く」を説明しました。 ゲームは完成しました！', null, '時間帯: その他
タイピング: 姿勢よくタイピングできていました！ホームポジションを意識できていました！正タイプ率は80%でした！
盛り上がり: Apexが好きだそうです！'),
  ('5187c15f-45b7-50a7-82f1-eed1f381fffb', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-05-09', null, null, '通常 / 単元別演習EとGで演算の復習', '演習1は、文章が読みづらいようだったので見本をみせつつプログラムしてもらいました。乱数の使い方、隠す表示するのタイミングも完璧でした。見本とは違うものの整合性のあるプログラムができていました。 演習2は、「～と～」の使い方に戸惑っていたようです。「こんにちはと答えを話す」と伝えたところ、納得してくれたようです。 演習3では、大きさのコントロールの仕方に少し困っていました。「20変える」と「1ずつ変えるを20回繰り返す」の違いを、スプライトを歩かすときの違いと交えて説明しました。ブロックの順番に気を配れていたので良かったです。 演習4ではタイマーを使用しました。「10秒」を使ってはじめはプログラムしてくれましたが、タイマーを使ってプログラムするようにリクエストしました。演算の<と>の向きで迷うことなく進めてくれましたが、「もし」を使うときに「ずっと」を忘れていたようです。声をかけたらすぐに気づいてくれました。 計算式のある演算については紹介だけしました。数学はあまり得意ではないようです。', null, '時間帯: その他
タイピング: 両手使って正確にタイピングできていました！ホームポジションも意識できていたようです！
盛り上がり: 答えが目の前にあるにも関わらず、早々に「できない」「分からない」と言ってしまう場面もあったので、もう少し自分で考えるように促しても良いかもしれません。'),
  ('ec985958-dc10-5dca-86b2-24c13619f259', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-04-25', null, null, '通常 / 先週の続きで、簡単に終わってしまいそうなので、その次のをイメージしておこうか。 細分化の練習＆「～へ行く」を復習', '全体的にやることは理解している。ただ動作が止まってしまった時など、自分で過去にやったところだなという引き出しを考えるのがもう一歩かなと思います 例）スコアが０になったときに止まるという演算を使ってコードを書くなど これはあらたくんのせいではないですが、スクラッチ特有なコード同士が干渉し合うという現象に悩まされていました。大抵がずっとやイベントが噛み合ってしまって動かないなどありますが、そういうときにちゃんと先生たちに聞いて、相談する、やってみるという部分が成長したように思います。前よりもずっとあらたくんが文章としてスクラッチを理解しているということが、私たちも分かってとても嬉しいです。', null, '時間帯: その他
タイピング: タイピングは安定。もう少ししたら文章を書く練習をしてもいいのかな？'),
  ('dd44eacf-1f9b-558f-bb50-f2eb066abc66', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-18', null, null, '通常 / 射的ゲーム応用の細分化と作成', '射的ゲームの応用で遊んでもらった後、細分化をしました。 個々のスプライトがどういう動きをしているか、ということは理解して書けています。 このくらいのレベルであれば、コードを作成するときにできてしまうのですが、 細分化の際にもう少しスプライト同士の関係を考えて記載することができると後々やりやすいのではないでしょうか。 今回も、コード作成の段階になって、風船が割れるのが弾が当たった時なのか悩んでいました。 ← ゲームを再度プレイしてもらって条件をよく見るよう促したら、関係しているのは的の方だと気づけました。 的の動きを、最初は「上下左右キーが押されたとき」で設定しようとしていたので、 滑らかに動かしたいので…と言いかけたら自主的に直していました。さすがに慣れてきています！ 一通りのスプライトの動きが完成した後、もう一度ゲームをプレイして、他に必要な要素をさがして書き出してもらいました。 3つの変数に気が付いて、初期値などを書き出すことができました。', '次回は変数を入れてゲームの完成を目指します。', '時間帯: その他
タイピング: 41点 正誤率86.364% 中学校では上級レベルとコメントしたら嬉しそうでした
盛り上がり: これまでの検定挑戦が生きているようで、基本的な動きについてはよく理解して自力で作成できています。 スプライト同士の関係も、声掛けをすれば目を向けることができそうでした。'),
  ('94d3c7ed-5cf1-5acf-b9a0-768dc0f39f0a', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, null, '2022-04-11', null, null, '通常', '細分化をしてもらいました。簡潔に、要点だけをまとめて書けていたと思います。 的の動きでつまづきました。座標と秒数をコントロールすることを提案したのですが、気づきにくかったようです。どうしても「y座標のみをなんとかして動かす」という考え方になりがちなようです。乱数はとてもうまく使えていてとても良かったです。 玉の動きは、「⚪︎歩動かす」を使って表現してくれました。見本とは少し違うのですが、本人は動きに納得しているようです。また、撃たないときは銃に行くというのをプログラムできていて素晴らしかったです。', '玉が割れたモーションがないのですが、本人的にこれで良いそうなので難しい方に進めようという話をしました。難しい方に玉の割れた動作は追加していきたいです。', '時間帯: その他
タイピング: 集中して取り組めていました！正答率も80%でした。
盛り上がり: 玉を発射したときに「ボールへ行く」というプログラムを作りそうになってたので、「それだと魔法の銃になっちゃうよね」という話で少し盛り上がりました…'),
  ('f42bebf9-c34f-50ff-8c02-69df9e248133', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-30', '17:30:00', null, '通常 / 追跡ゲームのアレンジ続き', '今日は一緒にゲームを作りましたが、バグっぽい箇所に気がつかない（スタートした後に動きを確認しない）なぁと思いました。おそらくちょっと難しいコードも書けているという自分で自信があるから・・なのかな？と思うのですが、今後、一回一回確認することを定着させていきたいと思います。 学んだことは「かつ」の演算を2回重ねてできる ゲームクリアの制御のとき、演算子と「もし」を正しく使えていました（やまと）', null, 'タイピング: 正答率が以前よりも上がっていました！
盛り上がり: ハリネズミがけがした様子のスプライトにとても凝っていました！いろんな傷の種類があって驚きました。（やまと） 自分が思い描くゲーム世界があって、それをちゃんとコードとして書けているのが大変すばらしい！'),
  ('0d6efa42-b59d-5852-9da4-62592a539c72', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-23', '17:30:00', null, '通常 / 先週の続きー追跡ゲームのおさらいでクラゲゲーム 自分で描いた背景画があるのでそれを使用して最後まで行う まだゲームのクリアが入れられてない', '今日は先週書いた絵を取り込んで、作成の続きを行いました。 やってほしいところは ゲームクリア▶︎変数、条件分岐、待つ、 ここでもう少し自分でアレンジを加えていたのが無敵時間 どこかのキーを押した時に敵に当たってもポイントが減らない▶︎ここをどう作るかですが、わたしも一緒になって考えてみました、 私が考えた案は、 aボタンを押したらプレイヤーからメッセージを敵に送って、１０秒間敵を隠す▶︎のちにもう一度動き出すというコードにしてみました、ここまではおうすけくんがメッセージを送る？ので対応できるかな？と案をくれたので、敵を隠すという感じでコードを作ったらどうだろう？と話してそれを取り入れてもらいました。', '次回完成まで', 'タイピング: その日によってタイピングの精度が変わるものの、概ね同じぐらいのレベルで進んでいると思います。 基本的には本人は嫌がる様子もないのでP研もしくはPlaygramで良いかと思います。
盛り上がり: 自分で色々と自分で考えた案をまとめて、よく集中できていました！'),
  ('aa03f7c6-646d-50d0-b9fe-2974270bf753', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-16', '17:30:00', null, '通常 / 乱数のチュートリアルを見せることと、マウスポインターに向けるのコードを教える▶︎クラゲゲーム', '細分化と乱数をやりながらクラゲゲーム。乱数に関しては知っていたようですが、角度、秒数などをも一緒に乱数にできるんだということを学んでもらって、その後クラゲゲームを見てどこまで細分化できるかをやってもらいました。 ほぼ自力でできているのですが、途中で乱数をどこに入れたらいいのか？を悩んでいる様子。ここのゲームでは〜度向けるの場所に乱数を入れることでゲーム性として面白くなるのですが、もしかするとコードの意味がわかっているものの、どこに入れたら面白くなるというアイディアの蓄積が足りないのかな？と思いました。', null, 'タイピング: 正誤率：97.806% 今日は初めてP検でタイピングを行いました。やはり5分間という長さが割と大変なのかな？
盛り上がり: 自分の中のワールドがある、背景を楽しんで書いていました。'),
  ('6a5d48d2-6a2f-50e6-a473-b70379ab0241', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-09', '17:30:00', null, '通常 / 基本操作コース06のメッセージを送り合うのも踏まえて、基本操作コース04やりたい', '追跡ゲームをまずは一通りやってもらう。 最後のレベルアップの部分で表示の仕方がパターンいくつかあることを伝授 ①まで待つ ②条件分岐 ③メッセージを送る ↑この部分で本人が条件分岐を使いたがる癖があるので、パターンがいくつかあることを覚えてもらって、ゲームによって使い方を分けることを理解してもらうことをしました。 全体的に、スクラッチをやったことがあるためかすぐにできる。ただし1+1=2みたいな考え方をすることがあるので、そこを今後どうもっとやり方はたくさんあるよ〜的なことを伝えてあげられるか？かなと思います。', 'メッセージを送る〜をもう一度おさらいしてからピンポンゲームでもいいのかも？', 'タイピング: 前回よりは少し、スコアは落ちたもの疲れなどもある？ぐらいだと思います。
盛り上がり: メッセージを送り合うを使って何回か背景を変える、ゲームクリアを表示するまでアレンジができました。'),
  ('c8cad369-1947-5dc2-87cd-f07cfdf83f3d', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-04-25', '17:30:00', null, '通常 / 順調に基礎進んでそうなので。続きだねー。03~進んでオリジナル作品まで作成することが目標。そのときに細分化することを目標にすると良いかもです。', '基本操作コース03の続きから。テキストを見ながら、自分の作品として作ってみるということをしてくれました。今回はメッセージを送り合うということがまだ学んでないので背景が〜になったときなどのイベントですべて物語を作るという形にしてもらいました。触れたら〜というコードはまだ使ってないものの、やはりゲームの組み立て方というのが理解しているので次回はメッセージを送り合うという基本操作コース06を一度踏まえて、基本操作コース04をやろうと思います。', '触れたら〜というコードはまだ使ってないものの、やはりゲームの組み立て方というのが理解しているので次回はメッセージを送り合うという基本操作コース06を一度踏まえて、基本操作コース04をやろうと思います。', 'タイピング: 先週よりも得点があがり、98.3▶︎98.4%、タイピングの速さも101秒から93.4秒へアップ。だいぶタイピングにもなれてきているようです。
盛り上がり: 自分がやりたい内容がはっきりしている、またどのコードを使うかが分かっている、完成度にこだわりがあるが、先生にできないところも逐一聞いてくれるので、作品一つ作っても内容が濃いと思います。'),
  ('60f373b0-f760-567b-ac33-513404548b8e', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-04-18', '17:30:00', null, '通常 / 基本操作03 先週の続きの自分の名前の作品をもう少しアレンジしたい。', '基本的な操作はほぼ分かっている、何より「座標」と「〜歩動く」の違いが分かっている。 また頭の中で、「こんな動きがあったら面白いな」やアイディアがたくさんあって、教える方も作品の良さに驚かされる。', '次回は今回の続きから自分の作品作成まで', '盛り上がり: 先週の名前の作品アレンジは、自分がやりたい動きが分かっている（コスチュームがスプライトに触れたら全く違うものになるというコードにしたい）、複製のやり方も分かっている 基本操作コース03の場合は、右と左、上、下の動きの際に向きを入れないと〜整数の数字を入れたときに動いてくれない（スプライトの向きがもともと右だということを分かっている） ストーリー性がある'),
  ('93cb6dbb-5810-5d37-8cea-b92339f477dd', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, null, '2022-04-11', '17:30:00', null, '通常 / 今日からスタート', 'カードと見本の動きを見せると、すぐに「あっ、〇〇使えばいいかも！」と発想がわくので、今後も習得が速そうです。 「ｘ座標〇、y座標〇」＆「１秒待つ」と、「〇秒でｘ座標〇、y座標〇へ行く」の動きの違いを自分で発見していました。特に、「「ｘ座標〇、y座標〇」＆「１秒待つ」はワープしているみたい」と言葉で具体的に表現できるのがすごいです。コミュニケーション能力が高いです。 自分の名前で作品を作りました。「Ｏ」を動かしたら鉄砲に化けて、球が出るというのをやりたがり。早速、今日やった「座標」を使うブロックのアレンジを使っていました。さらに、「Ｏの文字が鉄砲に化ける」というのを「コスチューム」に追加する技を瞬時に思いついていた！', null, 'タイピング: キーボードの位置はかなり把握しているのですが、人差し指１本しか使わないので徐々に改善させたいところです。なのですが、１本指打法で結構慣れているっぽいので、修正が難儀するかもです。
盛り上がり: 「Ｏ」の文字が動いて鉄砲に化ける動きが、今一つ納得いかなかった様子。早すぎるというので「１秒」を「２秒」にしたらイメージ通りだったようで、仕上がった時の顔がとても嬉しそうでした。'),
  ('cab841a1-2775-573f-a122-7311bf7ba899', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-06-06', '17:30:00', null, '通常 / メッセージの名前付け 物語のバグの修正、完成 追跡ゲームprg orピンポンゲーム', 'メッセージの名前が数字だったため、誰が見ても解るように動作の名前に変えるようにしました。最初は少し嫌がっていたが、一緒に考えてやることで、だんだんと乗り気に名前を付けてくれました。ただ、名前を付けのではなく、名前を付けることで次に何をするか一目でわかることを確認してみながらやりました。 クリオネが岩に隠れるときメッセージのやり取りが起こらないバグは、別のメッセージの送った先にずっとのコードが絡んでくると、そちらが優先されてしまうことがありました。その動きを止めてから、メッセージを起こることで解消されました。前回にも似たようなバグがあったのでスムーズに理解できました。 1通り話は完成したので、来週は追跡ゲームprgのやつをやれると思います。', null, 'タイピング: 正答率も少し上がり、スコアも順調に上がっていきました。
盛り上がり: やりたいことをできた時とても喜びました。'),
  ('b85ef771-2386-523c-b709-4fd39fc8885b', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-05-30', '17:30:00', null, '通常 / 物語完成クリオネを岩で隠し、サメを消す 後半はピンポンゲーム', '前回、クリオネが右端から出て左端に出ていくとき、サメの挙動が後ろからついてこないバグを直しにかかりましたl。一緒にヒントを与えつつ理解しながらやりました。クリオネが右端に行ったに送られる「９」のメッセージの座標移動のコードが動かなかったのは、隣のサメの動きのコードが優先されたからでした。なので、一旦、「９」のメッセージのメッセージが送られたとき、ほかのスプライト止めて、再び「８」のメッセージ送ってあげることで解消できました。 クリオネが岩に隠れた時、サメが何度か画面内で循環して、立ち去るようにしたいという工夫はとてもよかったです。しかし、コードづくりは、随時ヒント上げながら、やっていましたが、今日は振り替え休日で1日中遊んでいたらしく、疲れて何度も同じことを確認しようとしていました。お茶を飲んで、リフレッシュして残り少ない時間で手中してくれました。 岩触れたらのコードで発動する動きが触れ終わったときに動き出すバグがあって、次回に持ち越しです。', null, 'タイピング: 途中で教室に入った時のピッをし忘れて電話がかかってきたりして、スコアは伸びませんでした。しかし、指の打つスピードは少しずつ良くなっていきました。
盛り上がり: 前半はとても疲れ切っていて、集中力は切れていましたが、お茶を飲んでリフレッシュできました。'),
  ('862190e7-0244-5600-88ec-cd1d0deadf88', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-05-23', '17:30:00', null, '通常 / 物語完成', 'クリオネが端に行ったら、背景が変わる発想は良かった。変わる条件がどうすればいいか困っていたので、座標に着目してみてと提案したら、そのあとはコードを作れることができました。 サメも時間を置くことで追尾することも自身の工夫でできました。 そのあとは、少しアイデアが枯れ切ってしまったように見えたので、岩にかくれてサメから逃れることを提案しましたが、作るのが難しそうに感じていました。だから、次回は次のピンポンゲームに進んでもいいと思う。', null, 'タイピング: 少しもたついていてスコアが少し下がってしまった。
盛り上がり: だいきくんとカービィの話で盛り上がっていました。'),
  ('f5fa3112-b56c-5554-9472-fe9a84d7b2f8', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-16', '17:30:00', null, '通常 / 自分の声を録音追加、登場人物をクリックした後に色が変化する、BGMを鳴らす、表示、隠す▶︎06物語を終わらせる 07 ピンポンゲームへ進む', 'クリオネが右端に移動した際に消えるように提案したところ、最初にもとに位置に戻ることや、表示させることを教えることなく自ら進んでできていました。 ほかに動きをメッセージを通して作る際に、スムーズにメッセージを使いこなせていたので、今回でメッセージの使い方を理解したと思います。 逃げ遅れたクリオネを自由に動かしたいといいアイディアだったので、もしのコードを使えばできるとヒントを与えたところ、その後手伝うことなくできていました。 クリオネが右端に移動したら、左端から出るようにしたいといっていたので、次回、その際に背景を変えてみるのもいいと思います。 自分で絵を描きたいといっていました。', '海の背景イラスト', 'タイピング: ひとつひとつ指を確認しながらやり、スコアも伸びました。
盛り上がり: 自分の声を録音するときに、少し照れながらも録音してくれました。'),
  ('6ac8b940-c670-56bb-a514-19b665a47c56', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-09', '17:30:00', null, '通常 / 先週はメッセージを送り合うという場所に慣れていなかったため、そこをおさらいした方がいいのか？？ 物語を作ろう', '前回、メッセージの使い方が身についていないようだったので、物語を作った。 まず、何秒待つのコード使って、サメとクリオネの会話を作った。サメとクリオネの会話が重なった時、自分自身で時間差をつけてコードを作ることができた。 1通りの会話を作った際、何秒待つのか考えるのが面倒くさいと言っていたが、メッセージを使って作り直してほしいと頼んだら、自ら進めてできていた。そして、何秒待つのコードを使った後にメッセージのコードを使ったことで、メッセージの便利さを認識できた。 会話の後に、メッセージを使って動きも適応できることが理解できた。 （しもくん）', '次回は自分の声を録音追加、登場人物をクリックした後に色が変化する、表示と隠す▶︎06物語を終わらせる', 'タイピング: 久しぶりのタイピングもあり、スコアは横ばいだった。
盛り上がり: 物語の先の展開も考え付いていたので、楽しくできた。（しもくん） 発想力は前々からよく出てくるので、あとは自分が考えている動きとコードとの対応ができるかどうか？がしゅうくんは鍵になると思う。（青木）'),
  ('06479ec4-fe0d-54a6-8d5b-ad30545c5bf9', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-04-25', '17:30:00', null, '通常 / 乱数を習いたてなので、使い慣れるといいね。 前回、普通のゾンビが10回の1回出てきたら、ゴールデンゾンビ(レインボーゾンビ？名前忘れた)が出てくるを作っていて、混乱して終わってしまった。 あれこれやっていたので、いらないコードが沢山残ってて、余計混乱しちゃったろうなと。 基本、ゴールデンゾンビにコードを書こうとしたから、複雑になってるので。普通のゾンビにコードを入れるというヒントをあげてみて。', '乱数を使って緑のゾンビとゴールデンゾンビが入れ替わり出てくる仕組みを作ろうとしました。 最初、自分が作り上げたものを見せてあげたら、とても喜んでくれて、やる気はずっと高かったです。。 スコアが１０になるまでゴールデンゾンビが出てきて欲しくないそうだったので、そのコードを考えてもらいました。少しヒント与えながらも、不具合も自分で直せていました。 ゾンビの入れ替わりの乱数の仕組みをメッセージを使って場合分ける方法を提案しました。だが、メッセージを使ってほかのスプライトを動かすことが慣れてなく、理解するのに時間がかかりました。 緑のゾンビもメッセージを使って動かすように根本的に変えようとしましたが、同様に慣れてなく、重なって出てきたり、逆に表示されなかったたり、時間がかかり終わりませんでした。 ゴールデンゾンビのとき、コインのスコアを大きくしたいといっていました。', null, 'タイピング: 前回よりもスコアがよくなって、正答率もよくなっていた。
盛り上がり: 来てからずっと集中が途切れることがなく取り組んでいました。'),
  ('ce57a6e9-8e7d-5038-856b-886f9267fe13', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-18', '17:30:00', null, '通常 / 座標のコントロールと制御処理の定着のため、ジャンピングゲームの応用に取り組む アレンジポイントの課題が難しければ、スプライトの変更や障害物の仕様などのアイディアを出してもらい、「自分でゲームを作れた」という成功体験を目指す', '作りたいアレンジの仕様が決まっていたので、そのためにどういう動きを作ればよいかを一緒に考えながら取り組みました。 せまってくる障害物（ゾンビ）の上にコインを表示して一緒に動くようにするところで、コインがゾンビに向かっていってしまうのを、ゾンビの頭上を平行移動させるにはどうすればいいのか問いかけたところ、自分で考えて解決できました。 アルくんがジャンプする際にゾンビに触れてしまって得点がマイナスになるのを解決するにはどうすればいいか、考えてもらいました。アルくんのサイズを調整すること、ジャンプしたときに滞空時間を作ることで対応できました！ 効果音もこだわりを持って設定していました。 演算式で不等号を使って条件分岐をする方法を覚えました。 やりたいことが自分の頭の中あるので、まだ習っていないコードを使いたい▶︎乱数のチュートリアルを見せて、ランダムに動くには乱数のコードを使って〜秒待つを入れたりするとできることを学んでもらいました。 確率を出して、10回に1回スプライト１が出てくる、という細かな設定までが考えられる', null, 'タイピング: タイピング自体はまずまずといったところ、長文&時間が長すぎるとやや疲れるようでタイプの速さは遅くなる。それでも4年性にしては打てている方だと思います。（青木）
盛り上がり: やりたいことに対し、労力を惜しまないでチャレンジしようという姿勢がよいですね。'),
  ('f9a7184c-59eb-51db-9bbc-a624086dd255', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-04-11', '17:30:00', null, '通常 / 〇追跡ゲームをアレンジも含めて終わっている様子なので、次のステップだね。MTGで様子を確認してから 前々回にナホ先生が「来週はドリルをやろう」と書いていたので、そのあたりも含め。 ジャンプゲームをやる', 'ジャンプに少しつまづいているようでしたが、自分でいろいろと試した末に成功させていました！マイナスとプラスを読み間違えて混乱しているときもあったようなので、注意力も大事にしていきたいです。 このゲームを行うときにやったことがある！と話していたので、最初に自分でできるところまでやってみて〜と話してみました。ただし、〜回繰り返すというコードを使いながらジャンプに見せる動きというのはやったことがなかったみたいなので、最初に座標の原理をおさらい。上に行くと整数、下に行くとマイナスをつける数というのを理解してもらって、ジャンプというコードを完成させました。 卵が右から左に流れる際、数字の文字をカナの数字で打ってしまったため、しばらくコードが反応しないという問題になり、私も焦りましたが半角数字にすることを、しゅうくんも学んでくれたみたいなので、動かない時は文字を疑ってみるという学びにもなったのではないでしょうか？ 基本的には、卵が移動する単元は前の単元でやっていたことと同じと理解していた様子で、コードは最初からかけているので今までの授業が身についている様子🤗（青木）', '今回気になったのが連続してスペースキーを押してしまうとひよこが無限にジャンプ&上に行ってしまう問題 しゅうくんはキーを連打する性格なので、「なんで、これ無限にいってしまうの？」という質問をしてくれました ▶︎〜ではないを教えた方がいいか・・・（青木）', 'タイピング: 難しそう こどもタイピングに関しては、ある程度自分でできるという自信はあるものの、b、dが間違えたりと少し不安な箇所が見受けられる（本人も気がついている）ただこのあたりは時間の問題のため、もう少し時間をかけて見守る
盛り上がり: アレンジは卵に当たったら1点減点にする たまごとひよこに触れたら〜の条件分岐をどちらに書いたらいいか？が理解できている（青木）'),
  ('6b9353ce-a91c-5ad1-a765-936c813ce726', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-30', '16:30:00', null, '通常 / 前回の続き、宇宙の作品', 'コスチュームを変えたいとのこと！コードを忘れていたようですが、「見た目だったよね」と声をかけると思い出してくれたようです。コードを読んで自分で選べていたのも良かったです。 歩かせ方に悩んでいました。「端についたときに戻ってきてほしいから『ずっと』は使いたくない」とのことだったので、「〇回」を使うことを提案しました。 繰り返し実行するブロックを使うと、コスチュームを見せるための時間をいれるのを忘れてしまうようです。 初期位置の設定を提案しました。「〇秒で～へ移動する」を使う機会が多く、「座標～へ移動する」のブロックの存在を忘れてしまっていたようです。 「背景が～になったら」のブロックの存在も伝えました。 来週もう1場面作るそうです。本人は「次回で完成かな」と言っていました。', null, 'タイピング: 指の位置を守って丁寧にタイピングをしてくれていました。
盛り上がり: 自分の中でのストーリーや。リアリティに対するこだわりが しっかり感じられました。 ふくせいの仕方を教えました!たのしそうでした！'),
  ('dcdaefd0-52ae-5cc8-b4b0-00fcc7c56ba0', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-23', '16:30:00', null, '通常 / 次回基本操作コース03', '今日は教科書が全部終わりました、理解はとてもしている感じなのでこのまま自分の作品を作ってもらうことにしました。テーマは宇宙にして今日習ったことを使用して最後30 分は自分の作品の時間に当てました。', null, 'タイピング: 先週の引き続きでFGHJのおさらいをやってもらって、合格していました！
盛り上がり: 自分の作品を作成している時に、悩みながらも自分でストーリーを考えて作成していました！とても集中していたので次回も引き続き同じように行ってもらって発表まで行けたらいいかなと思います。'),
  ('03083d01-5891-5282-98e8-406e979f7f29', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-16', '16:30:00', null, '通常 / 基本操作コース02 名前の作品を作る', 'すべての文字を左から右へ移動し跳ね返るように見せたかった様子。最初は先週やったことを忘れていたみたいですが、やっていくうちに思い出した様子でした。理解をしているように見えてもまだ３年生なので覚えることが慣れていない様子です。間違っててもあまりへこたれる感じの子ではないので、笑いながら一緒にやってあげると伸びる感じかな？と思います。次回基本操作コース03', null, 'タイピング: FGHJのおさらいまで進む、ただし、GHが混乱するよう。まだ大文字と小文字の違いに慣れてない様子なので、少しずつアルファベットの理解からやらせてあげるのがBetter'),
  ('2619e462-39e2-5a2d-ba8b-58164bc8b457', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-05-09', '16:30:00', null, '通常 / 今日は初めての日なのでまずは、パソコンになれることと全体の流れを掴むこと 基本操作コース02 最後までやりきる', 'PC操作に慣れてない&スクラッチはやったことがないと本人は話していましたが、そうでもなくちゃんと向きや座標のこと、マイナスと正数のことを理解していたようでした。 名前を動かすを全て終了しましたが、どこまで理解をできてるか？は自分の作品を作成始めたので、そこで確認できればいいかなと思います。', '自分の作品を作成するの続き', '盛り上がり: 向きの話をした時に、上下左右の向きをちゃんと覚えてすぐ使えていました！'),
  ('ad3803c0-1dde-5531-bcef-1905788c7077', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-06-06', '16:30:00', null, '通常', '射的ゲームの応用はほとんど終わっていたので、ゲーム中にきらびやかな音が億をつけて完成しました。 そのあとは、大会作品の作成をしました。スタートのボタンを触れると、小さくなったり、ゲーム説明のチュートリアルを入れてゲームの進行がわかりやすく工夫されていました。 ウミガメを貝を放つコードに射的ゲームの銃を撃つコードが使ったり、打ちたい方向にスプライトの向きが合わないとき、コスチュームから絵の向きを変えたり、射的ゲームの応用で学んだことが活かされていました。', null, 'タイピング: キーボードを見ながらですが、得点も上がり生徒率は95%以上でした。
盛り上がり: ウミガメのゲームの背景がしっかり作りもまれていてすごかった。'),
  ('3c001097-5d98-57d1-81ff-af3d7c693584', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-06-02', '16:30:00', null, '振替え / 射的ゲームの応用 スコア コンテストの全体構想を聞く。作り込むかも？', '「ゲット」の文字表示プログラムがうまくいっていなかったので、書き直しました。「色を変える」で表現していましたが、うまい制御方法が考えられなかったようです。こちらからスプライトの見た目を交互に変えることで色が変わっている様子を表現できないか、提案しました。プログラムは自分で書いてくれました！ 背景の手直しをしました！お気に入りの色がどうやらあるようです。スコアの入力もしました。正確に書けていました。 後半は、大会に向けて作成中のゲームに取り掛かりました。大がかりなものになるので、クイズやミニゲームなど項目に分けてプログラムをするそうです。色合いが素敵でした。 長いプログラムを書くときのコツを伝えました。（コメントを使う、並列にして動き・見た目・音で項目を分ける） 写真を使いたい箇所があるようだったので、写真サイトを紹介しました（unsplash）。', null, 'タイピング: 省略
盛り上がり: 集中して取り組めたのでとても良かったです！ 色の調整にこだわりがあるようです！'),
  ('fc246f9d-c469-5676-bced-b2150da45e97', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-24', '16:30:00', null, '通常 / コンテスト作品続き モグラが弾に当たった時の動作作成など', 'すべてのモグラのコードを作成して、ゲームの雰囲気がわかるようになりました。 体力が0になったとき、一定時間農夫の動きが止まるコードを「スプライトの他のスクリプトを止める」で指定していたため、停止時間が過ぎても左右に動けなくなるバグについて、解決法を考えました。 メッセージの送受信を使うことにより、解決できました。', 'ラスボスのクマが消える動きと得点の調整、ゲームの説明画面を作成予定', '盛り上がり: モグラと農夫の動きの課題が解決できたことが嬉しそうでした。 イベントの使い分けについて、理解が進んだのではないかと思われます。
備考: 備考への反映テスト'),
  ('89ad3f03-b6f3-567c-94be-2536461f671e', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-05-23', '16:30:00', null, '通常 / 射的ゲームの応用細分化から続き 最後、当たった後の動きまで完成させる', '先週に続き、射的ゲームの応用の作成をしていきました。銃の向きを照準の動きに合わせて動かすコードはできていました。しかし、銃口が照準に向いていなかったので、試行錯誤していました。コスチュームの向きを変えてみるといいとヒントを与えたら、解消しました。 球が発射するコードでは、銃のxy座標から発射するようにしていましたが、向きを変えた時にはみ出してしまうことがありました。ほかの方法で試してみてといったら、「銃へ行く」を使って正しく起動しました。 そのほかは順調に進み、あとは風船のエフェクトとスコアをつければ、元のゲームに近づくので、次回はアレンジも行えそう。', null, 'タイピング: ときどき、手元を見ずに打てていました。'),
  ('17b00009-ab2e-5625-8b15-c6d2c08417a1', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-05-16', '16:30:00', null, '通常 / 子分が親分にメッセージを送る際に、「親分はつよいぞ」▶︎親分が出てこないといけない 親分が５秒待ってから表示にしないとだめなのか？検証したのち応用の射的に進んで欲しい。', '子分がやられてボスに代わる際に、セリフが表示されないバグは、子分のセリフの時間を調節することで、自力で解消できました。 ボスに星が当たった際に音が鳴るようになるなどの細かい修正をして完成しました。 次に、射的ゲームの応用編の細分化を行いました。不足なくスムーズに細分化をできました。 銃の標準を矢印キーで動かすコードでは、最初にイベントのキーが使ってぎこちない動きになっていました。もう一つの方法のコードに変えてほしいと頼んだところ、少し悩みましたがもしを使ってできました。 ほかのコードは順調に組み立てができているので、このまま進めてもらいたいです。', null, 'タイピング: 遅れてきたため、飛ばしました。
盛り上がり: ターゲットがぴえんの絵文字みたいのものでかわいかったです。'),
  ('8b1b15fc-2328-5e5a-a3a7-5cb9a72ccede', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-14', '17:30:00', null, '通常 / 検定チャレンジ または コンテスト', 'しっかりと検定問題に取り組むことができていました。', '検定問題の答え合わせを一緒にして復習をする予定です。', '盛り上がり: こちらの予想以上に集中できていました'),
  ('96e68201-e84a-50d0-9cd0-680904b7e5f6', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-07', '17:30:00', null, '通常 / 基本操作コース09 ジャンピングゲーム 06 障害物を追加しよう 2週間あいたので、振り返りをしてから ジャンピングゲームアレンジ', '基本操作コース09 ジャンピングゲーム 06 障害物を追加しよう 自己アレンジで、一定の得点になったら犬のスプライトを出したい、とのことだったので、ピンポンゲームの「～まで待つ」を復習して自分で作成してもらいました。 これ以上のアレンジや応用は今はやりたくない、教材をどんどん先に進めたいとの希望で、次の単元に進みました。 使用ツール：基本操作コース10 キャッチゲーム ゲームをプレイしてもらい、どういうゲームかの説明をしてもらいました。ほとんど身振り手振りでしたが、把握はできているようでした。 座標を「～にする」と「～ずつ変える」の使い分けが曖昧で、りんごが瞬間移動したりしていました。説明を聞いて納得はしたようですが、何度か復習した方が良いかもしれません。 スプライトが上端にくるためにはy座標がこのくらい、落ちてくるということはy座標をマイナスにする、などということは、口頭では自分から言えているのですが、それをブロックにするときに上記の使い分けを間違えたり、ブロックの数値にマイナスを付け忘れたりして、それを自分では気づけないことがありました。 キャッチした時の音をスプライトによって変えたりと、音に関するところは熱心に作成していました。', '検定の準備をしてみる予定です。', 'タイピング: 少し遅れてきたので、1度だけチャレンジしました。
盛り上がり: 課題を早く片付けたい意識が強かったようで、「次なにやりますか？！」とくいついてきてくれました。 これまでの学習から、こういう動きのときはどのようなコードを書く、というところまではだいぶ理解できているようです。似たようなブロックの違いや使い分けがもう少し明確になると、ぐっと伸びると思われます。 基本操作コースが、応用を除いて一通り終わったことに自分で驚いていました。'),
  ('f0551866-04e1-5b9f-965e-28d3801e4677', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-24', '17:30:00', null, '通常 / 基本操作コース08 さあ踊ろう_07インタラクティブなダンス～ ダンスのオリジナル作品 または 基本操作コース09 ジャンピングゲーム', '矢印キーでコスチュームを変えたり、背景の色を変えたりするところは、「前にやろうとしたけど面倒だったところかもしれない」などと言いながら、自分で記憶をたどって完成させることができました。 スタンプはゆき先生ご指導 ジャンピングゲームの作成に入りました。障害物が通過していくのではなく、端までいったら跳ね返るように設定し、それに伴ってプレイヤーキャラクターの大きさや滞空時間を調整しました。 基本操作コース09 ジャンピングゲーム06以外完成しました。', '06 障害物を追加しようだけ要確認', 'タイピング: 新記録チャレンジをがんばっていました！ アルファベット全打ち4秒台が出せました。
盛り上がり: ジャンピングゲームでは、障害物の動きの変更に伴ったオリジナルの工夫が見られました！ 口ではネガティブなことを言っていても、基本的に楽しそうに取り組めていました。 みずきくんの作品をのぞいて感想やアイディアを言ったりしていました。'),
  ('72197e38-aee6-51bb-98ea-68756b7a01b5', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-06-23', '17:30:00', null, '通常 / コンテストの作品作成', '最初、別にアイデアを思い付いたといって、銃の打つ動きを向きもイラスト自体の向きを直して、すむーむに作っていました。その動きが先週まで作っていたマイクラのやつで弓矢の動きに活かせそうと提案したところ、取り入れてくれました。 全体の構想がふわっとしていたので、コンテストのことに触れるとアイデアが出てきたので、紙に書いて次のように立てました。最初のステージでは矢が飛んできて避けて、次のステージはゾンビが向かってきて剣で倒していく構想になりました。 今回は、矢のイラストを描いて、ゾンビの動きのコードを作りました。ゾンビがスティーブを追いかけるという動きにしたくて、どのコードを使えばいいかわからなかったので、画面内にあると誘導した挙げた所、自力で「どこかへ行く」のコードを変更してできました。', '矢のステージを作っていけたらいいと思う。体力性も付けた良くなる', 'タイピング: 一つ一つスコアを維持しました。
盛り上がり: コンテストに話になると、やる気がわいてきてよかったです。 イラストを描いて缶バッチを売るのも楽しいにしていた。'),
  ('b2128f60-3f8a-5aa1-b3ce-128cc22e19e7', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '5cfbd637-17cd-5e1f-9521-1dae0dcfd527', '2022-05-17', '17:30:00', null, '通常 / 「さあ踊ろう」で表現できる動作の種類を増やす', 'もんく（乱数）なぜかうまく動いていた。本人に乱数は「かず」しかだせないことを説明しました。自分で言葉にして納得できていました。 01:先ほど説明した乱数を使って、コスチュームが変わるようにしてくれました。説明した内容がよく理解できていることが分かりました。スムーズに終わりました。 02＆03:コスチュームを変えたあとに「コスチュームを見せるための時間」をプログラムし忘れてしまうことが多かったです。また、「ずっと」を使うときにどこからどこまでが「ずっと」の範囲の中にあるのかを意識できていない場面も少しありました。こちらから間違っていそうな部分を示すと、うまくいっていない原因が自分で発見はできていたので良かったです。 04＆05:メッセージの機能の紹介をしました。初めて使ったようです。こちらの説明を自分の言葉で言い換えて分かりやすくすることができていたのでとても良かったです。理解して使えていました。 06:「明るさ」の効果を使うのは初めてだったようです。値をマイナスにしたりプラスにしたり試せていました。 06まで終わりました。', null, 'タイピング: ホームポジションが意識できていて、ミスも少なくスピードも速いので素晴らしいと思います。
盛り上がり: オリジナルでスプライトを選んで楽しんでいました！'),
  ('27d557e8-d369-5fb2-9542-bdc77021fab6', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-10', '17:30:00', null, '通常 / 乱数の復習、ピンポンゲーム完成めざす', 'ゲームの仕様についてはしっかり把握できていて、「赤い線にボールがきたらゲームをストップしたい」などと言葉で説明することができていました。 新しいことをしようとするとすぐに「ブロック定義」を作成しようとする癖があり、変数作成の際、ゲームクリアのスプライトを作る際もブロック定義作成をひとまずストップさせ、今作りたいのはどういうものなのか、考えてもらう時間が必要でした。 落ち着いて考えると、本人も「ああ、こっちか」という感じで軌道修正ができていました。 「スコアを0にする」「スコアを1ずつ変える」「変数スコアを表示する」の違いが曖昧だったので説明しました。その場では理解したようですが、何度か復習して慣れてもらえると良いかと…。 ピンポンゲーム完成後、20分弱時間が余りましたが、本人が自由作成を希望したので「もんく」という作品作成を見守り？ました。 コスチュームが毎回変わったら楽しそうなので、先週習った乱数を使いたい、という意欲はありましたが、コスチューム名を変えることなくそのまま乱数で指定したのでアイディアが実行できていませんでした。今日は「好きにしたい」とのことで指摘ができたなかったので、また機会を見て説明出来たらと思います。', null, 'タイピング: いずれもよくできていました！結果を嬉しそうに見せてくれました。
盛り上がり: 「面倒くさい」「やらなくていい」と言いつつも、少し雑談をしてから水を向けると「やっぱりやる」と乗ってきてくれることの繰り返しでした。取り組んでいるときは眞子ちゃんなりによく考えて、「ずっと」ブロックが抜けていることに気付いたり、演算式のブロックを自分で探そうとしたりと、既習の内容を活かそうとする態度が見られました。 みずきくんの作成していた追跡ゲームを何度ものぞいて感想を言ったりしていました。一緒に作成してみるのも良い刺激になりそうです。
備考: 先週、バイオリンの発表会があったそうです。at南大沢文化会館 今弾いているザイツの曲は「面倒」であまりお気に入りではなさそうでしたが、こちらが「ザイツのバイオリン曲はかっこよくて好き」と言ってみると、ちょっと嬉しそうでした。今やっている新曲（A-Mollの曲らしい…）を頑張る、とのことでした。'),
  ('049c96e7-88e0-56d2-b1d6-0a8edb1b8ca4', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-06-23', '17:30:00', null, '通常', 'オリジナルでゲームを作っていました。 自分で一度プログラムを実行して修正するということが出来ていました。「もし」の使い方が良かったです。途中セリフの入力も、自分でローマ字表を持ってきて取り組むことができていました。 スプライトを端で跳ね返すときに、ランダムに返すことを提案しました。ピンポンゲームにある跳ね返りのプログラムを見せ、自分で取り組んでもらいました。いつも使っているブロックを客観的に確認できた様子だったので良かったです。 最後はウノで遊んでいました！次回コードを確認してみたいです。', null, '盛り上がり: ウノで集中して遊んでいました。'),
  ('c196e3e5-7134-5fc2-abdd-0d4a03fe702c', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-23', '17:30:00', null, '通常 / コンテスト用オリジナル作品作成', '人生ゲームのマス目のイベントを20考えました。 職業、お給料、所持金、家族を設定することにして、内容を職業図鑑で調べて決定しました。 職業選択のサイコロを作成しました。 リストの作り方を学習しました。', '変更したスプライトでのオープニングとリストの作成、職業等の変数作成あたりを進める予定です。', '盛り上がり: 通常のサイコロをアレンジして、職業選択のサイコロを自作していました。良いアイデアだと思います！ 人生ゲームに参加するスプライトを変えたいとのことで、オープニングから作りなおしたいそうです。時間はかかりますが、だいぶゲームのイメージができたようでした。
備考: 家でも作成したいとのことで、Scratchでアルスパークから書き出したゲームを読み込み、ログインの方法を教えました。IDとパスワードの取り扱いについて注意をしました。'),
  ('aba71f6c-f81e-520c-89ae-1777a255e049', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-06-23', '17:30:00', null, '通常 / スケジュールを意識する。作成中のプログラムを先に進める。', 'ステージは5面まで作り、時間があれば8bitで絵を描いていれてみたいそうです。 前回作ったキャラクターがダウンするプログラムを編集したり、クローンをする時間を微調整したりしました。スケジュールが短いことを伝えました。ゲームオーバー画面をピクセル文字を使って作成していました。出現させるタイミングがばっちりでした。3面までは自分の納得いく出来になったようです。 時間が短いことに危機感があるようでした。自分のパソコンでログインできたので、家でも少し進めたいそうです。困ったときはメモして再来週に持ってくるように伝えました。 また、本人の教室アカウントを個人で使っているパソコンの方に動かしました。過去に作ったプログラムはファイルに保存してあることを自分で把握できていたので、移植は本人に任せました。', null, 'タイピング: 集中して取り組めていたのでよかったです。プラスを目指したいそうです。
盛り上がり: よく話して積極的にプログラミングできていました！ 学校用のパソコンが壊れている（tが打てない）そうです。ゆきちゃんから修理に出すように言われていました。'),
  ('96daa943-3917-5f9b-ba1c-44746df079c3', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-23', '16:30:00', null, '通常 / コンテスト作品の作成', '座標とメッセージ、乱数秒待つをうまく使って、魚がランダムに左右からジャンプしてくるコードを作成できました。 最背面と最前面の意味を学習して使いこなせるようになりました。 つりざおのスプライトを自作して、ゲームが開始したら表示されるように設定しました。', 'つりざおを動かせるようにして、魚が釣れるように作成する予定です。 もしできれば、魚の登場をだんだん速くしていきたいそうです。', 'タイピング: こだまの森 上段 家で練習してきたそうで、よくうてています。 QやPを中指でうつ癖があるので、徐々になおしていければ… ただ手が小さいので、今はそこまで厳しくしなくても良いかもしれないです。
盛り上がり: 魚の登場をランダムにできたことがとても嬉しそうでした！ タイピングもプログラミングも、学習したことはきちんと使えるようにななっています！
備考: 家でもココアタイピングに挑戦しているそうです。'),
  ('88935300-4525-5988-8421-814c7f79ebfc', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-06-23', '16:30:00', null, '通常 / 作成中のプログラムを進める。 ルール説明を作りたい ドアが動いてても乗れちゃう現象もできれば改善したい', 'スケジュールの話と、こちらからのリクエスト（ゲーム説明を入れる＆乗客のムーブを再考してほしい）を伝えました。 初めに。ゲーム説明をプログラムしました。スタートを「旗がおされたとき」にしていたので、メッセージが新たに必要になりました。ゲーム説明の消え方は幽霊の効果を使って、面白く工夫していました。とても見やすい説明画面になりました。 開閉の動作が表示されるように変数に言葉をいれていました！ かなり前に伝えたことですが、変数での制御をステージのコードの部分にプログラムできていてとても良かったです。 得点が最後に減ってしまう問題があったので、一緒に確認しました。影響を与えていそうな怪しいコード（人間が電車に当たってしまうと得点が減る仕様）を見つけてくれたので、変更を加えました。自分が作ったプログラムの全貌をきちんと把握できていることが分かりました。点数も減ってしまうことがなくなったので良かったです。', null, 'タイピング: ミス率5％でタイプ速度もかなり大きかったです。
盛り上がり: 楽しそうにプログラミングしていたので良かったです！！会話に参加してくれる機会も増えました！！'),
  ('5b870dce-ea17-5a0b-81c4-93c9a2d5b394', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-05-09', '16:30:00', null, '通常 / 星にあたった時の子分の変数が上手く機能しないコードを修正。 おわったら、射的の応用編へ進む。', '星が子分にあたった際に変数が起動しないバグを一緒に解消してあげました。はるちゃんが一人で考えていても、なかなか解消されなかったので、教えてあげました。原因としては子分の動きのコードの後に星が当たったらの条件文が直列につながっていたので、上手く機能しなかった。解消法として、動きのコードと条件文のコードを別々にしたことでできた。はるちゃんのこの考え方は納得できていたので、次からは大丈夫と思う。このバグは、誰もが陥りやすいので種類ごとにコードを分けるようにした方がいい。 次に、子分の体力が正常に減らないバグも発生した。これは、はるちゃんに追跡ゲームを見せながら、時間がかかったが解消することができた。 残りとして、子分からボスに代わるとき、子分のセリフなしに代わってしまうので、次にはそこを直したい。', null, 'タイピング: 先々週と同じくらいスコアでした。正答率は少し高かった。
盛り上がり: 子分の体力が減らないバグが解消されて、集中力が戻った気がします。'),
  ('3a113eae-9d83-5346-927f-70259981d09b', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-04-25', '16:30:00', null, '通常 / 先週、次回の予定で↓↓以下に書かれているので。子分作るのでよいと思う。 射的ゲーム応用を今回の作品と同じ世界観でアレンジして、ボスの子分たちがたくさん出てくる射的ゲームにしたいそうです。 誰かのノートに、細分化の際にスプライトの連携が書きにくいとあったので。連携を細分化シートに書き込める用のシート、イメージあるので作って共有します。ハルちゃん、細分化がうまくできてきたので。今後は連携も細分化で整理した方がいいかもなので。今日でなくていいので、どっかで連携も細分化に加えるようにしていこう！', '射的ゲーム（初級）アレンジ 子分を先に出してから、ボスを登場させるというアレンジ 先に私がどのポイントなのか？を自分がコードを書きながらやってみて、書いてみて、それを元に考えてもらいました。例）たとえば子分がどのタイミングで出るのか？など私が疑問に思った点などです はるちゃんが描きたかったのは子分が先にでて、その後ボスが出るという状態にしたかったようで途中まではうまく作動していました。 問題は、子分が星に当たると変数がうまく作動しないという点。 もしかすると、ずっとやコードを入れている位置も関係しているかな？と一緒に途中までみたのですが、最後まで変数がうまくいかず・・ちょっと疲れている様子だったのもあるし、残り時間もそこまでなかったので息抜きにそういう時は違うゲームをしてからもう一度見返すといいかもね、と話して終わりました。 でも全体的にはメッセージをどの部分で変わるなど自分で使うコードが理解できているので、GWもう一度見返してもいいし、射的の応用をやってみてもいいかなと思っています。', null, 'タイピング: 4級を維持、特段問題はなさそうなのでこのままタイピングの速さが早くなってくれるといいかなと思います。
盛り上がり: 子分、親分を登場させる、自分の中でのストーリーがきちんとゲームで描けているのが素晴らしい！'),
  ('40281f33-4d14-50ad-ab7c-da5812ed38b3', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-18', '16:30:00', null, '通常 / 先週の射的ゲームの玉の動きを完成させる ～の方へ向かう動きを確実に定着させるために、検定4級の「かえるの花びらのり」にチャレンジするか、射的ゲームの応用にチャレンジするかをゲームを見せて本人に決めさせる。', '：魔法の杖から発射される弾のコードを作りました。 コードがうまく動かないときに、自分で見直して修正することがほぼできていました。 （「ずっと」の入れ忘れやスクリプトを止める位置の不具合など） 作りたい動きがうまくいかなかったときの切り替えが早いです。最初に考えたコードに固執せず、指定するスプライトを変えたり、同様の動きを違う方向からのアプローチに作りなおすことができました。 弾が当たった時のボスキャラスプライトの動きや、ゲームクリア、ゲームオーバーの動きなどを楽しんで作成していました。', '射的ゲーム応用を今回の作品と同じ世界観でアレンジして、ボスの子分たちがたくさん出てくる射的ゲームにしたいそうです。', 'タイピング: 順調に4級相当の記録が出せています！
盛り上がり: 変数のスライダー表示に喜んでいました。 ボスゆうれいのコスチュームをアレンジして、はるなちゃんのイメージする世界に近づけることができていました。 ゆうれいに弾が当たったら点滅するという動きを試行錯誤しながら自分で作ることができました！'),
  ('ebcd4df6-f269-593a-8279-145075b5dbc2', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-06-06', '17:30:00', null, '通常 / 本人は「完成」と思っているようですが、前後に何かストーリーをつくったり、ボタンが出てくる場所をランダムにしたりなど、こちらから提案していきたいです。 もうひとつ、変数を使って、タイムを区切るのと、途中で質問してゼルダの冒険みたいな、質問をする場所があるといいのかも→リストを使う チュートリアルを見せる', 'スラボーが終了後も動いてしまっていたので修正しました。「すべてを止める」を複数個所にいれてもらうことで解決できました。自分でもあまり気に入っていない挙動だったようです。 クリア画面になったときに、スラボーを非表示にしてくれました。すべて自分で取り組めていたのでよかったです。 新しいステージを作ってもらうことを提案しましたが、あまり乗り気ではなかったようです。 来週は、〇作品に時間制限を付ける（逃走中風にする）、または〇テストに挑戦することになりました。 今日は集中力が途切れてしまっていたので、主人公の男の子に合わせてスラボーをスプライト化してもらいました。', '来週は、〇作品に時間制限を設ける または 〇検定の問題に挑戦する を予告しました。', 'タイピング: 上位20%でした。集中して取り組めていました。
盛り上がり: 絵を描くのは苦手との自己申告がありましたが、とても楽しく描けていました。'),
  ('4ebf8635-5b99-5a5c-bbea-3a841c09086f', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2022-05-23', '17:30:00', null, '通常 / 先週分は終了し終えている感じなのでコンテストの準備 神経衰弱のゲーム見せる、 まいくらっぽいゲームを作る', 'ドット絵に興味をもってくれたようです。まいくら風ゲームではなく、ドット絵を使ったゲームを作ることになりました。 ドット絵を使うとは決めたものの、詳しいゲームの内容までは希望はとくにありませんでした。 自分で迷路を作って、逃げるゲームにするようです。 直線をかく機能を使って工夫して面白い道を書いてくれました。 今日はコース設営・スプライトの操作まで終わりました。 ゲームの詳しい内容はまた考えてくるようにお願いしました。', null, 'タイピング: 集中してとりくんでくれました！ホームポジションも綺麗でタイピングも速かったです！
盛り上がり: 男の子のスプライトを見て「女の子もあればいいのに」と言っていました。 えにしくんのスプライトにリボンを描き足してあげてました！'),
  ('6ca9dc4c-c9b0-58af-a6a3-6ff53ad4a879', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, null, '2022-05-16', '17:30:00', null, '休み', null, null, null),
  ('9084505f-85c4-5004-9248-e2c9dc0b2f3f', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-05-09', '17:30:00', null, '通常 / フリーで選んでもらう▶︎細分化', 'ゲームの操作に困っているようでしたが、すぐに慣れたようです。 細分化も分かりやすく、細部まで書かれていました。素晴らしかったです。 ほとんど声をかけませんでした。ゲームの骨組みからプログラムができていた点もとても良かったです。 最後、「壁に当たったらとまる」の部分で少し困っているようでした。「1回で2歩進むよね」とアドバイスすると、すぐに思い出してくれました！', null, 'タイピング: ミスタイプ率3%と確実に出来ていました！姿勢もよかったです！
盛り上がり: 集中して取り組めていました。素晴らしかったです。 細分化もプログラミングも楽しそうでした。'),
  ('36dab403-72bd-5bae-88fc-0f4156b52c5f', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, null, '2022-04-25', '17:30:00', null, '通常 / 繰り返しや条件分岐の中に入れるブロックが整理しきれていないようなので、細分化の導入として、「繰り返したい動作」「条件にあてはまったときに実行したい動作」を書き出して考えさせてみてもよいかと思います 「すべてを止める」ブロックの位置がおかしいためゲームが動かなくなっているので、次回は上記の書き出しから始めて見直しをし、スコアの作成に取りかかりたいところです。', '弾をまっすぐ進めて、ピストルに戻る動作をプログラムしました。 まっすぐ進めるために「りんご」をピストルとy座標が同じように動くようにプログラムし、「りんごへ行く」を使って弾の動きを作ってくれました。 上のアイデアはとても斬新で面白かったのですが、撃った後にピストルを動かすと（りんごも動いてしまうため）弾が斜めに動いてしまい、納得のいく仕上がりになりませんでした。 そこで、「猫を歩かすように弾を動かそう」ということで、「歩く」を使いました。 しかし、プログラムがごちゃごちゃして見にくくなってしまったので、「弾の基本動作」と「弾がモノに当たったときの動作」とで分けてもらいました。本人も頭の中が少し整理されたようです。 弾が壊れる動作をしてほしいとリクエストしたのですが、あまり乗り気ではなかったのでやりませんでした。これにて完成です。', null, 'タイピング: ホームポジションもしっかりしていて素晴らしかったです！姿勢も良かった。タイピング速度も速いです。
盛り上がり: 細かい弾の動きまで注目してこだわっていて良かったです！！'),
  ('485a5f05-66e9-5b99-a781-e3e068cdbe48', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-17', '18:40:00', null, '通常 / 検定2級問題の振り返り', '・前回のファイルを開いて、意図した通りにいかなかった箇所を確認してから、問題文を1行ずつ一緒に見て、作成したコードを説明してもらいました。 ・一緒に見ていくことで余裕ができたのか、ネストで間違っていたところも少しのヒントで解決することができていました。 ・落ち着いて問題文をしっかり読めば、ほぼ自力でできることがわかったのか、最後までよく考えて取り組みことができていました。達成感も感じられたのではないかと思われます。', null, '盛り上がり: ・前回、途中でうまくいかなくなって適当にコードをいじりだしたのとは打って変わって、今日は最後までじっくりと考えることができていました！ ・なんとなくできてしまうことが多いゆまちゃんなので、勢いで作成してあとから見直すのが面倒になり、集中力が切れることがあるようです。「なんとなくこんな感じだったはず」で先走らず、問題文を落ち着いて丁寧に読めば、それをブロックに置きかえることはよくできているので、検定も大丈夫ではないかと…。 ・久しぶりにがっつりとコードと向き合って充実感が得られたのか、終わった後はすっきりとした感じで自由作成していました。'),
  ('88af1d3b-026a-5ee9-91dd-b10a53d97aee', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-17', '17:30:00', null, '通常 / 先週の細分化シートをもとに天狗の育成ゲームの作成', '・メインのスプライトにする天狗の絵を、8bit Painterで描いていました。', '・次回からコード作成に入ろう、ということにしています。', '盛り上がり: ・何度もやり直していたため、本日は絵の作成しかできませんでしたが、絵を描きながらゲームのイメージをふくらませていました。'),
  ('ea71a92c-44d6-5fe1-b3fa-18ef31c1248b', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-21', '17:30:00', null, '通常 / 検定問題の見直し', '・問題文を1行ずつ音読して、対応するコードを確認していきました。 ・問題の初めの方はきちんとできていましたが、途中から少し集中力が切れたのか、つながるべきコードを別にかいていたり、順序が曖昧だったり、重複するコードがあったりするミスが見られました。 ・コスチュームを切り替えるときに間に「待つ」を入れずに動かなくなっているミスは、こちらの指摘があるまで気づけなかったようでした。 ・一文ずつ丁寧に見ていけば、ブロックを探すことはできるようです。検定合格には、集中力の持続が課題かも…。', '・コンテストのビギナーズ部門の課題を作成予定', 'タイピング: 今日はタイピングに乗り気だったようで、4種類くらいのタイピングを熱心にしていました。
盛り上がり: ・今日はタイピングだけの気分、と言いながらも、こちらの検定見直しの提案を受け入れて、最終的には熱心に取り組むことができました。 ・コンテストはずっと嫌がっていましたが、賞品の話を聞いてやる気になってくれました'),
  ('54b2b956-959c-5bfd-802a-7b8ed9a59aad', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-21', '17:30:00', null, '通常 / 先週の検定問題の振り返り または コンテスト作品', '・授業開始前から、オリジナル作品を作りたいと言ってジャンピングゲームを作成していました。アルくんが垂直にジャンプして、日本刀に触れたらコスチュームを変えてゲームをストップする、という作品を完成させていました。 ・マリオのようなオリジナル作品を作りたいとのことで、ブロックの上を歩く動きを【Prg】55 走ってゴールを目指せ！キャットランゲームを作ろう！を参考に作成しました。 ・縦の動き、ジャンプ、落下の定義は、複製したものをアレンジして使用しました。使用する際、変更するべきところやメインのコードに入れる場所などは自力で考えるように促したところ、丁寧に一つ一つのコードを見てアレンジを加えることができていました。 ・思い通りの動きになるように背景に修正を加えたりしながら、ステージ3まで作成しました。', null, '盛り上がり: ・授業前も含めて90分以上、集中して作品作りに取り組んでいました。 ・もう少しだけ定義ブロックのアレンジをすれば、オリジナル要素が多くなるので、このままコンテスト用に作成を進めていけそうです。 ・公開できるレベルの作品ができるかもしれない！と、とても嬉しそうにしていました。'),
  ('ce3c25b2-006d-5b1b-a6f3-e7ebb632f6a3', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-21', '16:30:00', null, '通常 / コンテスト作品作成', '・一度お父さんと作成していたそうで、よく覚えていました。 ・問題文を提示しておいたら、ほぼ自力で作成できていました。座標や「ずっと」ブロックに関してはノーヒントでいけました。 ・ねずみを増やしてスピードを変えるのと、ネコがネズミをつかまえたときにかじる音を追加するアレンジをしていました。', '・ねずみとりのアレンジと、オリジナル部門の作成をご家庭で検討してきてもらうことになっています。', 'タイピング: タイピング道場の1回目のおさらいまで進みました。常にホームポジションを意識して丁寧に打てています。
盛り上がり: ・問題文の通りに丁寧に作成していくタイプです。検定などにも向いているかも。 ・一度学習したことはよく覚えていて、自分で再現することができています！'),
  ('758eaf6d-a559-50e3-a113-e115c792f6e9', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-21', '16:30:00', null, '通常 / コンテスト作品の作成', '・しょうたくんに触発されたのか、普段はすぐにあきらめる日本語入力なども、一生懸命ローマ字表を見ながらがんばっていました。 ・座標についても、しょうたくんが自力で解いているのを見て、自分で一生懸命考えて作成できていました。 ・xとy、プラスとマイナスについては、とっさにはまだ出てこないようですが、考える時間を与えると自己解決できていました。 ・課題の作品を完成させて、ねずみを増やすアレンジをしていました。', '・本日作成したねずみとりのアレンジ予定', 'タイピング: かわべの竹林第二場
盛り上がり: ・しょうたくんから刺激を受けたのか、自力でやろうとする積極性が見られました！マウスも一生懸命使っていました！ ・発表が苦手とのことですが、作品のアレンジのみのビギナーズ部門にはやる気を見せてくれました。'),
  ('255bed0d-5c05-5464-a10b-532f918ad650', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-14', '17:30:00', null, '通常 / 検定またはコンテスト', '・ムービーを見て、それをもとに作成しようとして、途中で行き詰っていました。 ・問題文を丁寧に読んで、1行ずつ線を引きながら解くと、ほぼ自力でできるのですが、しばらくするとまた自己流で作成しようとする傾向が見られました。 ・検定を通じて、問題文通りに作成することに慣れてほしいです。一度しっかりとしたコードを完成させてからアレンジを加えることができると、これまで行き詰っていたゲーム作りもより楽しくなるのではないかと…。', '・検定の答え合わせとアレンジ', 'タイピング: ゆずとくんが始めたのを見て、取り組んでくれました。
盛り上がり: ・なんどか行き詰まりながらも、最後まで投げ出さずに取り組むことができました！ ・普段は脱線が多いみずきくんにしては、辛抱強く頑張っていたと思います。'),
  ('7e511a59-05be-5089-9a02-554697461188', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-14', '16:30:00', null, '通常 / 基本操作コース_07 ピンポンゲーム', 'ゲームを3回ほどプレイしたら、必要なスプライトを自分で準備して、主な動きを説明することができていました。 「はしについたらはねかえる」「すべてを止める」「ずっと」などは、自分でブロックをさがして持ってくることができました。 変数はお父さんと勉強したことがあるそうで、カウントを増やす、最初に0にするなども自分でできていました。 丁寧に考えてからブロックをつなげるタイプで、「ずっと」の入れ忘れなどもなく、スムーズに30分で作成が終わりました。 使用ツール：ドリル レベル1 1～4 様子：ドリルの進め方の説明をしてから取り組みました。漢字の読み方を1度聞いてきたくらいで、丁寧に取り組んでいました。 問題文の読み落としなどもなく、完璧な解答でした！', 'ローマ字は少しわかるとのことなので、次回からタイピングを始めてみます。', '盛り上がり: 問題やこちらの発問を聞いて丁寧にブロックに置きかえているようです。 「回す」「向き」なども、一度説明したら自力で活用できるようになっていました。 新しくドリルの表に記録がついたことがとても嬉しそうでした！ お父さんと、ビギナーズ部門のアレンジを進めているようです。'),
  ('43823dcf-13f0-537e-8707-5d6323687518', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-17', '17:30:00', null, '通常 / ラーメンゲームの作成', '・お母さんと作成した設計書はあるのですが、自由作成となると、目についたスプライトを持ってきては適当なプログラムをして少し遊んでそれを削除する、というループが多かったです。かなり説得して、ようやく棒人間のコードを少し書いてくれました。', '今回のテーマが、下書きを見る限り、お母さんが主導になっていて、けいとくんが自主的にやりたいものとは違っている可能性もあるかと…。次回、けいとくんが本当に作りたいものを問いかけて、仕切り直してもよいかもしれません。', '盛り上がり: ・自分がやってみたいことはいろいろあるようなのですが、クリア型の課題でない場合、脱線がひどくなる傾向があります。とても楽しそうではあるのですが…'),
  ('41317fb7-5beb-578b-a712-26967456675d', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-06-20', '17:30:00', null, '通常 / prgのダイヤ取りゲームの作成', '・最初、先週作ったクリオネのコスチュームをいじったり、海のbgmを付けったり、動きのコードを作ることから脱線が起きてしまいました。 ・元のゲームを見ながら作ってほしいと頼みましたが、遊んでしまったので、先生と一緒に気づいたことを書き起こしていきました。一緒に書きながらやった方が進んでやってくれした。そして、元のゲーム以外にアレンジでやりたいこと（雷がふってくる）も書いてくれました。 ・書いたことを基にコードを組み立てていくと、スタートの合図でほかのスプライトを動かすとき、前回までやっていたメッセージを使うことが身についていてスムーズに組み立てられました。ただ、アレンジで別のコスチュームを選ぶとき、優柔不断で悩んでしまったり、書いたことをコードで作るとき、アレンジでほかのコードを作りしてしまうことがあるので、その結果頭いっぱいになることがあった。アレンジをするときとそうでないときでメリハリつけてやっていくべきだと感じた。', null, 'タイピング: 今日はミスタイピンぷが多く、スコアが伸びませんでした。
盛り上がり: ユニークなキャラを選んでいてでよかった。'),
  ('8b932dd5-afa2-571e-a8a6-daf74686c476', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-06-20', '17:30:00', null, '通常 / オリジナルゲームの作成！', 'ゲーム作成 背景をかわいいものから選んでくれました！！！！ 自分でスラスラ手を動かせていたので、基本的なところはバッチリなようです。スタートのメッセージ「はじまり」を作っていて良かったです。 もののこだわりの位置があるようで、何度も画面を見ながら調整していました。背景をこだわって作っていました。 途中悩む場面もありましたが、自分が作りたいものの形があるようです。一方、プログラムがうまくいかないと一気に捨ててしまう癖もあるようです。', null, 'タイピング: ホームポジションキープで正確に打てていました！姿勢も良い！ミスタイプ率6%!!!
盛り上がり: リビングの様子を作っていました！色合いが素敵です！'),
  ('c3b120f2-2292-52a9-bd74-74238c5e0148', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-06-20', null, null, '通常 / ①検定の見直し ②トランポリンの冒頭部分の復習', '①検定の見直し ミスの主な原因として、①プログラムするスプライトの選択間違え ②普段あまり使わないブロックを使いこなせない ③普段使ってるブロックの組み合わせて、普段表現しないことを表せない ことが挙げられます。②に関しては数をこなすことが近道だとは思いますが、「普段使うブロックをどう組み合わせて何をどう表現できるのか」を実践して学ぶことも必要だと思います。考え途中のブロックがそのまま置いてあり、誤作動してる箇所もありました。また、説明文の書かれ方も3,4級とは違ったので、混乱する原因の一つだったのかなと思います。 2級は難しかったようですが、基礎はほぼできているので挑戦できる範囲内にあることは伝えました！ ②トランポリン冒頭のみチャレンジ 前々回つかったトランポリンゲームの冒頭がうまく作動しなかったので、見本の冒頭部分のプログラムのみを抜き出して一緒に確認しました。変数の使い方が独特だったので、自分のゲームでも応用できそうだという話をしました。', null, '時間帯: その他
タイピング: 長文でしたが、長時間集中して取り組むことができました。
盛り上がり: 検定復習にかなり集中して取り組めました！今週の水曜日から期末テストみたいです！'),
  ('bab99ac3-97de-591f-bea5-fcc224102c0e', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-06-20', '17:30:00', null, '通常 / オリジナルゲームの作成。間違い探しの作成方法を考える。', 'まちがいさがしではなく、チャンバラのような金棒で倒すゲームに方針転換しました。「まちがいさがし」を表現するプログラムの考え方をいくつか紹介したのですが、どれもしっくりせず、ゲームごと変えることになりました。 ルールを変更したので、ルール説明の文章を変えることになり、タイピングを頑張っていました！ ルール説明のタイピングが終わったので、鬼と金棒のスプライトをつくることになりました。丁寧に作ってくれていました。 次回はプログラミングに移りたいです。', null, 'タイピング: ひとさし指以外にも使えてて良かったです！
盛り上がり: たのしくスプライト作っていました！！！作り込みが素晴らしいです！'),
  ('5b2aa5df-91ac-5cba-804c-2aa330e623a6', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-06-20', '16:30:00', null, '通常 / コンテストの作品作成', '・前半は親子大会の作品作りに集中して取り組めていました。プログラミングには関係ないが、クイズの解説文が長くなりすぎていたので、短くした方がわかりやすくなると伝えました。 ・太陽の温暖化の様子が、最初は「何秒待つ」のコードを使って変化を表していたが、「次へ」のスプライトを押して変化するようなコードをして、ゲームをやる側に親切になっていました。 ・後半はU-16の作品でゆき先生のアドバイスをしてもらいながら射的ゲームを活かせていました。', '作品の資料作り？', 'タイピング: 両手の五本の指がうまく使いこなせていて、スコアも安定してきました。'),
  ('5fbbebcb-7d73-5136-8000-0ac95deca691', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-20', '17:30:00', null, '通常 / コンテストの準備', 'コンテストの説明、オリジナル作品をまず作る前に腕試し的な感じで中級のアレンジをすることにしました。 一旦すべて見ながらすべて書いてもらって、そこからアレンジに入ったのですが、背景が変わったら次のゲームへ進むという内容を考えているようです。 全体的に気が散漫になりやすいので、ある程度メリハリをつけてあげるようにしたいと思います。', null, 'タイピング: タイピングする速さがはやくなってきた→ブラインドができつつあるのか？
盛り上がり: 自分で背景を描くことを始めたので、そうした絵関連の内容であればアレンジはもっと進むのかもと思います。'),
  ('ab39b8e8-f589-5131-b020-edcb8ea930f7', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-20', '16:30:00', null, '通常 / 追跡ゲームを完成させる、アレンジを行う', '全ての項目がおわりアレンジへ進む、 変数を使ってタイマーを設定することと、演算を使うことを少しだけ行った。 多少難しい内容ではあるものの、しっかりと先生の話を聞いて理解する姿勢がすばらしい。 また今使っているコードを使えばできるということをわかってくれたので、よかったなと思う。', '次回は、ピンポンへ進むかコンテストの準備', 'タイピング: 中段はすべてクリア、ココアのゲームのシステムが変わった模様（課金しないと使えない）なので次回からこどもタイピングにしていきたいと思います
盛り上がり: タイマーを設定し、スコアが取れなかったら残念と出す、クリアできたらおめでとうと表示するを発想し言葉にしてくれた（できた）ことがとても素晴らしい。なかなか言葉にすることができない子が多い中で、自分の想像と言葉がつながっていることだと思います。'),
  ('663fd455-7a8b-5e59-a868-cea475b9d694', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-04-18', '17:30:00', null, '通常 / 検定問題のカエルが葉っぱの上にのるという問題をしてからもう一度射的ゲーム', '検定の問題をやってもらっているときに、文章の読み間違いをしているので、最後まで動かないという状態へなってしまっていました。もちろんゆっくり読めばできるのだけど、疲れている？のか読み飛ばしがあり、うまく行かないことに対してイライラしていました。ただ、射的ゲームへと戻ったときに、自分が難しいコードを使ってゲームを作成していたのだということがわかると、「なーんだ」という感覚になっていたようなので、もしかすると今まで難しいコードばかりをやらせすぎていたかな？と思いました。', '次回は、初級の射的を最後まで完成させる（まだボールが割れるように見せる、ボールが何個もランダムに動くなどの設定をしていないので）', 'タイピング: タイピングのスキルがあるので安心して見ていられる状態です。
盛り上がり: 最後射的に戻ったとき、弾丸がボールに向かうようにしたら、ちゃんと動いたので、検定の問題をやることの意味を実感していたように思いました。'),
  ('3f457c7f-a0f1-50e5-9c1d-0e73b92427e9', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-06-06', '17:30:00', null, '通常 / 先週の続きー自分の作品を作る', '前回つくったスプライトが喋るようにしました。 話す文がかなり長かったため、ウェブ上のメモを使って入力してもらいました。少しは入力しやすそうでした。 変換が苦手なようです。文節や単語によって区切るという発想がまだないようで、苦労していました。隣からされんちゃんが助けてあげるような場面もありました。 今日は、文章の入力と話させるプログラムを作るところで終わりました。 来週は、まちがいさがしを作るそうです！', null, 'タイピング: キーの配置をよく確かめながら取り組んでいました。
盛り上がり: とても集中して文言を入力できていました。間違えてもあきらめることなく挑戦できていたので良かったです。'),
  ('fb116a06-bc38-5cc6-93c8-df2324f95dda', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-05-30', '17:30:00', null, '通常 / 先週作成したスプライトを使ってオリジナル作品の作成', 'スプライトをひとつ追加することになりました。 スプライトの名前をあとでみて分かりやすいようにすぐに変更してくれました。 スプライトが話す内容を打つのが大変そうなので、別のところ（文字を入力しやすいところ）に一度打ってから、コピペでブロックの中身に移すのがよさそうです。本人も打ちにくいと言っていました。 面は三枚あるそうです。案内人がおしゃべりする、どちらかというとアニメーション風の作品になるようです。 今回作ったスプライトは、ファイルのメッセージ（上のバーにあるメッセージマークのところ）に送っておきました。', null, 'タイピング: 両手を使ってできていました！
盛り上がり: おうすけくんとゲームの内容について話したりしている場面がありました！良かったです。 最近埴輪にはまっているようです。'),
  ('655033fa-63e9-5671-8467-77c2b7a8d0c2', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-05-23', '17:30:00', null, '通常 / 前回の続き 前回うまくいかなかったところを改善（数値の改善） 最後まで終わらせたい ドットツールを使うこと', '前回の続きではなく、新しいことを進めたいと本人の希望がありました！ 自分でオリジナルゲームをつくってほしいと提案して、本人も少し乗り気でした。 ドット絵のスプライトを作りたいとのことだったので、iPadで作成しました。 熊の絵や主人公の少年の絵などたくさんかいてくれました。 鬼退治するゲームを作るみたいです。 スプライトをつくったり見たりすることで作りたいゲームが浮かんでくるようでした！', null, 'タイピング: 集中して取り組めていました！
盛り上がり: 家族とか友達がでてくるゲームとか面白いよね！とコメントすると目がキラキラしてました！'),
  ('fbf90f6e-6e9f-587b-952b-60054b20cf0b', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2022-05-16', '17:30:00', null, '休み', null, null, null),
  ('6654d82b-5599-5c9c-ad10-d87b070dc4fd', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-05-09', '17:30:00', null, '通常 / 前回の続き', '前回から時間が空いたので自分が作った部分を少し振り返りながら進めていました。 ビルがうまく動かず苦戦しましたが、あきらめることなく考え続けてくれました！ 演算の<と>を間違えていたようなので声をかけました。説明したらなんとなく分かってくれたようでした。難しい内容なので繰り返し話していこうと思います。 ビルがうまく進まなくなってしまったので、原因を分析して細かく確認して来週また伝えたいと思います。', null, 'タイピング: 前回から時間が空いたので少し忘れてしまっているようでした。時間切れになってしまった部分も多かったです。
盛り上がり: 落ち着いていて良かったです。こちらの話もしっかりと聞いてくれました。'),
  ('85be5763-58b1-5301-829a-3002c7902120', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-04-25', '17:30:00', null, '通常 / 先週、ビルの隙間を動画を観ながらやって。難しすぎたという事なので。アレンジのイメージがあるようなので、続きでもいいかなーと。', 'やる気がとてもありました！！集中して取り組めていました。 うまくいかない部分があっても、放り出すことなく挑戦することもできていたので良かったです。 思うようにプログラムが働かなかったとき、自分でプログラムを少しばらして検証することもできていました。 いくつか「この動きを示しているのはどのブロックか」と聞いたときに、ゆっくりながらも説明してくれました。', null, 'タイピング: 片手で取り組んでいたので、両手の方がはやいよと伝えました。fの場所に迷うなど、まだキーの配置は自信がないようです。
盛り上がり: 車ゲームにはまっているみたいです。'),
  ('f47e8f1b-23f0-54e8-9453-1242e578390f', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2022-04-18', '17:30:00', null, '通常 / 先週の続き', '前回と同じように作り方の動画を見せながらやりました。途中、鳥に合う音が見つかなかったため、戦闘機に変えてアレンジしていました。 基本、動画の指示通り自ら進めることができ、最後まで集中して取り組んでいました。 ブロックに名前を付ける機能が「変数」だけにできることだという認識になっているようでした。「メッセージ」にも名前が付ける機能があることも覚えさせたいです。 作り方の動画は、6分30秒くらいまで進みました。', null, 'タイピング: 最後にやったので疲れていました。
盛り上がり: 後半にこのゲームが難しすぎるといって、画面下側の部分の通り抜けを無くして、上側のみにとおろぬけるようにしたいと言っていました。'),
  ('4453ac4b-a40a-5e2b-a4c9-3f1e000b5834', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-04-11', '17:30:00', null, '通常 / 【Prg】34 ビルのすきまを抜けようゲームを作ろう！ https://youtu.be/h7zbTAIbjHQ', 'ゲームには興味を示してくれましたが、あまり作るのには乗り気ではない様子でした。 作り方のYouTubeと見せたところ、自発的にプログラムを始めてくれました。 途中、「メッセージ」と「変数」をとりちがえて混乱しましたが、違うものであることの説明をしました。 かなり集中して取り組んでいました。3分50秒あたりまで終わっています。', null, 'タイピング: 集中してとりくんでくれました！
盛り上がり: 難しいゲームになるように間を狭めて工夫していました。'),
  ('9ccaf002-b513-5ad6-9b05-e9b50311075d', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-17', '17:30:00', null, '通常 / 背景、スプライトを表示、明るさや色を変更する', '最初の前半30分はポケモンキャラをお絵かき、それを使ってコードを作成しました。 ある意味、自分のキャラクターを作ってコードを書く方が彼は持続するので面倒ですが、一回一回書いたら、アルスパークに入れてあげて、コードを書くという方向性にしてください。 コードを書く事自体は、隠す、表示する、全てができるようになったので、今後少し物語っぽいものが作成できたらなと思っています。', null, 'タイピング: なし
盛り上がり: 自分のスプライトが明るさが変わる、歪むなどになった時にとても嬉しそうにしてました！'),
  ('684aa387-c66f-52f7-8c94-98b185a017f4', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-17', '16:30:00', null, '通常 / 変数の変化の作り込み（畑の荒らされ度、体力）', '・モグラが転がりながら落ちてくるのが不自然だということで、回転方法の調整をしました。 ・2種類の弾が当たる判定を調整しました。 ・モグラに弾が当たった時の効果を作りかけましたが、途中で難しくなったようで「疲れたからまた今度」となっていました。 ・モグラのコードが完成する前にスプライトを複製してしまったため、コードの複製が面倒になったようで、残り時間20分ほど、マイクラアスレチックタイムになってしまいました。こちらでとらのすけくんの作りかけていた効果を提示したら興味を示してくれました。', '・モグラが弾に当たった時の動作を作成していく約束です。', '盛り上がり: ・自分の作成したゲームを見直して、「ここが不自然だから修正したい」と思いつけるところは長所だと思います！ ・アイディアはいろいろ出てくるのですが、少し行き詰まるとすぐにScratchで検索してコピペをしたがります。今回はコンテストという目標があるため、コピペと参考にするのは違うことを説明してわかってもらえました。'),
  ('2c8f1573-2dc1-5291-a780-a63c76075bf8', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-17', '17:30:00', null, '通常 / 演習Aをやりきる', '最初のうちは、やることがあまりよくわかっていない様子でしたが、進んでいくごとに言われていることを理解している様子でした。 文章も本人に読ませた方が、該当コードを使うという感覚ができるので今度から演習やテストは本人に文章を読ませてあげてください。 １〜５までは概ね理解している様子。たまに自分なりのアレンジをかけてしまうこともありますが、正解をみると自分とは違うコードだということはわかっている。 辛抱強くではありますが、質問や投げかけをしてあげると晴くんは楽しんでくれていると思います。', null, 'タイピング: なし
盛り上がり: とうきくんと話が合うみたい'),
  ('25d53cdf-bbe6-551f-9541-2f27db38afdd', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-17', '16:30:00', null, '通常 / ジャンプゲームの応用（Prg）', '途中まで一緒にゲームを作ってもらいました。 ジャンプするスプライトを作成（前回と同じ）、木の動きを作る、背景の草を動かす までを行いました。（当たったら止まるなどの動きは次回以降）座標に関しては次回と同様あまり理解をしている感じではないので「ここの端の数字はこれ、これ」などを伝えてやってみてもらいました。 概ねスタート位置、ゴール位置の座標を設定することに関してはクリアできているものの、座標が動くとなるとちょっと問題になる様子（難しいみたい） 今日はとなりにお兄ちゃんがゲームを作っていたのに気を取られてしまった為集中力が切れたので残り２０分はお兄ちゃんと一緒のゲームをする、もしくは遊ぶで終了しました。', '今日の続きでもいいし、難しそうなら演習でもいいのかも', 'タイピング: 久しぶりにこどもタイピングをやってもらいましたが、９０２点と最高得点をだしました！
盛り上がり: ちょっと難しかったかな〜という感じです'),
  ('f1af29ab-5186-53a3-bf91-58a105fd3c17', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-10', '16:30:00', null, '通常 / 基本操作コース 09 ジャンプ', '基本操作コース 09 ジャンプを行いました、基本的な動作の理解はできているものの、まだ脳の引き出しに覚えるというのが定着していない為座標などは怪しい。 ただジャンプする動きなどは「こうするんだよ」と話すと概ねできていたので、次回は応用編をやってもいいかも。', null, 'タイピング: ２１点、小学2年生にしては得点が高く、今後も期待できそう
盛り上がり: 自分なりにアレンジする箇所が理解できているので、色々なアレンジをかけてもらいました。'),
  ('18dcad61-8f2b-536f-b013-6fb9328dd4f3', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-13', '16:30:00', null, '通常 / コンテストの説明をし、フリー素材などを勧めてみる 自由作成', 'コンテストの説明をしたところ、オリジナル部門のテーマのページを見てすぐに、「スプライトを自然に合うように変える」と言って、スラスラとゼビウスのスプライトを動物などに置きかえたストーリーを語ってくれました。 自分で書くのは嫌がったので、口述筆記の形でこちらが記載したものを見ながら使用するスプライトや背景、構成などを考えていきました。 自機は農業をしている人、キツネやモグラが畑を荒らしにくるので石を投げて帰ってもらう（倒すことはしない方向性らしい）、ラスボスは熊、スタート画面は森の前に畑がある風景、プレイ中は畑、ゲームオーバー画面は荒らされた畑、というところまで決まりました。 ゲームをある程度作りながら、自然との共生などのテーマで深めていく予定です。', '背景（3種類）によってスプライトの表示非表示を切り替える、新規スプライトの取り込みなど', 'タイピング: 珍しく、タイピングにやる気を出してくれました！ 下を見ないで打てるようになりたいとのことでホームポジションを教えました.。中段のホームポジションまでは、なるほど、と聞いていましたが、各指を上下段に動かすところで飽和したようで、ウガーッとなってしまいました…。 それでも「シルバー級」が出たことが嬉しかったようで、2回チャレンジしていました！
盛り上がり: ドット絵が好きとのことで、ゆき先生のExcelキャラクターに興味を示していました。農夫、キツネ、モグラ、クマのキャラクター待ちです。 背景も立体的ではなく２Dのドット絵にしたいとのことで、スプライトの土台を一生懸命加工していました。 投げる石のスプライトも、色やグラデーションを工夫してアレンジして作成していました。 ゼビウスやインベーダーからキャラクターを変えると決めた時に、スラスラとこれまでとは全く違うストーリーを語る頭の切り替えが見事でした！'),
  ('026a52df-2b1f-5044-9a20-fdf9c2d434d8', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-06', '16:30:00', null, '通常 / ゼビウス作成続き 敵キャラの作成 わかりやすいコード作成を目標', '定義ブロックを多用している見本から、必要な箇所だけを見分けて自分なりに簡潔なコードを作成することができました。 自機の残数の設定と、敵キャラBの動きを設定しました。 条件分岐に「ずっと」をつけることを忘れがちですが、自分で気づくこともできるようになっています。', null, '盛り上がり: 連休疲れで15分前に終了しました。
備考: Gun game 13.6 [1] https://scratch.mit.edu/projects/625842821 で遊んでいました(意外と難しい…）'),
  ('63fd6cda-3982-5f00-a90a-649cf0379011', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-22', '16:30:00', null, '通常 / アルスパークの中から好きなものをさがして自由作成', 'インベーダーゲームを作りたいとのことで、アルスパークのhttps://app.arspark.jp/projects/1331/editor を参照しました。 敵キャラクターが向かってくるものにしたいとの希望と、使いたいスプライトの画像の希望があり、Scratchの 「STAGE15 ボスキャラを作ろう remix」https://scratch.mit.edu/projects/679095651/ を参考にしました。 使いたいスプライトを書き出しして使用、自分で把握できる内容にするため、コードは参考にしつつ、基本的には一から作成するようにしていきました。 各スプライトのコードを1行ずつしっかり読んで、メッセージを使用した、他のスプライトや背景との関係も理解してから進めようとしていました。 隣で作成していた私の進捗を気にかけていたので、「ここはどうやった？」「私はこうしたよ」「それいいね！僕もそうしてみるけど、ここはこっちの方がいいと思う」などと会話をしながら、作成を進めていくことができました。', '引き続きゼビウス作成予定です。敵キャラの動きを作っていきたいです。', '盛り上がり: 自由作成とのことで、Scratchから題材をとりたがりましたが、自分で理解できる範囲で作っていこうということで納得してくれました。Scratchの作品を参考にはしましたが、真似やコピーをするのではなく、あくまでも参考にして作成は自力でするという姿勢が一貫して見られました！ 上下左右キーでスプライトを動かすコードに条件分岐を使って作成する方法をさせてみたところ、「こっちの方が動きがいい！」と喜んで、ようやくMakey Makeyから離れてくれました。 スプライトの弾が端についたら消えるコードは、とらのすけくん自身のオリジナルで考え、作成することができました！ 本日の学習ポイントは、背景による条件分岐でした。'),
  ('a9ae8eee-6659-5070-8931-d2a0b68aab9c', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-04-19', '17:30:00', null, '通常 / 今日は先週の続きで楽譜を持ってきてもらって、楽譜のコードを入れる', '様子：バイオリンをやっているので、ピアノの鍵盤の位置がわからないためか、途中でめんどくさいと話しました。そこで、私と一緒に音符と鍵盤の位置を一緒に確かめていきながら、1つの曲の３小節目まで音を組み合わせていきました。ここで、大事だなと思ったのが、どこかの音を間違えるとつながっていたときにどの音符のコードが間違っているかわからないと思ったため、「便利ツールが好きなまこちゃんに特別」と話して「定義」で小節毎に分けてみることにしました。 すると、ちゃんと定義を使い終えることができました。', 'ピンポンゲーム02まで進んでいます。次からボールが跳ね返るという部分を足すところなので、角度という問題に「毛嫌いさ」をいかに持たせないかがポイントかと思います。', 'タイピング: 様子：お母さんがタイピングにとても熱心な方なのでおそらく、まこちゃんもタイピング自体には毛嫌いはない様子。タイピングの速さも回数を行うごとに早くなっているので、ブラインドタッチが軽くできている？のではないかと思います。まだ迷いはある感じはしますが・・・簡単な文章であればそつなくこなせると思います。
盛り上がり: 終わった後、定義の使い方を「ゲームの時にとか使うの？」と聞いてくれたので、ここからゲームがどんどん面白くなるね！とワクワクしていた様子でした。まこちゃんはアーティストタイプではあるものの、やはりゲームも好きな様子です。定義をうまく使い始めたら、「めんどくさい」「不便」をよりよく便利にするという観点から大物に化ける可能性もあるかなと。それでも座標は嫌みたいなので、ワクワクと算数の帳尻をどう合わせるか？かな。'),
  ('70e90355-4ede-51c1-b3c8-75acc5ee28c5', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-10', '17:30:00', null, '通常 / お母さんと考えてきたゲームの検証、できれば作成開始', 'ラーメン食べ歩きゲームの説明をしてもらいました。食材を集めたり、クイズに答えたりするステージがあるそうです。 ゲームの内容を確認してから、やっていくことを一緒に考えました。 ラーメンの食材の絵を描きました。', '作成したスプライトを取り込んで、作成に入りたいです。', '盛り上がり: 今日はゲームの構成の確認とスプライトの作成がメインになりました。 クイズの内容に年齢の換算があり、計算した内容をとても熱心に説明してくれました。 （ドラゴンボールの孫悟空の年齢計算がすごかったです）'),
  ('f703febd-c1dc-5cac-9b09-14e9e20f72ab', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-04-12', '17:30:00', null, '通常 / 3月15日は追跡ゲームを全て完成させたところまで行う。 アレンジは、条件分岐で〜なら〜、〜でなければ〜の条件分岐をつかって、鍵に触れなかったら違う音を鳴らすということにした。感覚的な部分が彼女は多いので基本的には、そうした便利さなどの話から全てを教えてあげる方が良い。 今週は、先週までのことをおさらいしつつ、基本操作コースの音の単元へ進んでちょっと芸術的な要素の方で息抜きしてもよいかも。（青木）ドローンの一件もあるし・・・', '様子：春休みふくめ機会的なものや算数系に関しては苦手意識があったものの、芸術系のものには興味がある様子。 特に繰り返し音符を奏でるということに反応し、自分がバイオリンを弾いているからか、楽譜で何回も同じ旋律をやらなければならないことが、スクラッチ上では繰り返しやってくれることに感動していた（便利だと思っていた） 自分の楽器で演奏を録音し、アンサンブルもできるよと話したところ、まんざらでもなさそう（友達に聞かせることは嫌がっていたが・・・）リズムを録音し、練習もできるよと話たりすると、やはり自分で音律を入力してやってみたいということになった。次回は楽譜を持ってきて、大変だけどそれを入力してもらう', '楽譜を入力 ②基本操作コース_05_01 https://scratch.mit.edu/projects/511667175/editor/', 'タイピング: 様子：短文を打つ練習をする はじめて文章っぽいものをおこなう、スコアは323/366 上位45％の位置、本人は難しそうにしていたが、タイピングの速さ、正確性はまずまずといったところ。これから少しずつ短文ぽいものに挑戦していけばいいかと思う。
盛り上がり: ▼今日のワクワク 便利なものに興味がある 音楽、自分が関連しているものに対してワクワクしていた 今まで学んだことをきちんと理解している 今日は初めて乱数を使ったー乱数を使う場面で数字の大きさが変わる（座標なら座標の数字）ということを学んだ'),
  ('cf4e0b9f-56f6-515e-aaab-85e33a26d6df', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-03', '17:30:00', null, '通常 / お母さんと考えてきたゲームの検証、できれば作成開始', 'ゲームで遊んでから細分化に挑戦しました。 けいとくんが話す言葉をそのまま私が口述筆記の形で記載しました。 「りんごのスプライトは上から落ちてくるから、y座標を～ずつ変えるを使う」「最初に出てくる位置がランダムだから、x座標で乱数を使う」など、自分の話す言葉をその場でコードに置きかえていました！ おちてくるりんごが、赤と黄色でキャッチするかごの前にくるか後ろにくるか違っている、など、とても細かい部分にまで言及していました。 りんごが落ちてくる前に出現する位置について、カードでは「どこかの場所へいく」を使っていますが、前回学習した乱数を使って作成できていました。x座標の範囲も自分で仮のスプライトを作成して調べていました。', 'お母さんと「八王子ラーメン育成？ゲーム」を考えているそうなので、本日の細分化の紙を渡して、ゲームの大まかな構成を考えて次回持ってきてくれるようお願いしました。', 'タイピング: 久しぶりに楽しそうにチャレンジしていました。前回クリアできなかった最終ステージをクリアできて嬉しそうでした。
盛り上がり: 前回使った乱数がとても楽しかったようで、とても生き生きと乱数を作成していました。 細分化をとても緻密にしてくれて、こちらが驚くくらいでした！'),
  ('3c4aaf14-8a0e-528a-8594-39e44622cded', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-27', '17:30:00', null, '通常 / 人に見せるゲームを考える 途中でまっつんに意見をもらう？ 前回のゲームを発展させるか、新しいゲームにするか？', 'こうもりと銃のシューティングゲームを作成しました。 銃から弾丸が発射されるのをランダムにしたいというので、乱数を使うことを提案しました。「それは習ってない！」と、新しいブロックを使うことにとても乗り気になり、説明もきちんと聞くことができていました。 ゲーム開始後、一定時間が経ったら表示したいスプライトがあるとのことで、タイマーの使い方を学習しました。 「すべてを止める」「このスクリプトを止める」「スプライトの他のスクリプトを止める」の違いと、「スクリプト」「スプライト」などの用語について整理しました。けいとくんなりに納得して、スッキリしたようでした。', '本日お迎えにいらしたお父さんのお話では、家でお母さんと一緒にコンテスト用の素材を準備しているとのことだったので、次回見せてほしいとお伝えしました。方向性を決めることができれば、それに沿って作成に入りたいと思います。', 'タイピング: 最近ちょっとタイピングには疲れたのと、授業前から作成し始めていたプログラムに集中したいとのことで、今日はパスしました。
盛り上がり: 「乱数」「タイマー」「止めるブロックの違い」など、新規の内容を学習できたことが得意そうでした。 BGMや効果音のタイミングなどにこだわりをもって、丁寧に設定していました。'),
  ('d00007f0-7445-5992-af35-07cf828177dd', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-06-10', '17:30:00', null, '通常 / ジャンプゲームの再おさらい https://app.arspark.jp/projects/2665/editor', '様子：みないでできるが、動きの時に イベントで動きを作るのか、条件分岐で動かすのか？まで選択肢があるということを理解はできている様子でした。 ただ、コードをまとめて一緒にスッキリさせようとすると、ジャンプするのと左右するのでコードの書き方が違うことがまだ混乱している様子。向きに関して、イベントに関してが今一歩というところなのかな？ 変数の使い方、コスチュームの使い方、また自分なりのアレンジ（的に当たったらライフが減っているように見せる）などはとても良くできていると思います。', null, 'タイピング: 様子：ステージ１をクリアしていなかったようなので、晴くんが気が済むまでひとまずやってもらいました。 簡単なものをやりたがる傾向なものの、本人が集中してくれるなら・・と思いやってもらいました。ただもしかすると特定のキーが苦手？なのかなという感じも見受けられ全体的にタイピングが得意というわけではなさそう。'),
  ('6a87e45f-e239-5f89-a7b0-8386bc98eeaf', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-06-03', '17:30:00', null, '通常 / ジャンプゲームの仕上がりを見せて、カード通りに作成させる。アレンジしないで裏を見せて、自分が作成したものとどこが違うのか確認させる。 カードに「使用するブロック」を付記し、作品も用意しておく。', null, null, '盛り上がり: とても楽しそうにやっていたため、本当にゲームが好きなのだなあと感じました。'),
  ('668b92b3-abd6-5a07-8ca4-1016a4edd403', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-20', '17:30:00', null, '通常 / 世界観を意識しながらレースゲーム作成の続き', '前回から引き続き、にわとりとひよこの追いかけっこゲームを作成しました。 スプライトのゴール判定をどうするか迷っていたので、「この場所についたら、というのは「位置」で判定できるよね？」のヒントで座標を使う、と思いつくことができていました。判定に使用するのはx座標のみということも理解して、自分で座標を調べて演算式を作成できました。 鳴らしたい音の指定が複数あったため、「すべての音をとめる」で思い通りの音がなるように工夫していました。 作成、修正ともに理解が早く、ちょっとしたヒントで自己解決できています。', null, 'タイピング: 今日は飛ばしたいと言いながらも、周りをみて少しだけ取り組んでくれました。
盛り上がり: コード自体はよく理解できていますが、メッセージやスプライトの名前など、タイピングが関係する箇所がおざなりになりがちなので、今後のためにも名称はわかりやすくするよう促していきたいです。 今日はきちんとゲームの発表ができたので嬉しそうでした！'),
  ('1c621098-1765-5610-b9af-86ff67beda22', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '761a91b5-63ed-547d-8524-e06abcc55967', '2022-05-27', '17:30:00', null, '通常', '様子：先週検定の過去問を頑張っていたようなので今週は好きなゲームをやってもらいました。ずっと青鬼(https://scratch.mit.edu/projects/625454891/)をやっていました。周りの子たちが気になって終わった後やっている子もいました。', null, 'タイピング: 様子：すぐに飽きてしまい、「ki」だけを打ち続けるタイピングなどをやってしまっていました。
盛り上がり: とても楽しそうにやっていたため、本当にゲームが好きなのだなあと感じました。'),
  ('6bec5c8c-746b-5406-a146-a8c32daecde2', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-13', '17:30:00', null, '通常 / 一区切りついているので、自由作成', '前回の迷路ゲームのゴールスプライトを作成してから、コンテスト用自由作成に入りました。 テーマの紹介については聞くのが面倒そうだったため、けいとくんが今作りたいものをさがしてもらいました。 「【Prg】10レースゲーム＿レベル2」のようなものを作りたいとのことで、スポーツ対戦系か動物系の作品にふくらませていく予定です。 競争相手のNPCが、最短距離を一定時間で進むようにしたところがけいとくんなりの面白ポイントだったようです。', '自由制作となると、コンテストに向けての作品作りというよりも、その場で自分がウケることのできる刹那的な楽しさに流れていってしまう傾向が顕著でした。次回は切り口を変えて、これは「人に見せる作品」ということ、一発芸ではなくストーリーを持った作品にすることを意識してもらえるよう努めたいです。', 'タイピング: 使用するキーが増えてきたせいか、集中力がいつもより途切れ気味でした…。
盛り上がり: どういうイメージの作品を作るかの検討にとても時間がかかりましたが、いろいろなゲームの仕様を見ることができて楽しそうでした。 プログラミングに関しては相変わらずとても勘が良いのですが、作りたい作品の設計やコンテストについての理解などは、ある意味年齢相応な様子でした。プログラミングをしているときとのギャップが新鮮でした。'),
  ('ede195c7-322e-5bf1-b225-e4a39f7041fa', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-05-20', '17:30:00', null, '通常 / 検定４級 必要性を意識して、最初から', '様子：再度さかなつりをやりました。一番驚いたのは集中度合い。隣に私が座っているからか？なのか文章をよく読み、コードを書いていました。途中自分自身で読み飛ばしてしまった箇所もコードが動かないことに気がつき、自分で判断し正しいコードを追加してくれていました。 前回よりもはるかに集中し、問題を解いてくれていたのでこの感じなら検定は４級であればいけるかな？と思います。', null, '盛り上がり: 全部できてるね！と話した時に、とても笑顔になって満足していた様子なので、こうした自信を少しずつ増やしてあげたらいいなと思います。'),
  ('84bea585-25f5-5279-8325-cf83c5629588', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-06', '17:30:00', null, '通常 / 基本操作コース09 ジャンピングゲーム スコア設定、応用', '基本操作コース09 ジャンピングゲームの見直しをしてからアレンジを勧めましたが、今日は迷路脱出ゲームのようなものを作りたいとのことで、さらちゃんと同様にオリジナル迷路ゲームを作りました。 迷路の背景は、さらちゃんの作成を参考に自分で作っていました。 ゲームの仕様をけいとくんなりにシンプルにして作成できていました。', null, '盛り上がり: 最低限のシンプルなコードで上手に作りたいゲームを形にできていました。'),
  ('6c606370-ec68-5bed-8aaf-5cdb05eacb1b', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-05-13', '17:30:00', null, '通常 / 検定４級？自分ができてない部分を理解してもらうために〜', '様子：当初はお手本ムービーを見ていなかったこともあり、問題文を読まずにオリジナル作成に流れがち。 先生がついていて、問題文とブロックを照らし合わせながらだと該当ブロックを持ってくることはできるが、自力では問題文の順序通りに作成することが難しい、あるいはそうしなければならない意味がわかっていない。 最初から新しく作成しなおして、文章と使うブロックについて強調したところ、(2)の③まで進めることができた。', '本人にとってはつらい関門であることを、親御さんにもお伝え済み。', '盛り上がり: このレベルで相当苦戦していて、本人も難しかったという自覚はあり。 問題文通り、順序通りに作成する意義を理解した上で、オリジナリティを出していくことの必要性をわかってもらいたい。'),
  ('5058b673-14d8-5ace-ba33-7fb1fcc1c356', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-22', '17:30:00', null, '通常 / 「さあ踊ろう」の内容は、けいとくんにとっては既習のものが多く、もう十分という雰囲気だったので、新しい単元「09 ジャンピングゲーム」にとりかかる。', '1か月前にジャンプの動きを学習した際の作品が残っていて、「これを使いたい」とのことだったので、背景として作成した土台のスプライトなどはそのままにして、障害物のスプライトを新しく作成してもらいました。 アルスパークの「③基本操作コース_09_ジャンピングゲーム ゆき先生作」をプレイさせたところ、頭の中で細分化ができたようで、カードも見ずに作成していました。障害物に触れた時の判定やゲームを止めるブロックの作成場所がテキストとは異なりますが、きちんと作成できていました。 当たっても何も起こらない障害物スプライト（爆弾）を作成して楽しんでいました。 障害物スプライト（スラボー）に触れた時にゲームオーバーを表示するというのも自分で考えていました。「ゲームオーバー」のスプライトはどうやって表示しようかと質問してきたので、「ゲームオーバーになったというお知らせを、ゲームオーバースプライトに教えられるといいね」の助言でメッセージを使うことを思い出し、自力で作成できていました。', '次回はスコアの設定の予定です。また、爆弾スプライトにはせっかく音などを別個に設定しているので、スコアやボーナスポイントなど、もっとアレンジして楽しくできないか挑戦してもらいたいです。', 'タイピング: ココアタイピングで新しいアイテムが手に入ったらしく、嬉しそうでした。最初のうちは比較的丁寧に、指使いも見て打っているのですが、後半になると段々打ち方や指使いが雑になってきます…。雑になる前に切り上げるのもありかもしれませんが、先に進めたいという意識もあるようなので、しばらくは声かけをしながら様子見でしょうか。
盛り上がり: 相変わらず、頭の中でよく整理できています。お手本のスプライトの動きを再現するためのブロックを的確に準備して、最小限の単位で組み立てています。そのため、修正箇所を見つけるのもとても速いです！
備考: バグ修正のときはとても集中しているので、あまり話しかけてほしくなさそうでした。'),
  ('3ad1224b-e37c-5147-a50b-51e906fef494', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-04-15', '17:30:00', null, '通常 / さらちゃんと同じ進みだったので、さらちゃんと同じがいいのでは？ 現場の様子で、二人一緒でない方がというのであれば、別でもOK。 （以下、さらちゃんと同じ） 少し間があいたので、本人の前回画面を見ながら「前回はピンポン作ったよね～、この時、「もし〇〇なら」のブロックの使い方を習得したよね～と、で、この時「もし〇〇なら」のブロックの中に、乱数も使えたね」いう程度の復習にしておこう。↓↓ピンポンゲームの単元のポイントは「もし〇〇なら」で調べるコードを使うということなので。ここの復習。 簡単に復習したら、次の単元いっちゃいましょう。 「さあ、踊ろう」か「ジャンピング」、両方見せてやりたい方を選択してもらおう。 それぞれの目標は以下です。', '物語を作ろうで触れた箇所も複数あったため、復習と新規の勉強を兼ねることを説明して取り組みました。 既習事項、新規事項に関わらずよく理解できていて、楽器のスプライトや音を追加してオリジナル音楽を作っていました。 さらちゃんの作品の「メッセージを送る」ブロックの位置が間違っていたところをパッと見て指摘できていました。', null, 'タイピング: ココアタイピングを少し進めたところで、少し違うものがやりたいとのことでマイタイピングを開きました。 さらちゃんがマイタイピングをしているのを見て少しおじけづいたのか、A連打で遊べただけでしたが、少しずつマイタイピングの基礎練習にチャレンジしてもいいかもしれません。
盛り上がり: 音楽も好きなのか、既存のBGMに一生懸命に音を追加して、より楽しくにぎやかな音を作ろうと盛り上がっていました！ 繰り返しブロックを使用する場所やメッセージの使いどころなども問題なく理解していました！
備考: 車ゲームremix https://scratch.mit.edu/projects/661952544/ にはまっています。'),
  ('35a713b5-2e60-5096-9942-e12fab0dff40', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-05-06', '17:30:00', null, '通常 / 使用ツール：射的ゲーム＿初級 https://app.arspark.jp/contents/11309', null, null, null),
  ('1d4d3b93-8e3f-5eff-b062-5f75088b2965', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-10', '17:30:00', null, '通常 / ゲームの世界観作成', '前回までの作品は完成していて、コンテスト用には別の作品を作りたいとのことで、どんなゲームを作りたいのか考えました。 細分化の紙に、自分の作りたいゲームを書いてもらいました。 八王子の「天狗育成ゲーム」で、バイトをして小判をためて都まんじゅうを買い、天狗を育てるそうです。 天狗は高尾山のキャラクターを使い、小判と都まんじゅうのスプライトをアルスパーク上で作りました。', 'ゲームの構成を考えて作成に入りたいです。', 'タイピング: 何回目かのチャレンジで、これまでの最高点を出していました！
盛り上がり: 新しいゲームを作るとのことでスプライトの絵を描きたがりましたが、今日は低学年の子に譲ることができました。 ゲームの設定を考えるのがとても楽しそうでしたが、基本「お話」として考えているので、それをコードにするための細かい設定を書き出していけるように促していきたいところです。'),
  ('ae0f0107-6886-54e7-8f7b-533ccad49842', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '761a91b5-63ed-547d-8524-e06abcc55967', '2022-04-22', '17:30:00', null, '通常', '様子：初めは自分が好きなゲームを作りたいと言っていたのですが、とりあえずジャンプゲームのランダムで障害物が流れてくる動作を作ってもらいました。乱数の使い方がわからないと言っていたのですが、自力でコスチュームのなかに乱数を入れるコードを作ってくれました。 その後、はるとくんと一緒に射的ゲーム＿初級の細分化をしてもらいました。初めはあまり細かく細分化できていなかったのですが、 はると君が細かく細分化してるのを見て、もう少し細かく愛分化してくれました。(まだ若干物足りない感じではありますが...)', null, 'タイピング: 様子：集中してしばらくやっていました。
盛り上がり: 自分で作りたいのを作りたいと言っていてアイデアがたくさんあってスゴイと感じました。'),
  ('409fb062-413f-5f58-9d3a-d53cf9e4891d', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-06-03', '17:30:00', null, '通常 / ドット絵のキャラクターと魔法の杖の位置の調整', '魔法の杖と、それを持つキャラクターが連動して動くように設定するところで、「〇〇の方へいく」を使うとスプライト同士が重なってしまうところの修正をしました。 連動して動かすために着目するところはどこか考えてもらい、y座標を思いつくことができました。 キーの操作によって変わるy座標を他のスプライトで使うためにはどうすれば良いかを考えてもらい、「変数」を作成することができました。 多少の誘導はしましたが、自分で考えてスプライトの動きの修正をすることができていました。 ゲームを止めるタイミングを作成していました。 後半15分くらい、新しいキャラクターをドット絵で作成していました。', 'ゲームの世界観などを考えながら作り込んでいく予定です。', 'タイピング: 自分の記録を更新しようとがんばっていました。
盛り上がり: 今日は、前回持ち越した課題（キャラクターと杖の動き、ゲームストップ）がクリアできたら新しいキャラクターのドット絵を作成してよいということにしたため、かなり集中して取り組んでいました。 以前は「無理」「答え教えて」と言うことが多かったですが、こちらの発問を受けて自力で考えることがだいぶ増えてきました！ ドット絵を描くのがとても楽しいようで、iPadのアプリ名をメモして帰っていました。
備考: 再投稿ドロップザナンバー スクラッチ remix がお気に入りで、最近毎回遊んでいます。 https://scratch.mit.edu/projects/693769536/'),
  ('0bd80c65-3fd3-5969-880c-d40ad8740b5e', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-04-15', '17:30:00', null, '通常 / これまで、教材はピンポンゲームまでやっているので。今回は次の「ジャンピング」か「キャッチゲーム」をお勧めしてみましょうか？ 細分化はできそうかな？ 細分化をやれるようになることは凄いことだという説明をしつつ、高学年の子はみんなやっていくので、やってみようか！と促してみましょうか。 細分化をした上で、ジャンピングもキャッチも簡単そうだったら、最近みんなで取り組んでいる「射的」をお勧めしようか。 ★重要★「射的の場合」最初の説明で、難しい方と簡単なのを両方最初に見せてあげてください。 「最初に難しい方も両方見せてゴールを確認してから、簡単なのを始める」→簡単なのでできた！成長している自身になる、難しいのにチャレンジしたくなる！という流れです。 最初に簡単な方で細分化させてみよう！', '様子：自分でどんどん進めていましたが、自分でどんどん進めておりあまり口を出せなかったのですが、ところどころごちゃごちゃしたコードを使っており、もう少し簡単にできるよなどのアドバイスはしました。 やったこと ①ジャンプの動作 向きと～歩動かすというスプライトを使って作っていました。(y座標に関しては説明できていません) ②障害物をコスチュームを使って2パターン作ってくれました。 （x座標を使って動かしており、「~秒で～まで動かす」というコードの説明はできていません。）', null, 'タイピング: 様子：しばらく集中してやっていました。
盛り上がり: ジャンプ作ってーと言ったら、すぐにそれは簡単みたいな感じで自信があっていいと思いました(まあ、良し悪しですが笑)'),
  ('b8c2e097-a592-5e74-babc-aa6d2756b326', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-27', '17:30:00', null, '通常 / 卵の割れ方を考える', '卵が1度うたれたらヒビが入り、2度打たれたら割れるという動きを、変数を使うというヒントを出して一緒に考えました。 変数の初期値や値が変わる設定は覚えていて、自分で作成ができました。 作成した変数をどう使うかは、「1度うたれたら変数はどう変わる？」「変数が1になったら、何を変えればいい？」という問いかけが必要でしたが、その後は自分で作成することができました。 自分でスプライトを描いてみたいということで、iPadでドット絵を描きました！', 'ドット絵で作成したスプライトと、魔法の杖の動きがうまく連動するように作成していく予定です。', 'タイピング: 最近タイピングは少し飽きているようで、先週に引き続き飛ばしました。
盛り上がり: さらちゃんのこだわったポイント（卵が2段階で割れる）が、コピーなどではなく自力で作成できたのがとても嬉しそうでした。 ドット絵を描くのがとても上手で、本人も満足そうでした。とうきくんにもよく教えてくれました。'),
  ('f35d6689-2260-5be8-98d1-9b6618c16f1f', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-20', '17:30:00', null, '通常 / 先週作成した二人分の魔法の杖にコードを作成', 'それぞれの魔法の杖から出すビームの設定をしました。発射する杖にいってから表示するという設定を、元のゲームを見ながら作成することができました。 ビームが当たったときに卵が割れるというコードで、元のゲームにはない演算式「または」を使うことができました。 卵のコスチュームが段階を踏んで変わるところはさらちゃんのオリジナルです！ 今日の作成分では、卵が段階を踏んで割れるのが時間差で自動で進んでしまうので、次回はそこを何とかしたい、というところで終了しました。', '卵が2段階でわれる設定を考える予定です。', 'タイピング: 今日は気分じゃないとのことで飛ばしました。
盛り上がり: ビームを発射するところや卵にビームが当たったときなど、当初は思い通りの動きにならなかったところでも、癇癪をおこさずに考えようとする姿勢が見られました！ずいぶんと我慢強くなったと思います！ どうしてもうまくいかないところも、むやみに先生を頼らず、元のゲームのコードを読んで自分で考えようとしていました。'),
  ('8ceca9c0-2d1c-52c6-b422-b24e6a3749fc', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-13', '17:30:00', null, '通常 / 迷路ゲームのバグ探しと修正（クリア時にスプライトを隠した後、表示の設定を忘れている） アイディアをコードにすることはできるようになってきているので、アレンジをしたときに生じた不具合を探せるようになることを目的にしたい', 'コンテストの意図もある程度わかったようで、射的ゲームをもとに「つながり～チームプレイ」または「対戦ゲーム」を作成したいとのこと、細分化の紙も意欲的に書いていました。 自分用と友達用のスプライトを作成し、卵をうったときに段階を踏んでゲットするという仕様を考え、準備をしました。', '細分化の際、コードに直すことを意識して、箇条書きのような簡潔な文章で書くことを意識させていきたいです。', 'タイピング: 本人曰く、今日は調子が悪いとのことで、集中力はイマイチでした。
盛り上がり: 想像以上に細分化の作業を熱心にできていたのですが、せっかく書けている文章をコードに直すことがまだ難しいようでした。'),
  ('48073283-0911-5b28-af21-2f823811adc5', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-05-06', '17:30:00', null, '通常 / 「すべてを止める」ブロックの位置の検証。 「ずっと」や条件分岐の中に入れるブロックを考える。 ← 簡単な細分化 スコアの作成。', '前回のジャンピングゲームの見直しに取りかかりましたが、あまり集中して考えられていなかったので、気分転換に新しいゲームを作ってみることにしました。 アルスパークからいくつか探した結果、「イライラ迷路」のようなものを作ってみたいとのことで、自分で背景の迷路を描き、スラボーがドーナツに触れたら背景が次のステージの迷路に進み、それがクリアできたらゲームクリアの背景を表示する、というオリジナルゲームを作りました！ ステージの構成やスプライトの大きさ、ゲームクリアしたときには終了メッセージだけを見せるようにするなど、さらちゃんなりにこだわったゲームの仕様を、コードにすることができました。', '今回飛ばしたジャンピングゲームの「すべてを止める」ブロックの位置がおかしいためゲームが動かなくなっているので、次回は上記の書き出しから始めて見直しと、スコアの作成。 または、今回作成の迷路ゲームのバグ探しと修正（クリア時にスプライトを隠した後、表示の設定を忘れている）', 'タイピング: 最近は比較的楽しそうにできています。
盛り上がり: 作成したいゲームのイメージを形にすることができるようになってきています！ ゲームの仕様に関しては、比較的細かいところまで気が回って、実現しようとする意欲もあります。ただ、一度くじけるとすべてが「もういいや」になってしまうこともあるので、落ち着いてコードを見直すことに慣れていけると良いかなあ、と…。')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

commit;
